/* Continue Session Card */
.continue-session-card {
  background: linear-gradient(135deg, rgba(154, 103, 56, 0.08), rgba(154, 103, 56, 0.02));
  border: 1px solid rgba(154, 103, 56, 0.2);
  border-radius: 16px;
  padding: 16px 20px;
  margin-bottom: 18px;
}

.continue-session-inner {
  display: flex;
  align-items: center;
  gap: 16px;
}

.continue-icon-wrapper {
  width: 48px;
  height: 48px;
  border-radius: 50%;
