/* Custom Session Selector */
.custom-session-selector {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 16px;
  padding: 16px 20px;
  margin-bottom: 18px;
}

.selector-header {
  display: flex;
  align-items: center;
  gap: 8px;
  font-weight: 600;
  color: var(--text);
  font-size: 0.9rem;
  margin-bottom: 12px;
}

.selector-header i {
  color: var(--accent);
}

.selector-row {
  display: flex;
  gap: 12px;
  align-items: stretch;
}

.selector-row .dropdown {
  flex: 1;
}

.btn-session-dropdown {
  background: var(--surface-strong);
  border: 1px solid var(--border);
  border-radius: 10px;
  color: var(--text);
  font-weight: 500;
  padding: 10px 16px;
  text-align: left;
  height: 100%;
  min-height: 48px;
}

.btn-session-dropdown:hover {
  border-color: var(--accent);
  background: var(--accent-light);
}

.btn-session-dropdown.has-selection {
  border-color: var(--accent);
  background: var(--accent-light);
}

.btn-session-dropdown .placeholder-text {
  color: var(--text-muted);
}

.session-dropdown-menu {
  max-height: 320px;
  overflow-y: auto;
  padding: 8px;
