  border-top: 1px solid var(--border);
}

.technique-benefits small {
  font-size: 0.65rem;
  color: var(--accent);
  display: flex;
  align-items: center;
  gap: 4px;
}

.technique-benefits small i {
  font-size: 0.6rem;
}

/* Presets Section */
.presets-section {
  margin-top: 24px;
  padding-top: 20px;
  border-top: 1px solid var(--border);
}

.presets-section h4 {
  margin: 0 0 12px 0;
  font-size: 0.85rem;
  font-weight: 600;
  color: var(--text);
  display: flex;
  align-items: center;
  gap: 6px;
}

.presets-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(120px, 1fr));
  gap: 10px;
}

.preset-btn {
  padding: 10px 14px;
  border-radius: 12px;
  border: 1px solid var(--border);
  background: var(--surface);
  cursor: pointer;
  font-size: 0.75rem;
  font-weight: 500;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  transition: all 0.2s ease;
  color: var(--text);
}

.preset-btn:hover {
  background: var(--accent);
  color: white;
  border-color: var(--accent);
  transform: translateY(-1px);
}

.preset-btn i {
  font-size: 0.8rem;
}

/* Responsive */
@media (max-width: 640px) {
  .tools {
    --tools-width: 100vw;
  }

  .technique-card-header {
    flex-wrap: wrap;
  }

  .technique-toggle {
    width: 100%;
  }

  .presets-grid {
    grid-template-columns: 1fr;
  }
}

.conflict-badge {
  margin-top: 6px;
  padding: 2px 8px;
  background: #fee2e2;
  color: #dc2626;
  border-radius: 20px;
  font-size: 0.65rem;
  font-weight: 500;
  display: inline-block;
}

[data-theme="dark"] .conflict-badge {
  background: rgba(220, 38, 38, 0.15);
  color: #f87171;
}

.technique-conflict-warning {
  display: flex;
  align-items: center;
  gap: 6px;
  margin-top: 6px;
  padding: 4px 8px;
  background: rgba(220, 53, 69, 0.1);
  border-radius: 8px;
  font-size: 0.65rem;
  color: #c62828;
  border: 1px solid rgba(220, 53, 69, 0.2);
  animation: warningPulse 1s ease-in-out;
}

.technique-conflict-warning i {
  font-size: 0.7rem;
}

@keyframes warningPulse {

  0%,
  100% {
    opacity: 0.7;
  }

  50% {
    opacity: 1;
    background: rgba(220, 53, 69, 0.2);
  }
}

/* Dark mode */
[data-theme="dark"] .technique-conflict-warning {
  background: rgba(229, 57, 53, 0.15);
  color: #ef9a9a;
}

/* Hint button in sheet toggle */
.st-right-group {
  display: flex;
  align-items: center;
  gap: 8px;
}

.st-hint-btn {
  width: 28px;
  height: 28px;
  border-radius: 10px;
  border: 1px solid var(--border);
  background: rgba(255, 255, 255, 0.78);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--accent);
  transition: all 0.2s ease;
}

.st-hint-btn:hover {
  background: var(--accent-light);
  transform: scale(1.05);
}

.st-hint-btn i {
  font-size: 0.9rem;
}

/* Compatibility Modal */
.compatibility-modal {
  max-width: 560px;
  width: 100%;
}

.compatibility-intro {
  font-size: 0.85rem;
  color: var(--text-muted);
  margin-bottom: 20px;
  line-height: 1.4;
}

.compatibility-grid {
  display: flex;
  flex-direction: column;
  gap: 12px;
  margin-bottom: 20px;
}

.compatibility-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
  padding: 14px 16px;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 14px;
  transition: all 0.2s ease;
}

.compatibility-row:hover {
  border-color: var(--accent);
  background: var(--accent-light);
}

.combo-icons {
  display: flex;
  align-items: center;
  gap: 6px;
  min-width: 70px;
  font-size: 1.1rem;
  color: var(--accent);
}

.combo-icons i {
  font-size: 1rem;
}

.combo-icons .bi-plus-lg {
  font-size: 0.7rem;
  color: var(--text-muted);
}

.combo-text {
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.combo-text strong {
  font-size: 0.85rem;
  color: var(--text);
}

.combo-text span {
  font-size: 0.7rem;
  color: var(--text-muted);
}

.combo-badge {
  padding: 4px 10px;
  border-radius: 20px;
  font-size: 0.7rem;
  font-weight: 600;
  white-space: nowrap;
}

.combo-badge.success {
  background: rgba(46, 125, 50, 0.12);
  color: #2e7d32;
  border: 1px solid rgba(46, 125, 50, 0.2);
}

.combo-badge.alone {
  background: rgba(154, 103, 56, 0.12);
  color: var(--accent);
  border: 1px solid rgba(154, 103, 56, 0.2);
}

.compatibility-note {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 12px 14px;
  background: rgba(220, 53, 69, 0.08);
  border-radius: 12px;
  font-size: 0.75rem;
  color: #c62828;
  border: 1px solid rgba(220, 53, 69, 0.15);
}

.compatibility-note i {
  font-size: 1rem;
  flex-shrink: 0;
}

/* Dark mode support */
[data-theme="dark"] .compatibility-row {
  background: var(--surface-strong);
}

[data-theme="dark"] .compatibility-row:hover {
  background: rgba(208, 160, 107, 0.1);
}

[data-theme="dark"] .combo-badge.success {
  background: rgba(76, 175, 80, 0.15);
  color: #81c784;
}

[data-theme="dark"] .compatibility-note {
  background: rgba(229, 57, 53, 0.12);
  color: #ef9a9a;
}

/* Responsive */
@media (max-width: 560px) {
  .compatibility-row {
    flex-wrap: wrap;
    gap: 10px;
  }

  .combo-badge {
    margin-left: auto;
  }

  .combo-icons {
    min-width: 55px;
  }
}

.segmented-control-compact button {
  font-size: 0.7rem;
  padding: 6px 8px;
}

.save-name-modal {
  max-width: 680px;
  width: 100%;
}

.save-modal-desc {
  font-size: 0.85rem;
  color: var(--text-muted);
  margin-bottom: 20px;
  line-height: 1.4;
}

.save-name-input-group {
  margin-bottom: 16px;
}

.save-name-input-group label {
  display: block;
  font-size: 0.75rem;
  font-weight: 600;
  color: var(--text);
  margin-bottom: 8px;
}

.save-name-input {
  width: 100%;
  padding: 12px 14px;
  border-radius: 12px;
  border: 1px solid var(--border);
  background: var(--surface);
  font-size: 0.9rem;
  color: var(--text);
  transition: all 0.2s;
}

.save-name-input:focus {
  outline: none;
  border-color: var(--accent);
  box-shadow: 0 0 0 3px var(--accent-light);
}

.save-preview-info {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 10px 12px;
  background: var(--accent-light);
  border-radius: 10px;
  font-size: 0.75rem;
  color: var(--text-muted);
  margin-top: 8px;
}

.save-preview-info i {
  color: var(--accent);
  font-size: 0.9rem;
}

.technique-desc-hint {
  display: block;
  font-size: 0.65rem;
  color: var(--accent);
  margin-top: 4px;
  font-weight: 500;
}

.technique-example-hint {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 12px;
  margin-top: 8px;
  background: rgba(154, 103, 56, 0.08);
  border-radius: 10px;
  font-size: 0.7rem;
  color: var(--text-muted);
  border: 1px solid rgba(154, 103, 56, 0.12);
}

.technique-example-hint i {
  color: var(--accent);
  font-size: 0.8rem;
  flex-shrink: 0;
}

.technique-example-hint strong {
  color: var(--accent);
}

/* Anchor Mode Styles - Enhanced */
.verse-arabic .wbw-word.anchor-highlight,
.verse-arabic word.anchor-highlight,
.mushaf-ayah-text .wbw-word.anchor-highlight,
.mushaf-ayah-text word.anchor-highlight,
.word-item.anchor-highlight {
  position: relative;
  background: linear-gradient(135deg, rgba(255, 193, 7, 0.3), rgba(255, 152, 0, 0.4));
  border-bottom: 3px solid #ff9800;
  border-radius: 8px;
  transform: scale(1.02);
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  cursor: pointer;
  box-shadow: 0 2px 4px rgba(255, 152, 0, 0.2);
}

.mushaf-ayah-text .wbw-word.anchor-highlight,
.mushaf-ayah-text word.anchor-highlight {
  display: inline;
  font-size: inherit !important;
  line-height: inherit !important;
  transform: none !important;
  vertical-align: baseline;
}

.mushaf-ayah-text .anchor-pulse {
  animation: mushafAnchorPulse 0.6s ease-out;
}

@keyframes mushafAnchorPulse {

  0%,
  100% {
    box-shadow: 0 2px 4px rgba(255, 152, 0, 0.2);
  }

  50% {
    box-shadow: 0 0 0 8px rgba(255, 152, 0, 0);
  }
}

/* Animation for newly highlighted anchors */
.anchor-pulse {
  animation: anchorPulse 0.6s ease-out;
}

@keyframes anchorPulse {
  0% {
    transform: scale(1);
    box-shadow: 0 0 0 0 rgba(255, 152, 0, 0.7);
  }

  50% {
    transform: scale(1.08);
    box-shadow: 0 0 0 8px rgba(255, 152, 0, 0);
  }

  100% {
    transform: scale(1.02);
    box-shadow: 0 0 0 0 rgba(255, 152, 0, 0);
  }
}

.verse-arabic .wbw-word.anchor-highlight:hover,
.verse-arabic word.anchor-highlight:hover,
.mushaf-ayah-text .wbw-word.anchor-highlight:hover,
.mushaf-ayah-text word.anchor-highlight:hover,
.word-item.anchor-highlight:hover {
  background: rgba(255, 152, 0, 0.6);
  transform: scale(1.08);
  box-shadow: 0 4px 12px rgba(255, 152, 0, 0.4);
}

.mushaf-ayah-text .wbw-word.anchor-highlight:hover,
.mushaf-ayah-text word.anchor-highlight:hover {
  transform: none !important;
}

/* Tooltip for anchors */
.anchor-highlight::after {
  content: "🔗 Memory Anchor";
  position: absolute;
  bottom: 100%;
  left: 50%;
  transform: translateX(-50%);
  background: #333;
  color: white;
  padding: 4px 8px;
  border-radius: 6px;
  font-size: 0.7rem;
  white-space: nowrap;
  z-index: 100;
  opacity: 0;
  pointer-events: none;
  transition: opacity 0.2s;
}

.anchor-highlight:hover::after {
  opacity: 1;
}

/* Dark mode support */
[data-theme="dark"] .anchor-highlight {
  background: linear-gradient(135deg, rgba(255, 193, 7, 0.2), rgba(255, 152, 0, 0.3));
  border-bottom-color: #ffb74d;
}

[data-theme="dark"] .anchor-highlight:hover {
  background: rgba(255, 152, 0, 0.4);
}

.main.blur-mode-active .verse-card.blur-upcoming .anchor-highlight {
  filter: blur(calc(var(--recall-blur, 10px) - 4px));
}

.technique-select {
  padding: 8px 12px;
  border-radius: 10px;
  background: var(--surface);
  border: 1px solid var(--border);
  font-size: 0.8rem;
}

.verse-small-play-btn {
  width: 28px;
  height: 28px;
  border-radius: 50%;
  background: var(--accent);
  border: none;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.2s ease;
  color: white;
  box-shadow: 0 2px 6px rgba(0, 0, 0, 0.1);
}

.verse-small-play-btn i {
  font-size: 0.72rem;
}

.verse-small-play-btn:hover {
  transform: scale(1.05);
  background: rgba(255, 255, 255, 0.85);
  color: var(--accent);
}

.verse-self-check-btn {
  min-height: 28px;
  padding: 0 8px;
  border-radius: 999px;
  border: 1px solid rgba(154, 103, 56, 0.14);
  background: rgba(255, 255, 255, 0.88);
  color: var(--text);
  display: inline-flex;
  align-items: center;
  gap: 6px;
  font-size: 0.68rem;
  font-weight: 700;
  cursor: pointer;
  transition: all 0.2s ease;
}

.verse-self-check-btn:hover {
  border-color: rgba(154, 103, 56, 0.28);
  background: var(--accent-light);
  color: var(--accent);
}

.verse-self-check-btn.active {
  background: linear-gradient(135deg, rgba(154, 103, 56, 0.15), rgba(154, 103, 56, 0.05));
  border-color: rgba(154, 103, 56, 0.26);
  color: var(--accent);
}

.verse-self-check-btn em {
  min-width: 18px;
  height: 18px;
  padding: 0 5px;
  border-radius: 999px;
  background: rgba(154, 103, 56, 0.12);
  color: inherit;
  font-size: 0.66rem;
  font-style: normal;
  display: inline-flex;
  align-items: center;
  justify-content: center;
}

.self-check-modal {
  width: min(1280px, calc(100vw - 20px));
  max-height: calc(100dvh - 20px);
  height: auto;
  padding: 0;
  overflow: hidden;
  animation: selfCheckModalIn 180ms ease;
}

.self-check-modal-overlay {
  z-index: 12100;
}

@keyframes selfCheckModalIn {
  from {
    opacity: 0;
    transform: translateY(12px) scale(0.985);
  }

  to {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}

.self-check-modal-header {
  align-items: flex-start;
  padding-top: 14px;
  padding-bottom: 14px;
}

.self-check-modal-head-copy {
  display: grid;
  gap: 6px;
}

.self-check-modal-head-copy p {
  margin: 0;
  color: var(--text-muted);
  font-size: 0.86rem;
}

.self-check-modal-body {
