  align-items: center;
  justify-content: center;
  cursor: pointer;
  box-shadow: 0 8px 18px rgba(85, 55, 26, 0.12);
  transition: transform 0.18s ease, background 0.18s ease, border-color 0.18s ease;
}

.self-check-ayah-action:hover {
