}

.self-check-modal-ayah.tajweed-enabled .tajweed-idgh_w_ghn,
.self-check-modal-ayah.tajweed-enabled .tajweed-ikhf,
.self-check-modal-ayah.tajweed-enabled .tajweed-ikhf_shfw {
