.self-check-modal-ayah.tajweed-enabled .tajweed-madda_normal,
.self-check-modal-ayah.tajweed-enabled .tajweed-madda_permissible,
.self-check-modal-ayah.tajweed-enabled .tajweed-madda_necessary,
