}

@keyframes selfCheckRecorderGlow {

  0%,
  100% {
    box-shadow: 0 18px 40px rgba(85, 55, 26, 0.08);
  }

  50% {
    box-shadow: 0 22px 46px rgba(154, 103, 56, 0.14);
  }
}

.self-check-kicker {
  font-size: 0.7rem;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--text-muted);
}

.self-check-recorder-head,
.self-check-recorder-meta,
.self-check-review-head,
.self-check-review-actions,
.self-check-live-actions,
.self-check-idle-actions,
.self-check-attempt-top,
.self-check-attempt-actions {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 12px;
}

.self-check-recorder-head>div:first-child,
.self-check-review-head>div:first-child,
.self-check-attempt-copy {
  flex: 1;
  min-width: 0;
}

.self-check-recorder-head strong,
.self-check-attempts-head strong,
.self-check-live-copy strong,
.self-check-review-head strong,
.self-check-attempt-copy strong {
  color: var(--text);
  font-size: 0.96rem;
  display: block;
}

.self-check-live-copy span,
.self-check-review-head span,
.self-check-attempt-copy span {
  margin: 0;
  color: var(--text-muted);
  font-size: 0.8rem;
  line-height: 1.55;
}

.self-check-recorder-meta {
  justify-content: flex-start;
  flex-wrap: wrap;
}

.self-check-recorder-meta span,
.self-check-attempts-count {
  display: inline-flex;
  align-items: center;
  min-height: 28px;
  padding: 0 10px;
  border-radius: 999px;
  border: 1px solid rgba(154, 103, 56, 0.12);
  background: rgba(255, 255, 255, 0.84);
  color: var(--text-muted);
  font-size: 0.74rem;
  font-weight: 600;
}

.self-check-recorder-meta-clickable button {
  display: inline-flex;
  align-items: center;
  min-height: 28px;
  padding: 0 10px;
  border-radius: 999px;
  border: 1px solid rgba(154, 103, 56, 0.12);
  background: rgba(255, 255, 255, 0.86);
  color: #6f6258;
  font: inherit;
  font-size: 0.74rem;
  font-weight: 750;
  cursor: pointer;
}

.self-check-recorder-meta-clickable button:hover {
  border-color: rgba(154, 103, 56, 0.24);
  background: #fff;
  color: var(--text);
}

.self-check-ai-detail {
  margin-top: 12px;
}

.self-check-library-link {
  min-height: 34px;
  padding: 0 12px;
  border-radius: 14px;
  border: 1px solid rgba(154, 103, 56, 0.12);
  background: rgba(255, 255, 255, 0.78);
  color: var(--text);
  display: inline-flex;
  align-items: center;
  gap: 8px;
  font-size: 0.8rem;
  font-weight: 700;
  cursor: pointer;
  transition: all 0.2s ease;
}

.self-check-library-link:hover {
  background: var(--accent-light);
  color: var(--accent);
  border-color: rgba(154, 103, 56, 0.24);
}

.self-check-status {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 12px;
  border-radius: 14px;
  border: 1px solid transparent;
  font-size: 0.8rem;
  font-weight: 600;
}

.self-check-status-success {
  background: rgba(89, 138, 96, 0.1);
  border-color: rgba(89, 138, 96, 0.16);
  color: #43684a;
}

.self-check-status-warning {
  background: rgba(166, 121, 72, 0.12);
  border-color: rgba(166, 121, 72, 0.18);
  color: #7d5d37;
}

.self-check-status-info {
  background: rgba(154, 103, 56, 0.08);
  border-color: rgba(154, 103, 56, 0.14);
  color: var(--text);
}

.self-check-live-stage {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
  padding: 14px 16px;
  border-radius: 18px;
  background: rgba(255, 255, 255, 0.7);
  border: 1px solid rgba(154, 103, 56, 0.12);
}

.self-check-live-card,
.self-check-review-card {
  display: grid;
  gap: 14px;
}

.self-check-review-card {
  padding: 14px;
  border-radius: 14px;
  border: 1px solid rgba(154, 103, 56, 0.12);
  background: rgba(255, 255, 255, 0.62);
}

.self-check-live-copy {
  display: grid;
  gap: 4px;
}

.self-check-live-pulse {
  display: inline-flex;
  align-items: flex-end;
  gap: 5px;
}

.self-check-live-pulse span {
  width: 6px;
  border-radius: 999px;
  background: var(--accent);
  animation: selfCheckPulse 0.9s ease-in-out infinite;
}

.self-check-live-pulse span:nth-child(1) {
  height: 14px;
}

.self-check-live-pulse span:nth-child(2) {
  height: 22px;
  animation-delay: 0.12s;
}

.self-check-live-pulse span:nth-child(3) {
  height: 16px;
  animation-delay: 0.24s;
}

@keyframes selfCheckPulse {

  0%,
  100% {
    transform: scaleY(0.7);
    opacity: 0.72;
  }

  50% {
    transform: scaleY(1.1);
    opacity: 1;
  }
}

.self-check-result-block {
  display: grid;
  gap: 12px;
}

.self-check-result-label {
  display: grid;
  gap: 2px;
}

.self-check-result-group {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 10px;
}

.self-check-result-btn {
  min-height: auto;
  padding: 12px;
  border-radius: 12px;
  border: 1px solid rgba(154, 103, 56, 0.16);
  background: rgba(255, 255, 255, 0.9);
  font-size: 0.78rem;
  font-weight: 700;
  cursor: pointer;
  transition: all 0.2s ease;
  display: grid;
  gap: 4px;
  text-align: left;
  color: var(--text);
}

.self-check-result-btn-label {
  font-size: 0.86rem;
  font-weight: 700;
}

.self-check-result-btn-hint {
  font-size: 0.72rem;
  font-weight: 500;
  line-height: 1.45;
  opacity: 0.95;
  color: var(--text-muted);
}

.self-check-result-btn.active {
  transform: translateY(-1px);
  box-shadow: 0 12px 26px rgba(85, 55, 26, 0.16);
  border-color: rgba(154, 103, 56, 0.42);
  outline: 2px solid rgba(154, 103, 56, 0.18);
  outline-offset: 2px;
}

.self-check-result-btn.tone-excellent {
  color: #12351f;
  border-color: rgba(34, 118, 64, 0.38);
  background: #dff0e4;
}

.self-check-result-btn.tone-good {
  color: #3d2a11;
  border-color: rgba(161, 108, 38, 0.38);
  background: #f3e1c5;
}

.self-check-result-btn.tone-review {
  color: #4b2217;
  border-color: rgba(174, 82, 51, 0.38);
  background: #f3d8ce;
}

.self-check-result-btn:hover {
  transform: translateY(-1px);
  box-shadow: 0 12px 24px rgba(154, 103, 56, 0.16);
}

.self-check-attempts-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
}

.self-check-attempts-list {
  display: grid;
  gap: 8px;
  max-height: 40vh;
  overflow-y: auto;
  padding-right: 4px;
  align-content: start;
}

.self-check-attempt-card {
  gap: 10px;
  padding: 14px;
  border-radius: 12px;
  background: rgba(255, 255, 255, 0.7);
  box-shadow: 0 10px 24px rgba(85, 55, 26, 0.05);
}

.self-check-attempt-card.playing {
  border-color: rgba(154, 103, 56, 0.22);
  box-shadow: 0 16px 32px rgba(154, 103, 56, 0.12);
}

.self-check-attempt-copy {
  display: grid;
  gap: 3px;
}

.self-check-attempt-meta {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  color: var(--text-muted);
  font-size: 0.8rem;
}

.self-check-attempt-meta span {
  display: inline-flex;
  align-items: center;
  gap: 8px;
}

.self-check-attempt-actions {
  align-items: center;
  padding-top: 2px;
}

.self-check-empty {
  min-height: 220px;
  display: grid;
  place-items: center;
  align-content: center;
  gap: 10px;
  text-align: center;
  color: var(--text-muted);
  padding: 12px;
}

.self-check-empty h3,
.self-check-empty p {
  margin: 0;
}

.self-check-empty p {
  max-width: 280px;
  line-height: 1.6;
}

.self-check-empty-icon {
  width: 56px;
  height: 56px;
  border-radius: 18px;
  border: 1px solid rgba(154, 103, 56, 0.12);
  background: rgba(154, 103, 56, 0.08);
  color: var(--accent);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-size: 1.2rem;
}

.self-check-action-btn,
.self-check-preview-btn {
  min-height: 42px;
}

/* Add to your style section */
.countdown-overlay {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0, 0, 0, 0.85);
  backdrop-filter: blur(12px);
  z-index: 99999;
  display: flex;
  align-items: center;
  justify-content: center;
}

.countdown-modal {
  text-align: center;
  background: transparent;
  border: none;
  box-shadow: none;
}

.countdown-number {
  font-size: 8rem;
  font-weight: 800;
  color: var(--accent);
  animation: pulse 1s ease infinite;
}

.countdown-text {
  font-size: 1.5rem;
  color: white;
  margin-top: 20px;
}

@keyframes pulse {

  0%,
  100% {
    transform: scale(1);
  }

  50% {
    transform: scale(1.1);
  }
}

@media (max-width: 640px) {
  .countdown-number {
    font-size: 5rem;
  }

  .countdown-text {
    font-size: 1.2rem;
  }
}

/* Add these styles if missing */
.technique-peek-hint {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 12px;
  margin-top: 8px;
  border-radius: 10px;
  background: rgba(154, 103, 56, 0.08);
  border: 1px solid rgba(154, 103, 56, 0.12);
  font-size: 0.7rem;
  color: var(--text-muted);
}

.technique-peek-hint i {
  color: var(--accent);
  font-size: 0.8rem;
  flex-shrink: 0;
}

.technique-peek-hint kbd {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 4px;
  padding: 2px 6px;
  font-family: monospace;
  font-size: 0.65rem;
  font-weight: 600;
  color: var(--accent);
  display: inline-block;
}

/* Add to style section */
.countdown-overlay {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0, 0, 0, 0.85);
  backdrop-filter: blur(12px);
  z-index: 10000;
  display: flex;
  align-items: center;
  justify-content: center;
  animation: fadeIn 0.3s ease;
}

.countdown-modal {
  text-align: center;
  animation: scaleIn 0.4s cubic-bezier(0.34, 1.2, 0.64, 1);
  background: transparent;
  border: none;
  box-shadow: none;
}

.countdown-number {
  font-size: 8rem;
  font-weight: 800;
  color: var(--accent);
  text-shadow: 0 0 30px rgba(154, 103, 56, 0.5);
  animation: pulse 1s ease infinite;
  font-family: monospace;
}

.countdown-text {
  font-size: 1.5rem;
  color: white;
  margin-top: 20px;
  font-weight: 500;
  letter-spacing: 2px;
}

.countdown-hint {
  font-size: 0.85rem;
  color: rgba(255, 255, 255, 0.6);
  margin-top: 12px;
}

@keyframes fadeIn {
  from {
    opacity: 0;
  }

  to {
    opacity: 1;
  }
}

@keyframes scaleIn {
  from {
    opacity: 0;
    transform: scale(0.8);
  }

  to {
    opacity: 1;
    transform: scale(1);
  }
}

@keyframes pulse {

  0%,
  100% {
    transform: scale(1);
  }

  50% {
    transform: scale(1.1);
  }
}

@media (max-width: 640px) {
  .countdown-number {
    font-size: 5rem;
  }

  .countdown-text {
    font-size: 1.2rem;
  }
}


/* Mobile */
@media (max-width: 768px) {
  .wavemark-bars {
    height: 30px;
    gap: 1.5px;
  }

  .wavemark-playhead::before {
    width: 8px;
    height: 8px;
    top: -5px;
    left: -3px;
  }
}

.waveform-canvas {
  width: 100%;
  height: 60px;
  display: block;
  border-radius: 8px;
  cursor: pointer;
}

/* Settings notice */
.settings-notice {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 10px 14px;
  background: var(--accent-light);
  border-radius: 12px;
  margin-bottom: 20px;
  font-size: 0.75rem;
  color: var(--accent);
  border: 1px solid var(--accent-soft);
}

.settings-notice i {
  font-size: 0.9rem;
}

/* Login Hero Section */
.login-hero {
  padding-top: calc(80px + env(safe-area-inset-top, 0px)) !important;
  margin-top: 0 !important;
  min-height: calc(100vh - 100px);
  padding: 34px 20px 48px;
  align-items: stretch;
}

.guest-shell {
  margin-top: 0 !important;
  width: min(1180px, 100%);
  margin: 0 auto;
  display: grid;
  gap: 22px;
  animation: loginFadeIn 0.5s ease-out;
}

.guest-hero {
  display: grid;
  grid-template-columns: minmax(0, 1.2fr) minmax(320px, 0.8fr);
  gap: 24px;
  align-items: stretch;
}

.guest-hero-copy,
.guest-hero-panel,
.guest-section,
.guest-panel {
  border: 1px solid var(--border);
  background: linear-gradient(180deg, rgba(255, 252, 247, 0.96), rgba(247, 240, 231, 0.92));
  box-shadow: var(--shadow-lg);
}

.guest-hero-copy {
  border-radius: 34px;
  padding: 38px;
  display: grid;
  gap: 18px;
  align-content: center;
}

.guest-kicker,
.guest-section-kicker {
  display: inline-flex;
  width: fit-content;
  padding: 6px 10px;
  border-radius: 999px;
  background: rgba(154, 103, 56, 0.1);
  color: var(--accent);
  font-size: 0.72rem;
  font-weight: 700;
  letter-spacing: 0.05em;
  text-transform: uppercase;
}

.guest-hero-copy h1 {
  margin: 0;
  font-size: clamp(2.5rem, 5vw, 4rem) !important;
  margin-top: 0 !important;
  line-height: 1.06;
  letter-spacing: -0.04em;
  color: var(--text);
  max-width: 12ch;
  font-weight: 650;
}

.guest-subtitle {
  margin: 0;
  max-width: 62ch;
  font-size: 1rem;
  line-height: 1.65;
  color: var(--text-muted);
}

.guest-copy-stack {
  display: grid;
  gap: 10px;
}

.guest-copy-support,
.guest-cta-note {
  margin: 0;
  max-width: 58ch;
  font-size: 0.82rem;
  line-height: 1.6;
  color: var(--text-muted);
}

.guest-action-row {
  margin-top: 1rem;
  display: flex;
  gap: 12px;
  flex-wrap: wrap;
  align-items: center;
}

.guest-primary-btn {
  width: auto;
  min-width: 260px;
  margin-bottom: 0;
  min-height: 58px;
  padding-inline: 28px;
  font-size: 1rem;
  box-shadow: 0 14px 30px rgba(154, 103, 56, 0.24);
}

.guest-secondary-btn {
  min-height: 58px;
  padding: 14px 24px;
  border-radius: 60px;
  border: 1px solid rgba(154, 103, 56, 0.18);
  background: rgba(255, 255, 255, 0.78);
  color: var(--text);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  font-size: 0.96rem;
  font-weight: 600;
  box-shadow: 0 12px 22px rgba(61, 40, 20, 0.06);
  transition: transform 0.2s ease, box-shadow 0.2s ease, border-color 0.2s ease;
}

.guest-secondary-btn:hover {
  transform: translateY(-1px);
  box-shadow: var(--shadow-md);
  border-color: rgba(154, 103, 56, 0.28);
}

.guest-proof-row {
  display: flex;
  gap: 10px;
  flex-wrap: wrap;
}

.guest-proof-row span {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  min-height: 34px;
  padding: 0 12px;
  border-radius: 999px;
  border: 1px solid rgba(154, 103, 56, 0.12);
  background: rgba(255, 255, 255, 0.72);
  color: var(--text-muted);
  font-size: 0.76rem;
  font-weight: 600;
}

.guest-hero-panel {
  border-radius: 30px;
  padding: 22px;
  display: grid;
}

.guest-preview-card {
  display: grid;
  gap: 16px;
  align-content: start;
}

.guest-preview-icon {
  width: 68px;
  height: 68px;
  border-radius: 22px;
  display: grid;
  place-items: center;
  background: linear-gradient(135deg, var(--accent), var(--accent-strong));
  color: #fff;
  box-shadow: 0 12px 28px rgba(154, 103, 56, 0.2);
}

.guest-preview-icon i {
  font-size: 1.8rem;
}

.guest-preview-copy strong,
.guest-panel h3,
.guest-section h2,
.guest-feature-card strong,
.guest-benefit-item strong,
.guest-preview-step strong {
  color: var(--text);
}

.guest-preview-copy p,
.guest-preview-step small,
.guest-feature-card p,
.guest-flow-item p,
.guest-benefit-item p,
.guest-section-head p {
  color: var(--text-muted);
}

.guest-preview-steps {
  display: grid;
  gap: 12px;
}

.guest-preview-step {
  display: grid;
  grid-template-columns: 34px minmax(0, 1fr);
  gap: 12px;
  padding: 12px;
  border-radius: 16px;
  background: rgba(255, 255, 255, 0.62);
  border: 1px solid rgba(154, 103, 56, 0.12);
}

.guest-preview-step span,
.guest-flow-item span {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 34px;
  height: 34px;
  border-radius: 999px;
  background: rgba(154, 103, 56, 0.12);
  color: var(--accent);
  font-size: 0.82rem;
  font-weight: 700;
}

.guest-section {
  border-radius: 28px;
  padding: 28px;
  display: grid;
  gap: 18px;
}

.guest-section-row {
  grid-template-columns: minmax(240px, 0.42fr) minmax(0, 1fr);
  gap: 22px;
  align-items: start;
}

.guest-section-head {
  display: grid;
  gap: 8px;
}

.guest-section-head-side {
  align-content: start;
}

.guest-section-head h2 {
  margin: 0;
  font-size: clamp(1.35rem, 2vw, 1.9rem);
  font-weight: 650;
  letter-spacing: -0.03em;
}

.guest-feature-grid {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 14px;
}

.guest-feature-card {
  border-radius: 18px;
  padding: 18px;
  background: rgba(255, 255, 255, 0.68);
  border: 1px solid rgba(154, 103, 56, 0.12);
  display: grid;
  gap: 10px;
}

.guest-feature-card i {
  width: 44px;
  height: 44px;
  border-radius: 14px;
  display: grid;
  place-items: center;
  background: rgba(154, 103, 56, 0.1);
  color: var(--accent);
  font-size: 1.05rem;
}

.guest-feature-card strong,
.guest-panel h3 {
  font-size: 0.98rem;
  font-weight: 650;
}

.guest-feature-card p,
.guest-benefit-item p,
.guest-flow-item p {
  margin: 0;
  font-size: 0.82rem;
  line-height: 1.55;
}

.guest-section-split {
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 16px;
  background: transparent;
  border: none;
  box-shadow: none;
  padding: 0;
}

.guest-panel {
  border-radius: 24px;
  padding: 24px;
  display: grid;
  gap: 16px;
}

.guest-panel-head {
  display: grid;
  gap: 8px;
}

.guest-panel h3 {
  margin: 0;
  font-size: 1.18rem;
}

.guest-flow-list,
.guest-benefit-list {
  display: grid;
  gap: 12px;
}

.guest-flow-item {
  display: grid;
  grid-template-columns: 40px minmax(0, 1fr);
  gap: 12px;
  align-items: start;
}

.guest-benefit-item {
  display: grid;
  grid-template-columns: 40px minmax(0, 1fr);
  gap: 12px;
  align-items: start;
}

.guest-benefit-item i {
  width: 40px;
  height: 40px;
  border-radius: 12px;
  display: grid;
  place-items: center;
  background: rgba(154, 103, 56, 0.1);
  color: var(--accent);
  font-size: 1rem;
}

.guest-benefit-item strong {
  display: block;
  margin-bottom: 4px;
}

.login-btn {
  width: 100%;
  padding: 14px 24px;
  background: linear-gradient(135deg, var(--accent), var(--accent-strong));
  color: white;
  border: none;
  border-radius: 60px;
  font-size: 1rem;
  font-weight: 600;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  transition: all 0.2s ease;
  margin-bottom: 20px;
  box-shadow: 0 4px 12px rgba(154, 103, 56, 0.3);
}

.login-btn:hover {
  transform: translateY(-2px);
  box-shadow: 0 8px 24px rgba(154, 103, 56, 0.4);
}

.login-btn:active {
  transform: translateY(0);
}

.login-note {
  font-size: 0.7rem;
  color: var(--text-muted);
  margin: 0;
  line-height: 1.4;
}

[data-theme="dark"] .login-hero {
  background: transparent;
}

[data-theme="dark"] .guest-hero-copy,
[data-theme="dark"] .guest-hero-panel,
[data-theme="dark"] .guest-section,
[data-theme="dark"] .guest-panel {
  background: linear-gradient(180deg, rgba(28, 33, 31, 0.96), rgba(22, 27, 25, 0.94));
  border-color: rgba(109, 160, 145, 0.22);
  box-shadow: 0 28px 60px rgba(0, 0, 0, 0.46);
}

[data-theme="dark"] .guest-proof-row span,
[data-theme="dark"] .guest-preview-step,
[data-theme="dark"] .guest-feature-card,
[data-theme="dark"] .guest-secondary-btn,
[data-theme="dark"] .guest-flow-item span,
[data-theme="dark"] .guest-benefit-item i {
  background: rgba(255, 255, 255, 0.05);
  border-color: rgba(216, 185, 150, 0.16);
}

[data-theme="dark"] .guest-kicker,
[data-theme="dark"] .guest-section-kicker {
  background: rgba(208, 160, 107, 0.14);
  color: #ddb07c;
}

[data-theme="dark"] .guest-preview-icon,
[data-theme="dark"] .guest-feature-card i {
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.34);
}

[data-theme="dark"] .guest-feature-card i,
[data-theme="dark"] .guest-benefit-item i,
[data-theme="dark"] .guest-flow-item span {
  color: #97c9ba;
}

[data-theme="dark"] .login-btn {
  box-shadow: 0 10px 24px rgba(0, 0, 0, 0.32);
}

@keyframes loginFadeIn {
  from {
    opacity: 0;
    transform: translateY(20px);
  }

  to {
    opacity: 1;
    transform: translateY(0);
  }
}

/* Responsive */
@media (max-width: 1024px) {

  .guest-hero,
  .guest-section-split {
    grid-template-columns: 1fr 1fr;
  }

  .guest-section-row {
    grid-template-columns: 1fr;
  }

  .guest-feature-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}

@media (max-width: 768px) {
  .login-hero {
    padding: 20px 0 36px;
  }

  .guest-hero,
  .guest-feature-grid,
  .guest-section-split,
  .guest-section-row {
    grid-template-columns: 1fr;
  }

  .guest-hero-copy,
  .guest-hero-panel,
  .guest-section,
  .guest-panel {
    border-radius: 24px;
  }

  .guest-hero-copy,
  .guest-section,
  .guest-panel {
    padding: 22px;
  }

  .guest-hero-copy h1 {
    max-width: none;
    font-size: 1.9rem;
  }

  .guest-action-row {
    flex-direction: column;
    align-items: stretch;
  }

  .guest-primary-btn,
  .guest-secondary-btn {
    width: 100%;
    min-width: 0;
  }

  .guest-proof-row {
    flex-direction: column;
  }

  .guest-proof-row span {
    width: 100%;
    justify-content: flex-start;
  }

  .guest-copy-support,
  .guest-cta-note {
    max-width: none;
  }
}

@media (max-width: 520px) {
  .guest-hero-copy h1 {
    font-size: 1.7rem;
  }

  .guest-subtitle {
    font-size: 0.92rem;
  }

  .guest-section-head h2,
  .guest-panel h3 {
    font-size: 1.1rem;
  }
}

/* Save Name Modal Styles */
.save-name-modal {
  max-width: 680px;
  width: 100%;
}

.save-modal-desc {
  font-size: 0.85rem;
  color: var(--text-muted);
  margin-bottom: 20px;
  line-height: 1.4;
}

.save-name-input-group {
  margin-bottom: 16px;
}

.save-name-input-group label {
  display: block;
  font-size: 0.75rem;
  font-weight: 600;
  color: var(--text);
  margin-bottom: 8px;
}

.save-name-input {
  width: 100%;
  padding: 12px 14px;
  border-radius: 12px;
  border: 1px solid var(--border);
  background: var(--surface);
  font-size: 0.9rem;
  color: var(--text);
  transition: all 0.2s;
}

.save-name-input:focus {
  outline: none;
  border-color: var(--accent);
  box-shadow: 0 0 0 3px var(--accent-light);
}

.save-preview-info {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 10px 12px;
  background: var(--accent-light);
  border-radius: 10px;
  font-size: 0.75rem;
  color: var(--text-muted);
  margin-top: 8px;
}

.save-preview-info i {
  color: var(--accent);
  font-size: 0.9rem;
}

/* Fix saved tab layout */
.saved-sessions-container {
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.78), rgba(255, 248, 242, 0.62));
  border: 1px solid var(--border);
  border-radius: 18px;
  padding: 16px;
  box-shadow: var(--shadow-sm);
}

.saved-header {
  margin-bottom: 16px;
  padding-bottom: 12px;
  border-bottom: 1px solid var(--border);
}

.saved-header h3 {
  margin: 0 0 4px 0;
  font-size: 1.05rem;
  font-weight: 650;
  color: var(--text);
  display: flex;
  align-items: center;
  gap: 8px;
}

.saved-header p {
  margin: 0;
  font-size: 0.82rem;
  line-height: 1.35;
  color: var(--text-muted);
}

.sessions-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
  overflow-y: auto;
}

.session-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 12px;
  transition: all 0.2s ease;
  overflow: hidden;
}

.session-info {
  flex: 1;
  min-width: 0;
  padding: 10px 12px;
  cursor: pointer;
}

.session-info:hover {
  background: var(--accent-light);
}

.session-name {
  font-weight: 600;
  font-size: 0.86rem;
  color: var(--text);
  margin-bottom: 4px;
  display: flex;
  align-items: center;
  gap: 6px;
}

.session-name i {
  color: var(--accent);
  font-size: 0.7rem;
}

.session-meta {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  font-size: 0.6rem;
  color: var(--text-muted);
}

.session-meta span {
  display: inline-flex;
  align-items: center;
  gap: 3px;
}

.delete-btn {
  width: 36px;
  height: 36px;
  margin-right: 8px;
  border-radius: 8px;
  background: transparent;
  border: 1px solid var(--border);
  cursor: pointer;
  color: #dc3545;
  transition: all 0.2s;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}

.delete-btn:hover {
  background: #dc3545;
  color: white;
  border-color: #dc3545;
}

.save-section {
  padding-top: 12px;
  border-top: 1px solid var(--border);
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
}

.current-info {
  display: flex;
  align-items: center;
  gap: 8px;
  flex: 1;
  min-width: 0;
  padding: 8px 10px;
  background: var(--accent-light);
  border-radius: 10px;
}

.current-info i {
  font-size: 1rem;
  color: var(--accent);
  flex-shrink: 0;
}

.current-info div {
  display: flex;
  flex-direction: column;
  min-width: 0;
}

.current-info strong {
  font-size: 0.75rem;
  color: var(--text);
}

.current-info small {
  font-size: 0.6rem;
  color: var(--text-muted);
}

.save-btn {
  padding: 8px 16px;
  background: linear-gradient(135deg, var(--accent), var(--accent-strong));
  color: white;
  border: none;
  border-radius: 10px;
  cursor: pointer;
  font-size: 0.75rem;
  font-weight: 500;
  display: flex;
  align-items: center;
  gap: 5px;
  transition: all 0.2s;
  flex-shrink: 0;
}

.save-btn:hover {
  transform: translateY(-1px);
  box-shadow: 0 2px 8px rgba(154, 103, 56, 0.3);
}

.save-btn:active {
  transform: translateY(0);
}

