/* Action Buttons Group - Perfect Alignment */
.action-buttons-group {
  display: flex;
  gap: 8px;
  align-items: center;
}

.action-icon-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 42px;
  height: 42px;
  border-radius: 12px;
  border: 1px solid var(--border);
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.88), rgba(255, 255, 255, 0.68));
  box-shadow: var(--shadow-sm);
  font-size: 1.1rem;
  cursor: pointer;
  transition: all 0.2s ease;
  color: var(--text-muted);
  flex-shrink: 0;
}

.action-icon-btn:hover {
  transform: translateY(-1px);
  background: var(--accent-light);
  border-color: var(--accent);
  color: var(--accent);
  box-shadow: var(--shadow-md);
}

.action-icon-btn:active {
  transform: translateY(0);
}

.action-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  height: 36px;
  padding: 0 14px;
  border-radius: 12px;
  font-weight: 600;
  font-size: 0.8rem;
  cursor: pointer;
  transition: all 0.2s ease;
  border: none;
  white-space: nowrap;
  flex-shrink: 0;
}

.action-btn-secondary {
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.88), rgba(255, 255, 255, 0.68));
  border: 1px solid var(--border);
  color: var(--text);
  box-shadow: var(--shadow-sm);
}

.action-btn-secondary:hover {
  transform: translateY(-1px);
  background: var(--accent-light);
  border-color: var(--accent);
  color: var(--accent);
  box-shadow: var(--shadow-md);
}

.action-btn-exit {
  background: rgba(255, 247, 243, 0.9);
  border: 1px solid rgba(154, 103, 56, 0.14);
}

.action-btn-exit:hover {
  background: rgba(255, 239, 232, 0.96);
  border-color: rgba(139, 79, 57, 0.22);
  color: #8b4f39;
}

.action-btn-primary {
  background: linear-gradient(135deg, var(--accent), var(--accent-strong));
  color: white;
  box-shadow: 0 4px 12px rgba(154, 103, 56, 0.25);
  border: none;
}

.action-btn-primary:hover:not(:disabled) {
  transform: translateY(-1px);
  box-shadow: 0 6px 16px rgba(154, 103, 56, 0.35);
}

.action-btn-primary:disabled {
  opacity: 0.5;
  cursor: not-allowed;
  transform: none;
}

.action-btn-secondary:active,
.action-icon-btn:active {
  transform: translateY(0);
}

.action-btn-recitation-check {
  border-color: rgba(154, 103, 56, 0.2);
}

.action-btn-recitation-check:disabled {
  cursor: not-allowed;
  opacity: 0.55;
  transform: none;
}

.recitation-check-panel {
  margin-top: 14px;
  padding: 16px;
  border: 1px solid rgba(154, 103, 56, 0.16);
  border-radius: 16px;
  background: linear-gradient(180deg, rgba(255, 253, 248, 0.92), rgba(250, 244, 236, 0.82));
  box-shadow: var(--shadow-sm);
}

.recitation-check-panel-inline {
  margin: 14px 0;
  box-shadow: none;
}

.recitation-check-head {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 14px;
}

.recitation-check-head-actions {
  display: inline-flex;
  align-items: center;
  gap: 8px;
}

.recitation-result-close {
  width: 36px;
  height: 36px;
  border-radius: 999px;
  border: 1px solid rgba(154, 103, 56, 0.16);
  background: rgba(255, 255, 255, 0.68);
  color: var(--text-muted);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: background 0.18s ease, color 0.18s ease, border-color 0.18s ease;
}

.recitation-result-close:hover {
  border-color: rgba(154, 103, 56, 0.32);
  background: rgba(154, 103, 56, 0.1);
  color: var(--text);
}

.recitation-check-kicker {
  display: block;
  margin-bottom: 4px;
  color: var(--text-muted);
  font-size: 0.68rem;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

.recitation-check-head h2 {
  margin: 0;
  color: var(--text);
  font-size: 1.05rem;
  font-weight: 700;
}

.recitation-check-score {
  min-width: 64px;
  padding: 8px 12px;
  border-radius: 999px;
  background: rgba(154, 103, 56, 0.12);
  color: var(--accent-strong);
  text-align: center;
  font-weight: 750;
}

.recitation-check-score.tone-excellent {
  background: rgba(66, 145, 96, 0.14);
  color: #2f7a4d;
}

.recitation-check-score.tone-good {
  background: rgba(176, 126, 50, 0.16);
  color: #7b5223;
}

.recitation-check-score.tone-review {
  background: rgba(180, 87, 61, 0.14);
  color: #994833;
}

.recitation-check-status,
.recitation-check-error {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-top: 12px;
  color: var(--text-muted);
  font-weight: 560;
}

.recitation-check-status .bi-record-circle {
  color: #b84a35;
}

.recitation-check-actions {
  display: flex;
  justify-content: flex-end;
  margin-top: 12px;
}

.recitation-result-actions {
  display: flex;
  justify-content: flex-end;
  flex-wrap: wrap;
  gap: 10px;
}

.recitation-delete-btn {
  color: #994833;
}

.recitation-check-error {
  color: #9f3f2d;
}

.recitation-check-body {
  margin-top: 12px;
}

.recitation-live-review,
.recitation-check-results {
  display: grid;
  gap: 12px;
  margin-top: 14px;
}

.recitation-live-review-compact {
  padding: 10px 12px;
  border: 1px solid rgba(37, 112, 104, 0.18);
  border-radius: 12px;
  background: rgba(37, 112, 104, 0.06);
}

.recitation-live-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  color: var(--text-muted);
  font-size: 0.86rem;
  font-weight: 650;
}

.recitation-live-head strong {
  color: var(--text);
}

.recitation-word-stream {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  align-items: center;
  justify-content: flex-start;
  padding: 14px;
  border: 1px solid rgba(154, 103, 56, 0.14);
  border-radius: 14px;
  background: rgba(255, 255, 255, 0.58);
  line-height: 2.1;
}

.recitation-word-stream-final {
  background: rgba(154, 103, 56, 0.045);
}

.recitation-word-chip {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-height: 34px;
  padding: 4px 10px;
  border-radius: 999px;
  border: 1px solid rgba(154, 103, 56, 0.12);
  background: rgba(255, 255, 255, 0.72);
  color: var(--text);
  font-size: 1.06rem;
  font-weight: 700;
  transition: transform 0.18s ease, background 0.18s ease, border-color 0.18s ease, color 0.18s ease;
}

.recitation-word-chip.word-pending {
  color: var(--text-muted);
  opacity: 0.62;
}

.recitation-word-chip.word-correct {
  border-color: rgba(66, 145, 96, 0.28);
  background: rgba(66, 145, 96, 0.14);
  color: #2f7a4d;
  animation: recitationWordPop 180ms ease;
}

.recitation-word-chip.word-partial {
  border-color: rgba(176, 126, 50, 0.3);
  background: rgba(176, 126, 50, 0.16);
  color: #7b5223;
  animation: recitationWordPop 180ms ease;
}

.recitation-word-chip.word-incorrect {
  border-color: rgba(180, 87, 61, 0.28);
  background: rgba(180, 87, 61, 0.14);
  color: #994833;
  animation: recitationWordPop 180ms ease;
}

@keyframes recitationWordPop {
  from {
    transform: translateY(3px) scale(0.98);
  }

  to {
    transform: translateY(0) scale(1);
  }
}

.recitation-result-stats {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 10px;
}

.recitation-result-stat {
  min-height: 96px;
  display: grid;
  gap: 4px;
  padding: 12px;
  border-radius: 14px;
  border: 1px solid rgba(154, 103, 56, 0.14);
  background: rgba(255, 255, 255, 0.68);
}

.recitation-result-stat span,
.recitation-next-card span {
  color: var(--text-muted);
  font-size: 0.72rem;
  font-weight: 750;
  letter-spacing: 0.07em;
  text-transform: uppercase;
}

.recitation-result-stat strong {
  color: var(--text);
  font-size: 1.35rem;
  line-height: 1;
}

.recitation-result-stat small,
.recitation-next-card p {
  color: var(--text-muted);
  line-height: 1.45;
}

.recitation-next-card {
  display: grid;
  gap: 6px;
  padding: 14px;
  border: 1px solid rgba(154, 103, 56, 0.14);
  border-radius: 14px;
  background: rgba(255, 255, 255, 0.68);
}

.recitation-next-card strong {
  color: var(--text);
  font-size: 1rem;
}

.recitation-next-card p {
  margin: 0;
}

.recitation-check-recommendation {
  margin: 0 0 12px;
  color: var(--text);
  font-weight: 600;
  line-height: 1.45;
}

.recitation-check-feedback-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 10px;
}

.recitation-check-feedback-card {
  min-height: 74px;
  padding: 12px;
  border: 1px solid rgba(154, 103, 56, 0.14);
  border-radius: 14px;
  background: rgba(255, 255, 255, 0.68);
  color: var(--text-muted);
}

.recitation-check-feedback-card strong {
  display: block;
  margin-bottom: 6px;
  color: var(--text);
  font-size: 0.82rem;
  font-weight: 650;
}

.recitation-check-feedback-card strong i {
  margin-right: 5px;
  color: var(--accent);
}

.recitation-check-transcript {
  margin-top: 12px;
  color: var(--text-muted);
}

.recitation-check-transcript summary {
  cursor: pointer;
  font-weight: 600;
}

.recitation-check-transcript p {
  margin: 8px 0 0;
  color: var(--text);
  font-size: 1.08rem;
  line-height: 1.8;
}

[data-theme="dark"] .recitation-check-panel {
  border-color: rgba(214, 183, 132, 0.18);
  background: linear-gradient(180deg, rgba(36, 31, 27, 0.96), rgba(28, 24, 22, 0.92));
}

[data-theme="dark"] .recitation-check-feedback-card {
  border-color: rgba(214, 183, 132, 0.14);
  background: rgba(255, 255, 255, 0.045);
}

[data-theme="dark"] .recitation-word-stream,
[data-theme="dark"] .recitation-result-stat,
[data-theme="dark"] .recitation-next-card {
  border-color: rgba(214, 183, 132, 0.14);
  background: rgba(255, 255, 255, 0.045);
}

[data-theme="dark"] .recitation-word-chip {
  border-color: rgba(214, 183, 132, 0.16);
  background: rgba(255, 255, 255, 0.06);
}

[data-theme="dark"] .recitation-result-close {
  border-color: rgba(214, 183, 132, 0.16);
  background: rgba(255, 255, 255, 0.05);
}

[data-theme="dark"] .recitation-word-chip.word-correct {
  border-color: rgba(90, 190, 128, 0.3);
  background: rgba(90, 190, 128, 0.16);
  color: #9ce0b0;
}

[data-theme="dark"] .recitation-word-chip.word-partial {
  border-color: rgba(224, 171, 87, 0.3);
  background: rgba(224, 171, 87, 0.16);
  color: #f0d19b;
}

[data-theme="dark"] .recitation-word-chip.word-incorrect {
  border-color: rgba(232, 120, 89, 0.3);
  background: rgba(232, 120, 89, 0.16);
  color: #f1ad9a;
}

[data-theme="dark"] .recitation-check-score {
  background: rgba(214, 183, 132, 0.14);
  color: #f0d7ad;
}

[data-theme="dark"] .recitation-check-score.tone-excellent {
  background: rgba(90, 190, 128, 0.16);
  color: #9ce0b0;
}

[data-theme="dark"] .recitation-check-score.tone-good {
  background: rgba(224, 171, 87, 0.16);
  color: #f0d19b;
}

[data-theme="dark"] .recitation-check-score.tone-review {
  background: rgba(232, 120, 89, 0.16);
  color: #f1ad9a;
}

.memorisation-checker-overlay {
  z-index: 1500;
}

.memorisation-checker-modal {
  width: min(1040px, calc(100vw - 28px));
  max-height: min(92vh, 920px);
  display: flex;
  flex-direction: column;
  overflow: hidden;
  border: 1px solid rgba(214, 183, 132, 0.18);
  background: linear-gradient(180deg, rgba(32, 28, 25, 0.98), rgba(20, 18, 17, 0.98));
  color: var(--text);
}

.memorisation-checker-header {
  border-bottom: 1px solid rgba(214, 183, 132, 0.14);
}

.memorisation-checker-body {
  display: grid;
  grid-template-rows: minmax(0, 1fr) auto;
  gap: 16px;
  overflow: auto;
  padding: 18px;
}

.memorisation-checker-workspace,
.memorisation-checker-ayah-panel {
  border: 1px solid rgba(214, 183, 132, 0.16);
  border-radius: 18px;
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.058), rgba(255, 255, 255, 0.032));
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.055);
}

.memorisation-checker-workspace {
  display: grid;
  gap: 16px;
  padding: 16px;
}

.memorisation-checker-section-head {
  display: grid;
  gap: 4px;
}

.memorisation-checker-section-head span {
  color: #f0d7ad;
  font-size: 0.68rem;
  font-weight: 780;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

.memorisation-checker-section-head strong {
  color: #fff7ec;
  font-size: 1rem;
  line-height: 1.25;
}

.memorisation-checker-section-head p {
  max-width: 680px;
  margin: 0;
  color: rgba(255, 247, 236, 0.68);
  font-size: 0.82rem;
  line-height: 1.45;
}

.memorisation-checker-topbar {
  display: flex;
  align-items: stretch;
  justify-content: space-between;
  gap: 12px;
  flex-wrap: wrap;
}

.memorisation-checker-mode-actions {
  flex: 1 1 560px;
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 10px;
}

.memorisation-checker-mode-btn {
  min-height: 76px;
  padding: 12px;
  border-radius: 14px;
  border: 1px solid rgba(214, 183, 132, 0.14);
  background: rgba(255, 255, 255, 0.045);
  color: rgba(255, 247, 236, 0.76);
  display: grid;
  grid-template-columns: auto minmax(0, 1fr);
  grid-template-areas:
    "icon label"
    "icon copy";
  column-gap: 10px;
  row-gap: 2px;
  text-align: left;
  cursor: pointer;
  transition: border-color 0.18s ease, background 0.18s ease, transform 0.18s ease;
}

.memorisation-checker-mode-btn:hover {
  transform: translateY(-1px);
  border-color: rgba(214, 183, 132, 0.28);
  background: rgba(255, 255, 255, 0.07);
}

.memorisation-checker-mode-btn.active {
  border-color: rgba(90, 190, 128, 0.34);
  background: rgba(90, 190, 128, 0.11);
  color: #dff7e6;
}

.memorisation-checker-mode-btn i {
  grid-area: icon;
  width: 34px;
  height: 34px;
  border-radius: 12px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  background: rgba(214, 183, 132, 0.12);
  color: #f0d7ad;
}

.memorisation-checker-mode-btn span {
  grid-area: label;
  color: #fff7ec;
  font-size: 0.86rem;
  font-weight: 780;
}

.memorisation-checker-mode-btn small {
  grid-area: copy;
  color: rgba(255, 247, 236, 0.62);
  line-height: 1.35;
}

.memorisation-checker-status {
  align-self: flex-start;
  min-height: 34px;
  padding: 0 12px;
  border-radius: 999px;
  display: inline-flex;
  align-items: center;
  gap: 8px;
  background: rgba(214, 183, 132, 0.12);
  color: #f0d7ad;
  font-size: 0.78rem;
  font-weight: 700;
}

.memorisation-checker-status.recording i {
  color: #f1ad9a;
}

.memorisation-checker-live {
  display: grid;
  gap: 12px;
}

.memorisation-checker-word-stream {
  min-height: 116px;
  align-content: start;
  background: rgba(10, 9, 8, 0.28);
}

.memorisation-checker-live-placeholder {
  width: 100%;
  color: rgba(255, 247, 236, 0.48);
  font-family: var(--font-sans, inherit);
  font-size: 0.86rem;
  font-weight: 650;
  text-align: center;
}

.memory-word-hidden,
.memorisation-checker-hidden-word {
  border-color: rgba(214, 183, 132, 0.18) !important;
  background: rgba(214, 183, 132, 0.12) !important;
  color: #f0d7ad !important;
}

.memorisation-checker-hidden-word {
  display: inline-flex;
  min-width: 2.6ch;
  justify-content: center;
  border-radius: 999px;
  padding: 0 0.25em;
}

.memorisation-checker-hidden-text {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-height: 92px;
  width: 100%;
  border-radius: 14px;
  border: 1px dashed rgba(214, 183, 132, 0.26);
  color: rgba(240, 215, 173, 0.84);
  font-family: var(--font-sans, inherit);
  font-size: 1rem;
  font-weight: 700;
}

.memorisation-checker-hint {
  margin: 0;
  color: var(--text-muted);
  font-size: 0.82rem;
  line-height: 1.45;
}

.memorisation-checker-primary-actions {
  margin-top: 0;
  display: flex;
  justify-content: center;
  align-items: center;
  min-height: 48px;
}

.memorisation-checker-primary-actions .self-check-action-btn {
  flex: 0 0 auto;
  width: auto;
  min-width: 176px;
  max-width: 240px;
  min-height: 44px;
  padding: 0 18px;
  border-radius: 14px;
}

.memorisation-checker-results {
  scroll-margin-top: 20px;
  padding-top: 4px;
}

.memorisation-checker-ayah-panel {
  padding: 16px;
}

.memorisation-checker-ayah-actions {
  display: flex;
  gap: 8px;
  justify-content: flex-end;
  margin: 12px 0;
}

.memorisation-checker-ayah {
  min-height: 120px;
  padding: 16px;
  border-radius: 14px;
  border: 1px solid rgba(214, 183, 132, 0.12);
  background: rgba(255, 255, 255, 0.035);
  line-height: 2.3;
  text-align: center;
  transition: filter 0.18s ease, opacity 0.18s ease, background 0.18s ease;
}

.memorisation-checker-ayah.is-hidden {
  filter: blur(12px);
  opacity: 0.62;
  user-select: none;
  pointer-events: none;
}

.memorisation-checker-results .recitation-result-stats {
  grid-template-columns: repeat(4, minmax(0, 1fr));
}

.memorisation-checker-final-words {
  min-height: auto;
  padding: 12px;
}

.memorisation-checker-final-words .recitation-word-chip {
  min-height: 28px;
  padding: 3px 8px;
  font-size: 0.92rem;
}

.memory-word-enter-active {
  transition: opacity 180ms ease, transform 180ms ease;
}

.memory-word-enter-from {
  opacity: 0;
  transform: translateY(8px) scale(0.96);
}

.memory-word-enter-to {
  opacity: 1;
  transform: translateY(0) scale(1);
}

.memorisation-checker-modal {
  height: min(92vh, 920px);
  background: linear-gradient(180deg, #fffdf8, #f7efe5);
  border-color: rgba(154, 103, 56, 0.18);
  color: var(--text);
}

.memorisation-checker-header {
  flex: 0 0 auto;
  background: rgba(255, 255, 255, 0.72);
  border-bottom-color: rgba(154, 103, 56, 0.14);
}

.memorisation-checker-body {
  min-height: 0;
  grid-template-rows: minmax(0, 1fr) minmax(220px, 42%);
  gap: 14px;
}

.memorisation-checker-workspace,
.memorisation-checker-ayah-panel {
  min-width: 0;
  min-height: 0;
  border-color: rgba(154, 103, 56, 0.15);
  background: rgba(255, 255, 255, 0.68);
  box-shadow: none;
  overflow: hidden;
}

.memorisation-checker-workspace {
  grid-template-rows: auto minmax(0, 1fr) auto;
  overflow: auto;
}

.memorisation-checker-ayah-panel {
  display: grid;
  grid-template-rows: auto auto minmax(0, 1fr);
  overflow: auto;
}

.memorisation-checker-section-head span {
  color: var(--accent-strong);
}

.memorisation-checker-section-head strong {
  color: var(--text);
}

.memorisation-checker-section-head p {
  color: var(--text-muted);
}

.memorisation-checker-live {
  min-height: 0;
  grid-template-rows: auto minmax(150px, 1fr) auto auto;
}

.memorisation-checker-word-stream {
  min-height: 150px;
  max-height: 100%;
  overflow: auto;
  border-color: rgba(154, 103, 56, 0.14);
  background: rgba(255, 255, 255, 0.62);
  box-shadow: none;
}

.memorisation-checker-live-placeholder {
  color: var(--text-muted);
}

.memorisation-checker-ayah-actions .self-check-ayah-action {
  width: 38px;
  height: 38px;
  flex: 0 0 38px;
  border-radius: 12px;
  border: 1px solid rgba(154, 103, 56, 0.16);
  background: rgba(255, 255, 255, 0.82);
  color: var(--accent-strong);
  box-shadow: none;
}

.memorisation-checker-ayah-actions .self-check-ayah-action:hover,
.memorisation-checker-ayah-actions .self-check-ayah-action.active {
  border-color: rgba(154, 103, 56, 0.3);
  background: rgba(154, 103, 56, 0.12);
  color: var(--accent-strong);
}

.memorisation-checker-ayah {
  min-height: 0;
  max-height: 100%;
  overflow: auto;
  border-color: rgba(154, 103, 56, 0.12);
  background: rgba(255, 255, 255, 0.58);
  color: var(--text);
}

.memory-word-hidden,
.memorisation-checker-hidden-word {
  border-color: rgba(154, 103, 56, 0.2) !important;
  background: rgba(154, 103, 56, 0.12) !important;
  color: var(--accent-strong) !important;
}

[data-theme="dark"] .memorisation-checker-modal {
  background: linear-gradient(180deg, rgba(32, 28, 25, 0.98), rgba(20, 18, 17, 0.98));
  border-color: rgba(214, 183, 132, 0.18);
}

[data-theme="dark"] .memorisation-checker-header {
  background: rgba(20, 18, 17, 0.72);
  border-bottom-color: rgba(214, 183, 132, 0.14);
}

[data-theme="dark"] .memorisation-checker-workspace,
[data-theme="dark"] .memorisation-checker-ayah-panel {
  border-color: rgba(214, 183, 132, 0.16);
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.058), rgba(255, 255, 255, 0.032));
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.055);
}

[data-theme="dark"] .memorisation-checker-section-head span {
  color: #f0d7ad;
}

[data-theme="dark"] .memorisation-checker-section-head strong {
  color: #fff7ec;
}

[data-theme="dark"] .memorisation-checker-section-head p {
  color: rgba(255, 247, 236, 0.68);
}

[data-theme="dark"] .memorisation-checker-word-stream {
  border-color: rgba(214, 183, 132, 0.14);
  background: rgba(10, 9, 8, 0.28);
}

[data-theme="dark"] .memorisation-checker-live-placeholder {
  color: rgba(255, 247, 236, 0.48);
}

[data-theme="dark"] .memorisation-checker-ayah-actions .self-check-ayah-action {
  border-color: rgba(214, 183, 132, 0.16);
  background: rgba(255, 255, 255, 0.06);
  color: #f0d7ad;
}

[data-theme="dark"] .memorisation-checker-ayah-actions .self-check-ayah-action:hover,
[data-theme="dark"] .memorisation-checker-ayah-actions .self-check-ayah-action.active {
  border-color: rgba(214, 183, 132, 0.3);
  background: rgba(214, 183, 132, 0.13);
  color: #fff7ec;
}

[data-theme="dark"] .memorisation-checker-ayah {
  border-color: rgba(214, 183, 132, 0.12);
  background: rgba(255, 255, 255, 0.035);
  color: var(--text);
}

[data-theme="dark"] .memory-word-hidden,
[data-theme="dark"] .memorisation-checker-hidden-word {
  border-color: rgba(214, 183, 132, 0.18) !important;
  background: rgba(214, 183, 132, 0.12) !important;
  color: #f0d7ad !important;
}

/* Responsive adjustments */
@media (max-width: 640px) {
  .action-buttons-group {
    gap: 6px;
  }

  .action-icon-btn {
    width: 38px;
    height: 38px;
    font-size: 1rem;
  }

  .action-btn {
    height: 38px;
    padding: 0 14px;
    font-size: 0.8rem;
  }

  .action-btn span {
    display: inline-block;
  }

  .recitation-check-panel {
    padding: 14px;
    border-radius: 16px;
  }

  .recitation-check-feedback-grid {
    grid-template-columns: 1fr;
  }

  .recitation-result-stats {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .memorisation-checker-modal {
    width: calc(100vw - 16px);
    height: calc(100dvh - 24px);
  }

  .memorisation-checker-body {
    padding: 12px;
    grid-template-rows: minmax(0, 1fr) minmax(190px, 40%);
    gap: 10px;
  }

  .memorisation-checker-workspace,
  .memorisation-checker-ayah-panel {
    border-radius: 14px;
    padding: 12px;
  }

  .memorisation-checker-ayah-actions {
    justify-content: flex-start;
    flex-wrap: wrap;
  }

  .memorisation-checker-results .recitation-result-stats {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .recording-history-ai-grid {
    grid-template-columns: 1fr;
  }
}

@media (max-width: 480px) {
  .action-btn span {
    display: none;
  }

  .action-btn {
    width: 42px;
    padding: 0;
  }

  .action-btn i {
    font-size: 1.1rem;
    margin: 0;
  }

  .recitation-result-stats {
    grid-template-columns: 1fr;
  }

  .memorisation-checker-results .recitation-result-stats {
    grid-template-columns: 1fr;
  }

  .memorisation-checker-body {
    grid-template-rows: minmax(0, 1fr) minmax(180px, 38%);
  }

  .recitation-word-chip {
    font-size: 0.98rem;
    min-height: 32px;
  }
}

/* Keyboard Shortcuts Modal - Larger & Cleaner */
.keyboard-shortcuts-modal {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0, 0, 0, 0.6);
  backdrop-filter: blur(8px);
  z-index: 1000;
  display: flex;
  align-items: center;
  justify-content: center;
  animation: modalFadeIn 0.2s ease;
}

.shortcuts-modal {
  background: var(--surface-strong);
  border-radius: 24px;
  width: min(520px, 90vw);
  max-width: 520px;
  box-shadow: 0 32px 64px rgba(0, 0, 0, 0.3);
  border: 1px solid var(--border);
  animation: modalSlideUp 0.3s cubic-bezier(0.16, 1, 0.3, 1);
  overflow: hidden;
}

.shortcuts-modal-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 20px 24px;
  background: linear-gradient(135deg, var(--surface), var(--surface-strong));
  border-bottom: 1px solid var(--border);
}

.shortcuts-modal-header h3 {
  margin: 0;
  font-size: 1.2rem;
  display: flex;
  align-items: center;
  gap: 10px;
  color: var(--text);
  font-weight: 600;
}

.shortcuts-modal-header h3 i {
  font-size: 1.3rem;
  color: var(--accent);
}

.shortcuts-modal-close {
  width: 36px;
  height: 36px;
  border-radius: 10px;
  border: 1px solid var(--border);
  background: var(--surface);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.2s;
  color: var(--text-muted);
}

.shortcuts-modal-close:hover {
  background: var(--accent-light);
  color: var(--accent);
  transform: rotate(90deg);
}

.shortcuts-modal-body {
  padding: 24px;
  max-height: none;
  overflow-y: visible;
}

.shortcuts-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 24px;
}

.shortcut-card {
  background: var(--surface);
  border-radius: 16px;
  padding: 16px;
  border: 1px solid var(--border);
}

.shortcut-card-title {
  font-size: 0.75rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  color: var(--accent);
  padding-bottom: 12px;
  margin-bottom: 12px;
  border-bottom: 2px solid var(--accent-light);
}

.shortcut-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 10px 0;
  border-bottom: 1px solid var(--border);
}

.shortcut-row:last-child {
  border-bottom: none;
}

.shortcut-keys {
  display: flex;
  gap: 6px;
  align-items: center;
  flex-wrap: wrap;
}

.shortcut-keys kbd {
  background: linear-gradient(180deg, var(--surface-strong), var(--surface));
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 4px 10px;
  font-family: 'SF Mono', 'Monaco', 'Courier New', monospace;
  font-size: 0.7rem;
  font-weight: 700;
  color: var(--accent);
  box-shadow: 0 1px 2px rgba(0, 0, 0, 0.05);
  letter-spacing: 0.5px;
}

.shortcut-row span {
  color: var(--text-muted);
  font-size: 0.85rem;
  font-weight: 500;
}

@keyframes modalFadeIn {
  from {
    opacity: 0;
  }

  to {
    opacity: 1;
  }
}

@keyframes modalSlideUp {
  from {
    opacity: 0;
    transform: translateY(30px) scale(0.95);
  }

  to {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}

/* Responsive */
@media (max-width: 640px) {
  .action-buttons-group {
    width: 100%;
    gap: 8px;
  }

  .action-icon {
    min-width: 44px;
    height: 40px;
  }

  .action-btn {
    min-width: 0;
    flex: 1;
    padding: 0 12px;
    height: 40px;
    font-size: 0.8rem;
  }

  .action-btn span {
    display: inline;
  }

  .shortcuts-modal {
    width: 95vw;

    margin: 16px;
  }

  .shortcuts-modal-header {
    padding: 16px 20px;
  }

  .shortcuts-modal-header h3 {
    font-size: 1rem;
  }

  .shortcuts-modal-body {
    padding: 16px;
  }

  .shortcuts-grid {
    grid-template-columns: 1fr;
    gap: 16px;
  }

  .shortcut-card {
    padding: 12px;
  }

  .shortcut-row {
    padding: 8px 0;
  }

  .shortcut-keys kbd {
    padding: 3px 8px;
    font-size: 0.65rem;
  }

  .shortcut-row span {
    font-size: 0.8rem;
  }
}

@media (max-width: 480px) {
  .action-btn span {
    display: none;
  }

  .action-btn {
    min-width: 44px;
    padding: 0;
  }

  .action-btn i {
    font-size: 1.1rem;
    margin: 0;
  }
}

/* Keyboard Shortcuts Dropdown - Compact */

.shortcuts-panel.compact {
  background: var(--surface-strong);
  border-radius: 14px;
  width: 280px;
  box-shadow: var(--shadow-lg);
  border: 1px solid var(--border);
  animation: slideUp 0.2s ease;
  overflow: hidden;
}

.shortcuts-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 10px 14px;
  border-bottom: 1px solid var(--border);
  background: var(--surface);
}

.shortcuts-header h3 {
  margin: 0;
  font-size: 0.85rem;
  display: flex;
  align-items: center;
  gap: 6px;
  color: var(--text);
}

.shortcuts-header h3 i {
  font-size: 0.9rem;
}

.shortcuts-close {
  width: 26px;
  height: 26px;
  border-radius: 6px;
  border: 1px solid var(--border);
  background: var(--surface);
  cursor: pointer;
  font-size: 18px;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.15s;
  color: var(--text-muted);
}

.shortcuts-close:hover {
  background: var(--accent-light);
  color: var(--accent);
}

.shortcuts-list {
  padding: 8px 6px;
  max-height: 400px;
  overflow-y: auto;
}

.shortcut-item {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 6px 10px;
  border-radius: 6px;
  font-size: 0.75rem;
}

.shortcut-item:hover {
  background: var(--accent-light);
}

.shortcut-item kbd {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 4px;
  padding: 2px 6px;
  font-family: monospace;
  font-size: 0.7rem;
  font-weight: 600;
  color: var(--accent);
  box-shadow: 0 1px 0 var(--border);
}

.shortcut-item span {
  color: var(--text-muted);
  font-size: 0.75rem;
}

@keyframes fadeIn {
  from {
    opacity: 0;
  }

  to {
    opacity: 1;
  }
}

@keyframes slideUp {
  from {
    opacity: 0;
    transform: translateY(10px);
  }

  to {
    opacity: 1;
    transform: translateY(0);
  }
}

/* Saved Sessions Styles */
.saved-sessions-list {
  display: flex;
  flex-direction: column;
  gap: 10px;
  max-height: none;
  overflow-y: auto;
}

.saved-session-item {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 12px;
  padding: 10px 12px;
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 10px;
  transition: all 0.2s ease;
}

.saved-session-item:hover {
  border-color: var(--accent);
  background: var(--surface-strong);
}

.session-info {
  flex: 1;
  min-width: 0;
}

.session-name {
  font-weight: 600;
  font-size: 0.85rem;
  color: var(--text);
  margin-bottom: 4px;
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 8px;
}

.session-meta {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.session-meta span {
  display: inline-flex;
  align-items: center;
  gap: 3px;
  font-size: 0.65rem;
  color: var(--text-muted);
}

.session-actions {
  display: flex;
  gap: 10px;
  align-items: center;
  justify-content: space-between;
  width: 100%;
  margin-top: 10px;
}

.session-export-btn {
  min-height: 32px;
  padding: 0 11px;
  border-radius: 8px;
  border: 1px solid var(--border);
  background: rgba(255, 255, 255, 0.78);
  color: var(--text);
  cursor: pointer;
  transition: all 0.2s ease;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  font-size: 0.68rem;
  font-weight: 650;
  white-space: nowrap;
}

.session-export-btn:hover:not(:disabled) {
  border-color: var(--accent);
  color: var(--accent-strong);
  background: var(--accent-light);
}

.session-export-btn:disabled {
  opacity: 0.7;
  cursor: wait;
}

.spin {
  animation: spin360 0.9s linear infinite;
}

@keyframes spin360 {
  from {
    transform: rotate(0deg);
  }

  to {
    transform: rotate(360deg);
  }
}

.export-error-card {
  margin-top: 12px;
  padding: 12px 14px;
  border-radius: 12px;
  border: 1px solid rgba(220, 53, 69, 0.18);
  background: rgba(220, 53, 69, 0.06);
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
}

.export-error-card strong {
  display: block;
  font-size: 0.78rem;
  color: var(--text);
}

.export-error-card p {
  margin: 4px 0 0;
  font-size: 0.7rem;
  color: var(--text-muted);
}

.stats-sessions-container {
  display: grid;
  gap: 12px;
  padding: 12px;
  border-radius: 16px;
  border: 1px solid var(--border);
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.78), rgba(255, 248, 242, 0.62));
  box-shadow: var(--shadow-sm);
}

.stats-panel {
  display: grid;
  gap: 12px;
}

.stats-session-picker,
.stats-detail-footer {
  display: flex;
  flex-wrap: wrap;
  gap: 8px 12px;
}

.stats-session-pill {
  min-width: 0;
  padding: 8px 12px;
  border-radius: 14px;
  border: 1px solid var(--border);
  background: rgba(255, 255, 255, 0.72);
  cursor: pointer;
  transition: all 0.2s ease;
  display: grid;
  gap: 3px;
  text-align: left;
}

.stats-session-pill strong,
.stats-detail-head h4 {
  font-size: 0.84rem;
  color: var(--text);
}

.stats-session-pill span,
.stats-detail-head p,
.stats-detail-footer {
  font-size: 0.68rem;
  color: var(--text-muted);
}

.stats-summary {
  margin-top: 10px;
  padding: 8px 12px;
  border-radius: 12px;
  border: 1px solid var(--border);
  background: rgba(255, 252, 246, 0.55);
  font-size: 0.78rem;
  line-height: 1.32;
  color: var(--text);
}

.stats-session-pill:hover,
.stats-session-pill.active {
  border-color: var(--accent);
  background: var(--accent-light);
}

.stats-detail {
  padding: 12px;
  border-radius: 16px;
  border: 1px solid var(--border);
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.82), rgba(255, 248, 242, 0.72));
  box-shadow: var(--shadow-sm);
}

.stats-session-select-wrap {
  margin-top: 10px;
  display: grid;
  gap: 6px;
  max-width: 420px;
}

.stats-session-select-label {
  font-size: 0.7rem;
  font-weight: 650;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  color: var(--text-muted);
  opacity: 0.9;
}

.stats-session-select {
  width: 100%;
  min-height: 42px;
  padding: 0 14px;
  border-radius: 12px;
  border: 1px solid var(--border);
  background: rgba(255, 255, 255, 0.72);
  color: var(--text);
  font-size: 0.82rem;
  font-weight: 600;
}

[data-theme="dark"] .stats-session-select {
  background: rgba(255, 247, 236, 0.08);
  border-color: rgba(255, 236, 216, 0.14);
  color: var(--text);
}

[data-theme="dark"] .stats-summary {
  background: rgba(255, 247, 236, 0.04);
  border-color: rgba(255, 236, 216, 0.12);
}

.session-export-group {
  display: flex;
  flex-wrap: wrap;
  justify-content: flex-start;
  gap: 6px;
}

.saved-continue-banner {
  margin-bottom: 16px;
  padding: 14px;
  border-radius: 16px;
  border: 1px solid rgba(154, 103, 56, 0.16);
  background: rgba(255, 248, 239, 0.04);
  display: grid;
  gap: 12px;
}

.saved-continue-copy {
  display: grid;
  gap: 4px;
}

.saved-continue-kicker {
  font-size: 0.72rem;
  font-weight: 700;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  color: var(--text-muted);
}

.saved-continue-copy strong {
  font-size: 0.88rem;
  color: var(--text);
}

.saved-continue-copy small {
  font-size: 0.76rem;
  color: var(--text-muted);
  line-height: 1.45;
}

.saved-continue-actions {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto;
  gap: 10px;
}

.slider-markers-compact span {
  min-width: 0;
}

.session-item {
  align-items: stretch;
  gap: 14px;
}

.session-item-active {
  border-color: rgba(154, 103, 56, 0.28);
  box-shadow: 0 12px 26px rgba(122, 83, 46, 0.12);
}

.session-item .session-info,
.session-item .session-actions {
  position: relative;
  z-index: 1;
}

.session-live-badge {
  display: inline-flex;
  align-items: center;
  min-height: 22px;
  padding: 0 8px;
  border-radius: 999px;
  background: rgba(79, 157, 138, 0.14);
  color: #4f9d8a;
  font-size: 0.66rem;
  font-weight: 700;
}

.session-status-badge {
  display: inline-flex;
  align-items: center;
  min-height: 22px;
  padding: 0 8px;
  border-radius: 999px;
  font-size: 0.66rem;
  font-weight: 700;
  border: 1px solid transparent;
}

.session-status-active {
  background: rgba(79, 157, 138, 0.16);
  color: #4f9d8a;
}

.session-status-paused,
.session-status-idle {
  background: rgba(154, 103, 56, 0.1);
  color: var(--accent-strong);
  border-color: rgba(154, 103, 56, 0.14);
}

.session-status-loading {
  background: rgba(86, 124, 184, 0.14);
  color: #6e95d2;
}

.session-status-muted {
  background: rgba(255, 255, 255, 0.06);
  color: var(--text-muted);
  border-color: var(--border);
}

.session-details {
  display: flex;
  flex-wrap: wrap;
  gap: 6px 10px;
  font-size: 0.76rem;
}

.session-details span {
  display: inline-flex;
  align-items: center;
  gap: 5px;
}

.session-primary-action {
  display: grid;
  flex: 0 0 66.6667%;
  max-width: 66.6667%;
}

.saved-sessions-container .session-actions {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  width: 100%;
  margin-top: 8px;
  padding-top: 8px;
  border-top: 1px solid rgba(255, 255, 255, 0.06);
}

.session-secondary-actions {
  display: flex;
  justify-content: flex-end;
  gap: 8px;
  align-items: center;
  flex: 0 0 33.3333%;
  max-width: 33.3333%;
}

.session-resume-btn,
.session-delete-btn {
  border-radius: 10px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  font-size: 0.72rem;
  font-weight: 700;
  padding: 8px 11px;
  line-height: 1.1;
}

.session-resume-btn {
  border: 1px solid rgba(154, 103, 56, 0.16);
  background: linear-gradient(135deg, var(--accent), var(--accent-strong));
  color: #fff;
  padding: 9px 12px;
  box-shadow: 0 10px 22px rgba(154, 103, 56, 0.18);
}

.session-delete-btn {
  border: 1px solid rgba(168, 87, 68, 0.2);
  color: #a85744;
  background: rgba(255, 246, 243, 0.86);
  padding: 8px 10px;
  min-width: 0;
  width: auto;
  height: auto;
  margin-right: 0;
  flex-shrink: 0;
  width: 100%;
}

.session-delete-btn-quiet {
  min-width: 112px;
}

.session-export-btn.success {
  border-color: rgba(79, 157, 138, 0.3);
  background: rgba(79, 157, 138, 0.12);
  color: #2d7f6e;
}

.session-export-group {
  display: flex;
  flex-wrap: wrap;
  gap: 10px 12px;
}

.saved-sessions-container .session-export-btn {
  min-height: 0;
  height: auto;
}

.session-export-btn {
  width: auto;
  justify-content: center;
  padding: 10px 12px;
  border-radius: 12px;
  font-size: 0.76rem;
  font-weight: 700;
  background: rgba(255, 255, 255, 0.06);
  line-height: 1.1;
}

.analytics-bar-list {
  display: grid;
  gap: 10px;
}

.analytics-bar-row {
  display: grid;
  grid-template-columns: minmax(0, 72px) minmax(0, 1fr) 34px;
  gap: 10px;
  align-items: center;
}

.analytics-bar-row span,
.analytics-bar-row strong {
  font-size: 0.76rem;
  color: var(--text);
}

.analytics-bar-row strong {
  text-align: right;
  color: var(--text-muted);
}

.analytics-bar-track {
  height: 10px;
  border-radius: 999px;
  background: rgba(154, 103, 56, 0.1);
  overflow: hidden;
}

.analytics-bar-fill {
  height: 100%;
  border-radius: inherit;
  background: linear-gradient(90deg, #d8ac6b, #8d5a34);
}

.analytics-bucket-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 10px;
}

.analytics-bucket-card {
  display: grid;
  gap: 4px;
  padding: 12px;
  border-radius: 14px;
  border: 1px solid var(--border);
  background: rgba(255, 255, 255, 0.05);
}

.analytics-bucket-card span {
  font-size: 0.72rem;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.04em;
}

.analytics-bucket-card strong {
  font-size: 1.2rem;
  color: var(--text);
}

.analytics-bucket-card small {
  font-size: 0.74rem;
  line-height: 1.4;
  color: var(--text-muted);
}

.session-export-btn-pdf {
  border-color: rgba(196, 148, 72, 0.18);
}

.session-export-btn-word {
  border-color: rgba(120, 149, 196, 0.2);
}

.session-export-btn-csv {
  border-color: rgba(124, 170, 148, 0.18);
}

.post-onboarding-step-label {
  margin-bottom: 10px;
  font-size: 0.78rem;
  font-weight: 700;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  color: #8fc5b5;
}

.dua-onboarding-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 12px;
  margin-top: 14px;
}

.dua-onboarding-card {
  padding: 14px;
  border-radius: 14px;
  border: 1px solid rgba(104, 160, 143, 0.16);
  background: rgba(255, 255, 255, 0.04);
  display: grid;
  gap: 8px;
}

.dua-onboarding-title {
  font-size: 0.78rem;
  font-weight: 700;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  color: #97c9ba;
}

.dua-onboarding-arabic {
  margin: 0;
  font-size: 1.08rem;
  line-height: 1.85;
  color: #f1f7f4;
}

.dua-onboarding-translation {
  margin: 0;
  font-size: 0.88rem;
  line-height: 1.55;
  color: #d3ddd9;
}

.dua-onboarding-source {
  color: #9cb6af;
  font-size: 0.74rem;
}

.session-actions {
  display: grid;
  grid-template-columns: minmax(0, 1fr);
  gap: 10px;
  width: 100%;
  margin-top: 14px;
  padding-top: 14px;
  border-top: 1px solid rgba(255, 255, 255, 0.06);
}

.stats-detail-head {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 12px;
  margin-bottom: 12px;
}

.stats-detail-head-hero {
  margin-bottom: 12px;
}

.stats-detail-head h4 {
  margin: 0 0 4px;
  font-size: 0.98rem;
}

.stats-detail-head p {
  margin: 0;
}

.stats-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 12px;
}

.stats-grid-hero {
  gap: 12px;
}

@media (max-width: 520px) {
  .stats-grid {
    grid-template-columns: 1fr;
  }

  .stats-detail-head {
    flex-direction: column;
    align-items: stretch;
  }

  .session-export-group {
    justify-content: flex-start;
    flex-wrap: wrap;
  }

  .dua-onboarding-grid {
    grid-template-columns: 1fr;
  }
}

@media (max-width: 768px) {
  .session-item {
    flex-direction: column;
    align-items: stretch;
    gap: 12px;
  }

  .saved-sessions-container .session-actions {
    width: 100%;
    align-items: center;
    flex-wrap: nowrap;
  }

  .session-export-group {
    width: 100%;
  }

  .session-secondary-actions {
    flex: 0 0 33.3333%;
    max-width: 33.3333%;
  }

  .session-primary-action {
    flex: 0 0 66.6667%;
    max-width: 66.6667%;
  }

  .session-delete-btn {
    width: 100%;
  }

  .saved-continue-actions {
    grid-template-columns: 1fr;
  }
}

@media (max-width: 640px) {
  .action-buttons-group {
    flex-wrap: wrap;
    align-items: stretch;
  }

  .action-btn-primary,
  .action-btn-secondary,
  .action-btn-exit {
    flex: 1 1 calc(50% - 8px);
  }

  .workspace-shell-icon-actions {
    width: 100%;
    justify-content: flex-end;
  }
}

.stats-card {
  padding: 14px 12px;
  border-radius: 16px;
  border: 1px solid var(--border);
  background: rgba(255, 252, 246, 0.82);
  display: grid;
  justify-items: center;
  align-content: center;
  gap: 8px;
  text-align: center;
  min-height: 132px;
}

.stats-card-icon {
  font-size: 1.55rem;
  color: var(--accent);
}

.stats-card span {
  font-size: 0.74rem;
  color: var(--text-muted);
  line-height: 1.3;
}

.stats-card-value {
  font-style: normal;
  font-size: 1.6rem;
  font-weight: 600;
  color: var(--text);
  line-height: 1;
}

.stats-detail-footer {
  margin-top: 10px;
  padding-top: 10px;
  border-top: 1px solid var(--border);
}

.stats-detail-actions-prominent {
  margin: 4px 0 2px;
}

.stats-full-analytics-btn {
  width: 100%;
  min-height: 46px;
  border-radius: 12px;
  font-size: 0.82rem;
  color: #fff;
  border-color: transparent;
  background: linear-gradient(135deg, var(--accent), var(--accent-strong));
  box-shadow: 0 12px 28px rgba(0, 0, 0, 0.18);
}

.session-load-btn,
.session-delete-btn-icon {
  width: 32px;
  height: 32px;
  border-radius: 8px;
  border: 1px solid var(--border);
  background: var(--surface);
  cursor: pointer;
  transition: all 0.2s ease;
  display: flex;
  align-items: center;
  justify-content: center;
}

.session-load-btn {
  background: var(--accent);
  color: white;
  border-color: transparent;
}

.session-load-btn:hover {
  background: var(--accent-strong);
  transform: scale(1.05);
}

.session-delete-btn {
  background: rgba(220, 53, 69, 0.1);
  color: #dc3545;
}

.session-delete-btn:hover {
  background: #dc3545;
  color: white;
}

.save-current-session {
  margin-top: 12px;
  padding-top: 12px;
  border-top: 1px solid var(--border);
}

.save-session-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
}

.save-session-info {
  flex: 1;
}

.save-session-info strong {
  display: block;
  font-size: 0.8rem;
  color: var(--text);
  margin-bottom: 2px;
}

.save-session-info small {
  font-size: 0.65rem;
  color: var(--text-muted);
}

.session-archive-badge {
  display: inline-flex;
  align-items: center;
  min-height: 22px;
  padding: 0 8px;
  border-radius: 999px;
  background: rgba(154, 103, 56, 0.08);
  border: 1px solid rgba(154, 103, 56, 0.12);
  color: var(--accent-strong);
  font-size: 0.64rem;
  font-weight: 700;
}

.save-session-btn {
  padding: 6px 14px;
  border-radius: 8px;
  background: var(--accent);
  color: white;
  border: none;
  cursor: pointer;
  font-size: 0.75rem;
  font-weight: 500;
  display: inline-flex;
  align-items: center;
  gap: 5px;
  transition: all 0.2s ease;
}

.save-session-btn:hover {
  background: var(--accent-strong);
  transform: translateY(-1px);
}

.verse-download-btn {
  width: 30px;
  height: 30px;
  border-radius: 50%;
  background: rgba(255, 255, 255, 0.82);
  border: 1px solid var(--border);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.2s ease;
  color: var(--accent);
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
}

.verse-download-btn:hover:not(:disabled) {
  transform: scale(1.05);
  border-color: var(--accent);
  background: rgba(255, 255, 255, 0.96);
}

.verse-download-btn:disabled {
  opacity: 0.45;
  cursor: not-allowed;
}

/* Add to your style section */
.main.tools-open {
  overflow-x: clip;
}

/* Fix tools panel positioning - ensure it goes from very top */
.tools {
  position: fixed;
  top: 0;
  /* Changed from auto/padding */
  right: 0;
  bottom: 0;
  height: 100dvh;
  width: min(var(--tools-width), 92vw);
  background: linear-gradient(180deg, rgba(255, 250, 243, 0.96), rgba(247, 240, 231, 0.92));
  border-left: 1px solid var(--border);
  backdrop-filter: blur(14px);
  transform: translateX(100%);
  transition: transform 0.25s ease, visibility 0.25s ease;
  z-index: 1100;
  display: flex;
  flex-direction: column;
  overflow-x: hidden;
  box-shadow: var(--shadow-lg);
  isolation: isolate;
  visibility: hidden;
  pointer-events: none;
  overscroll-behavior: contain;
}

/* Adjust tools-top padding to account for no navbar offset */
.tools-top {
  padding: 18px 18px 12px;
  border-bottom: 1px solid var(--border);
  padding-top: calc(18px + env(safe-area-inset-top, 0px));
}

/* Ensure tools body scrolls correctly */
.tools-body {
  flex: 1;
  min-height: 0;
  overflow-y: auto;
  overflow-x: hidden;
  padding: 20px 20px calc(var(--tools-footer-h) + 26px);
  overscroll-behavior: contain;
  -webkit-overflow-scrolling: touch;
}

body.has-navbar .tools {
  top: 0;
}

body.has-navbar .tools-top {
  padding-top: calc(18px + env(safe-area-inset-top, 0px));
}

.tools.open {
  transform: translateX(0);
  visibility: visible;
  pointer-events: auto;
}

.tools-backdrop {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.5);
  z-index: 1099;
  opacity: 0;
  pointer-events: none;
  transition: opacity 0.2s ease;
}

.tools-backdrop.open {
  opacity: 1;
  pointer-events: auto;
}

/* Replace the existing blur mode CSS with this */
.main.blur-mode-active .verse-card.blur-upcoming .verse-arabic,
.main.blur-mode-active .verse-card.blur-upcoming .verse-aid {
  filter: blur(var(--recall-blur, 10px));
  opacity: 0.7;
  transition: filter 0.3s ease, opacity 0.3s ease;
}

.main.blur-mode-active .verse-card.blur-upcoming .verse-arabic .tajweed-mark,
.main.blur-mode-active .verse-card.blur-upcoming .verse-arabic word,
.main.blur-mode-active .verse-card.blur-upcoming .verse-arabic .wbw-word {
  filter: blur(var(--recall-blur, 10px));
}

/* Keep active verse clear */
.main.blur-mode-active .verse-card.active .verse-arabic,
.main.blur-mode-active .verse-card.active .verse-aid {
  filter: none;
  opacity: 1;
}

.main.blur-mode-active .verse-card.blur-upcoming.peek-revealed .verse-arabic,
.main.blur-mode-active .verse-card.blur-upcoming.peek-revealed .verse-aid,
.main.blur-mode-active .verse-card.blur-upcoming.peek-revealed .verse-arabic .tajweed-mark,
.main.blur-mode-active .verse-card.blur-upcoming.peek-revealed .verse-arabic word,
.main.blur-mode-active .verse-card.blur-upcoming.peek-revealed .verse-arabic .wbw-word {
  filter: none !important;
  opacity: 1;
}

/* Force tajweed spans to display properly */
.verse-arabic.tajweed-enabled span[class*="tajweed-"] {
  display: inline !important;
}

/* Ensure proper line height for tajweed text */
.verse-arabic.tajweed-enabled {
  line-height: 2.2 !important;
  font-family: var(--font-ar);
}

/* Make tajweed colors visible */
.verse-arabic.tajweed-enabled .tajweed-ham_wasl,
.verse-arabic.tajweed-enabled .tajweed-slnt {
  color: #7e8a97;
}

.verse-arabic.tajweed-enabled .tajweed-ghn,
.verse-arabic.tajweed-enabled .tajweed-idgh_ghn,
.verse-arabic.tajweed-enabled .tajweed-iqlb {
  color: #2e9d62;
  background: rgba(46, 157, 98, 0.10);
}

.verse-arabic.tajweed-enabled .tajweed-idgh_w_ghn,
.verse-arabic.tajweed-enabled .tajweed-ikhf,
.verse-arabic.tajweed-enabled .tajweed-ikhf_shfw {
  color: #9b59b6;
  background: rgba(155, 89, 182, 0.10);
}

.verse-arabic {
  /* Force Arabic ayah text to be comfortably large by default. */
  --verse-font-percent: 120;
  --verse-font-size: clamp(2.2rem, calc(var(--verse-font-percent, 120) * 0.02rem), 4rem);
  font-family: var(--font-ar);
  /* `--text-scale` is controlled by the text size slider; apply it to Arabic too. */
  font-size: calc(var(--verse-font-size) * var(--ui-scale, 1) * var(--text-scale, 1));
  line-height: 2.1;
  text-align: right;
  direction: rtl;
  unicode-bidi: isolate;
  background: var(--bg-elevated);
  padding: 20px;
  border-radius: 16px;
  margin: 12px 0;
  display: block;
  overflow-wrap: anywhere;
  word-break: normal;
}

/* Force re-render when font changes */
.verse-arabic.tajweed-enabled,
.verse-arabic:not(.tajweed-enabled) {
  transition: font-size 0.1s ease;
}

@keyframes wordHighlightPulse {
  0% {
    transform: scale(1);
  }

  50% {
    transform: scale(1.03);
  }

  100% {
    transform: scale(1.02);
  }
}

/* Combined Tajweed + Word Highlighting */
.verse-arabic.tajweed-enabled.word-highlight-enabled .wbw-word {
  display: inline-block;
  transition: all 0.15s ease;
  border-radius: 4px;
  padding: 0 2px;
  cursor: pointer;
}

.verse-arabic.tajweed-enabled.word-highlight-enabled .wbw-word.highlighted {
  background: var(--accent);
  color: white;
  transform: scale(1.02);
  box-shadow: 0 2px 8px rgba(154, 103, 56, 0.3);
}

.verse-arabic.tajweed-enabled.word-highlight-enabled .wbw-word:hover {
  background: var(--accent-light);
  cursor: pointer;
}

/* Preserve tajweed colors inside highlighted words but make them visible */
.verse-arabic.tajweed-enabled.word-highlight-enabled .wbw-word.highlighted .tajweed-mark {
  color: inherit !important;
  background: transparent !important;
}

.verse-arabic.tajweed-enabled.word-highlight-enabled .wbw-word.highlighted [class*="tajweed-"] {
  color: white !important;
  background: transparent !important;
}

/* Mode Button Styling */
.mode-btn {
  background: var(--surface);
  border: 1px solid var(--accent);
  color: var(--accent);
  display: flex;
  align-items: center;
  gap: 6px;
}

.mode-btn i:first-child {
  font-size: 0.85rem;
}

.mode-btn .bi-chevron-down {
  font-size: 0.7rem;
  transition: transform 0.2s;
}

.mode-btn:hover .bi-chevron-down {
  transform: translateY(2px);
}

.mode-btn:hover {
  background: var(--accent-light);
}

/* Make all buttons consistent */
.session-rail-actions {
  display: flex;
  gap: 10px;
  flex-wrap: wrap;
}

.rail-btn {
  padding: 8px 16px;
  border-radius: 12px;
  font-size: 0.8rem;
  font-weight: 500;
  cursor: pointer;
  transition: all 0.2s;
  display: flex;
  align-items: center;
  gap: 6px;
  border: none;
}

.rail-btn-ghost {
  background: var(--accent-light);
  color: var(--accent);
}

.rail-btn-ghost:hover {
  background: var(--accent);
  color: white;
}

.rail-btn:disabled,
.rail-btn-ghost:disabled,
.rail-btn-primary:disabled {
  opacity: 0.45;
  cursor: not-allowed;
  pointer-events: none;
  transform: none;
  box-shadow: none;
}

.rail-btn-resume {
  background: rgba(255, 255, 255, 0.92);
  color: var(--accent);
  border: 1px solid var(--accent-soft);
}

.rail-btn-resume:hover {
  background: var(--accent-light);
  transform: translateY(-1px);
}

.rail-btn-primary {
  background: var(--accent);
  color: white;
  box-shadow: 0 2px 8px rgba(154, 103, 56, 0.2);
}

.rail-btn-primary:hover {
  background: var(--accent-strong);
  transform: translateY(-1px);
}

body {
  font-family: var(--font-ui);
  background: var(--bg);
  color: var(--text);
}

html {
  background: var(--bg);
}

.app {
  min-height: 100dvh;
  font-size: calc(16px * var(--ui-scale, 1));
  animation: appFade 260ms ease-out;
  overflow-x: clip;
}

.verse-arabic {
  min-height: 60px;
}

/* Session Rail */
.session-rail {
  background: var(--surface);
  border-radius: 20px;
  margin-bottom: 20px;
  padding: 12px 16px 14px;
  border: 1px solid var(--border);
  box-shadow: var(--shadow-sm);
}

.session-rail-top {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 10px;
  flex-wrap: wrap;
  gap: 12px;
}

.session-rail-copy {
  flex: 1;
  min-width: 0;
}

.session-rail-headline {
  display: flex;
  align-items: baseline;
  gap: 10px;
  flex-wrap: wrap;
}

.session-rail-pills {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  margin-top: 6px;
}

.session-pill {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 5px 9px;
  border-radius: 999px;
  background: rgba(255, 255, 255, 0.72);
  border: 1px solid var(--border);
  color: var(--text-muted);
  font-size: 0.71rem;
  white-space: nowrap;
}

.session-pill strong {
  color: var(--text);
  font-weight: 700;
}

.session-pill-focus {
  max-width: min(280px, 100%);
}

.session-pill-focus strong {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.session-rail-kicker {
  font-size: 0.7rem;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  color: var(--text-muted);
}

.session-rail-title {
  font-size: 1rem;
  font-weight: 600;
  color: var(--text);
}

.session-rail-meta {
  font-size: 0.72rem;
  color: var(--text-muted);
  margin-top: 2px;
}

.session-rail-actions {
  display: flex;
  gap: 10px;
}

.rail-btn {
  padding: 8px 16px;
  border-radius: 12px;
  font-size: 0.8rem;
  font-weight: 500;
  cursor: pointer;
  transition: all 0.2s;
  display: flex;
  align-items: center;
  gap: 6px;
  border: none;
}

.rail-btn-ghost {
  background: var(--accent-light);
  color: var(--accent);
}

.rail-btn-ghost:hover {
  background: var(--accent);
  color: white;
}

.rail-btn-primary {
  background: var(--accent);
  color: white;
  box-shadow: 0 2px 8px rgba(154, 103, 56, 0.2);
}

.rail-btn-primary:hover {
  background: var(--accent-strong);
  transform: translateY(-1px);
}

.session-rail-subnote {
  margin-top: 10px;
  font-size: 0.72rem;
  color: var(--text-muted);
}

/* Mode Indicator */
.mode-indicator {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  padding: 6px 14px;
  margin: 8px 0 12px 0;
  background: var(--accent-light);
  border-radius: 40px;
  font-size: 0.7rem;
  color: var(--accent);
  border: 1px solid var(--accent-soft);
  width: fit-content;
}

.mode-switch-btn {
  background: transparent;
  border: none;
  cursor: pointer;
  color: var(--accent);
  padding: 4px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.2s;
}

.mode-switch-btn:hover {
  background: rgba(154, 103, 56, 0.2);
  transform: rotate(180deg);
}

.progress-bar-wide {
  margin-top: 10px;
  height: 6px;
  position: relative;
  overflow: visible;
}

.progress-label {
  position: absolute;
  top: -24px;
  right: 0;
  font-size: 0.72rem;
  font-weight: 700;
  color: var(--accent);
}

/* Responsive */
@media (max-width: 640px) {
  .session-rail-top {
    flex-direction: column;
    align-items: stretch;
  }

  .session-rail-actions {
    justify-content: stretch;
    width: 100%;
    flex-wrap: wrap;
  }

  .rail-btn {
    flex: 1;
    justify-content: center;
  }
}

.verse-arabic-loading {
  min-height: 60px;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--text-muted);
  animation: pulse 1s infinite;
}

@keyframes pulse {

  0%,
  100% {
    opacity: 0.3;
  }

  50% {
    opacity: 0.6;
  }
}

/* Ensure HTML content is styled properly before Vue mounts */
.verse-arabic word,
.verse-arabic .wbw-word {
  display: inline-block;
  transition: all 0.15s ease;
  vertical-align: baseline;
  white-space: nowrap;
}

/* Prevent raw HTML showing */
.verse-arabic:empty {
  display: none;
}

/* Tajweed styles */
.verse-arabic.tajweed-enabled [class*="tajweed"] {
  display: inline;
}

/* Color rules for tajweed - adjust based on what API returns */
.verse-arabic [class*="ghunnah"],
.verse-arabic [class*="Ghunnah"] {
  color: #2ecc71;
}

.verse-arabic [class*="madd"],
.verse-arabic [class*="Madd"] {
  color: #e74c3c;
}

.verse-arabic [class*="qalqalah"],
.verse-arabic [class*="Qalqalah"] {
  color: #f39c12;
}

.verse-arabic [class*="ikhfa"],
.verse-arabic [class*="Ikhfa"] {
  color: #9b59b6;
}

.verse-arabic [class*="idgham"],
.verse-arabic [class*="Idgham"] {
  color: #3498db;
}

/* Word by Word styles */
.wbw-word {
  display: inline-block;
  padding: 5px 8px;
  margin: 2px 3px;
  border-radius: 8px;
  transition: all 0.2s ease;
  cursor: pointer;
  font-size: 1.05rem;
  background: rgba(154, 103, 56, 0.05);
}

.verse-arabic .wbw-word,
.verse-arabic word {
  display: inline;
  padding: 0;
  margin: 0;
  font-size: inherit;
  line-height: inherit;
  background: transparent;
  border-radius: 0;
}

.wbw-word:hover {
  background: var(--accent-light);
  transform: scale(1.02);
}

.wbw-word.highlighted {
  background: var(--accent);
  color: white;
  transform: scale(1.05);
  box-shadow: 0 2px 8px rgba(154, 103, 56, 0.3);
  animation: pop 180ms ease-out;
}

.verse-arabic.verse-weak .wbw-word.weak-word {
  background: #fff3bf;
  color: #5f4b00;
}

.verse-arabic.verse-mastered .wbw-word.mastered-word {
  background: #d3f9d8;
  color: #1f6f31;
}

@keyframes pop {
  from {
    transform: scale(1.01);
  }

  to {
    transform: scale(1.05);
  }
}

/* Word highlighting styles */
.verse-arabic word {
  display: inline-block;
  transition: all 0.15s ease;
  border-radius: 4px;
  padding: 0 2px;
  cursor: pointer;
}

.verse-arabic word.highlighted {
  background: var(--accent);
  color: white;
  transform: scale(1.02);
  box-shadow: 0 2px 8px rgba(154, 103, 56, 0.3);
}

.verse-arabic word:hover {
  background: var(--accent-light);
  cursor: pointer;
}

.rail-stat strong,
.player-eta {
  cursor: help;
  border-bottom: 1px dotted var(--text-muted);
}

/* Optional: Show detailed breakdown on hover */
.rail-stat:hover strong::after {
  content: attr(title);
  position: absolute;
  bottom: 100%;
  left: 50%;
  transform: translateX(-50%);
  background: var(--surface-strong);
  color: var(--text);
  padding: 4px 8px;
  border-radius: 8px;
  font-size: 0.7rem;
  white-space: nowrap;
  z-index: 100;
  box-shadow: var(--shadow-sm);
  border: 1px solid var(--border);
}

/* Minimized Session Rail */
.session-rail-mini {
  position: sticky;
  top: 12px;
  z-index: 18;
  padding: 10px;
  padding-top: 8px;
  margin-bottom: 20px;
  background: var(--surface);
  border-radius: 12px;
  border: 1px solid var(--border);
  backdrop-filter: blur(12px);
  box-shadow: var(--shadow-sm);
  overflow: hidden;
  transition: all 0.2s ease;
}

.session-rail-mini:hover {
  box-shadow: var(--shadow-md);
  border-color: var(--accent-soft);
}

.rail-mini-content {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
  padding: 8px 12px 8px 16px;
}

.rail-mini-info {
  display: flex;
  align-items: center;
  gap: 12px;
  flex: 1;
}

.rail-mini-icon {
  width: 32px;
  height: 32px;
  background: var(--accent-light);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
}

.rail-mini-icon i {
  font-size: 0.9rem;
  color: var(--accent);
}

.rail-mini-details {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.rail-mini-surah {
  font-size: 0.8rem;
  font-weight: 600;
  color: var(--text);
}

.rail-mini-progress {
  font-size: 0.65rem;
  color: var(--text-muted);
}

.rail-mini-stats {
  display: flex;
  align-items: center;
  gap: 12px;
}

.mini-stat-item {
  display: flex;
  align-items: center;
  gap: 4px;
  font-size: 0.7rem;
  color: var(--text-muted);
}

.mini-stat-item i {
  font-size: 0.7rem;
  color: var(--accent);
}

.rail-mini-actions {
  display: flex;
  align-items: center;
  gap: 6px;
}

.mini-btn {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  background: transparent;
  border: 1px solid var(--border);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.2s ease;
  color: var(--text-muted);
}

.mini-btn:hover {
  background: var(--accent-light);
  border-color: var(--accent);
  color: var(--accent);
}

.mini-btn:first-child {
  background: var(--accent);
  border-color: var(--accent);
  color: white;
}

.mini-btn:first-child:hover {
  transform: scale(1.05);
  background: var(--accent-strong);
}

.rail-mini-progress {
  height: 2px;
  background: var(--border);
}

.progress-fill-mini {
  height: 100%;
  background: var(--accent);
  transition: width 0.3s ease;
}

/* Responsive */
@media (max-width: 640px) {
  .rail-mini-stats {
    display: none;
  }

  .rail-mini-content {
    padding: 6px 10px 6px 12px;
  }

  .rail-mini-surah {
    font-size: 0.75rem;
  }
}

/* Font Dropdown */
.font-dropdown {
  position: relative;
}

.font-dropdown-trigger {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 12px;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 999px;
  font-size: 0.75rem;
  cursor: pointer;
  transition: all 0.2s;
  color: var(--text);
}

.font-dropdown-trigger:hover {
  background: var(--accent-light);
  border-color: var(--accent);
}

.font-dropdown-trigger .bi-chevron-down {
  transition: transform 0.2s;
  font-size: 0.7rem;
}

.font-dropdown-trigger .bi-chevron-down.rotated {
  transform: rotate(180deg);
}

.font-dropdown-menu {
  position: absolute;
  top: calc(100% + 8px);
  right: 0;
  min-width: 200px;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 12px;
  box-shadow: var(--shadow-lg);
  overflow: hidden;
  z-index: 100;
  backdrop-filter: blur(12px);
}

.font-option {
  display: flex;
  align-items: center;
  gap: 10px;
  width: 100%;
  padding: 10px 14px;
  background: transparent;
  border: none;
  cursor: pointer;
  font-size: 0.8rem;
  text-align: left;
  transition: all 0.15s;
  color: var(--text);
}

.font-option:hover {
  background: var(--accent-light);
}

.font-option.active {
  background: var(--accent);
  color: white;
}

.font-option .check-icon {
  margin-left: auto;
  font-size: 0.8rem;
}

/* Dropdown Animation */
.dropdown-fade-enter-active,
.dropdown-fade-leave-active {
  transition: all 0.2s ease;
}

.dropdown-fade-enter-from,
.dropdown-fade-leave-to {
  opacity: 0;
  transform: translateY(-8px);
}

