/* Improved Toggle Buttons - Consistent with modern UI */
.toggle-chip {
  min-height: 32px;
  min-width: 68px;
  padding: 6px 14px;
  border-radius: 40px;
  font-size: 0.75rem;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
  border: 1px solid var(--border);
  background: var(--surface);
  color: var(--text-muted);
  letter-spacing: 0.3px;
  position: relative;
  overflow: hidden;
}

.toggle-chip::before {
  content: '';
  position: absolute;
  top: 50%;
  left: 50%;
  width: 0;
  height: 0;
  border-radius: 50%;
  background: rgba(154, 103, 56, 0.2);
  transform: translate(-50%, -50%);
  transition: width 0.4s, height 0.4s;
}

.toggle-chip:active::before {
  width: 100px;
  height: 100px;
}

.toggle-chip:hover {
  transform: translateY(-1px);
  box-shadow: var(--shadow-sm);
}

.toggle-chip.active {
  background: linear-gradient(135deg, var(--accent), var(--accent-strong));
  border-color: transparent;
  color: white;
  box-shadow: 0 2px 8px rgba(154, 103, 56, 0.3);
}

.toggle-chip.active:hover {
  transform: translateY(-1px);
  box-shadow: 0 4px 12px rgba(154, 103, 56, 0.4);
  filter: brightness(1.05);
}

.toggle-chip:active {
  transform: translateY(0);
}

.mode-radio-group {
