/* Planner & Analytics UI */
.modal-overlay {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(12, 10, 8, 0.62);
  backdrop-filter: blur(8px);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 9999;
  padding: 20px;
}

.session-analytics-overlay {
  z-index: 12000;
}

.post-onboarding-overlay {
  z-index: 12500;
}

.post-onboarding-modal {
  width: min(640px, 94vw);
  border-radius: 18px;
  overflow: hidden;
  --onboarding-bg: linear-gradient(180deg, rgba(32, 38, 35, 0.98), rgba(24, 30, 27, 0.96));
  --onboarding-border: rgba(104, 160, 143, 0.2);
  --onboarding-text: #e7efeb;
  --onboarding-muted: #c2d0cb;
  --onboarding-kicker-bg: rgba(79, 157, 138, 0.16);
  --onboarding-kicker-text: #97c9ba;
  --onboarding-panel-bg: rgba(255, 255, 255, 0.035);
  --onboarding-panel-border: rgba(104, 160, 143, 0.18);
  --onboarding-panel-text: #d7e3de;
  --onboarding-preview-title: #f1f7f4;
  --onboarding-preview-subtitle: #b9cbc4;
  --onboarding-preview-icon-bg: rgba(90, 165, 143, 0.16);
  --onboarding-preview-icon: #9dd7c5;
  --onboarding-progress-idle: rgba(104, 160, 143, 0.28);
  --onboarding-progress-active: #5aa58f;
  background: var(--onboarding-bg);
  border: 1px solid var(--onboarding-border);
  color: var(--onboarding-text);
  animation: onboardingScaleIn 220ms ease;
}

.post-onboarding-header {
  background: transparent;
  border-bottom: 1px solid var(--onboarding-border);
}

.post-onboarding-header h2 {
  margin: 0;
  font-size: 1.28rem;
  font-weight: 500;
  color: var(--onboarding-text);
}

.post-onboarding-body p {
  margin: 0;
  font-size: 1.08rem;
  line-height: 1.62;
  color: var(--onboarding-muted);
}

.post-onboarding-kicker {
  display: inline-flex;
  margin-bottom: 10px;
  padding: 5px 9px;
  border-radius: 999px;
  background: var(--onboarding-kicker-bg);
  color: var(--onboarding-kicker-text);
  font-size: 0.7rem;
  font-weight: 750;
  text-transform: uppercase;
  letter-spacing: 0.04em;
}

.post-onboarding-points {
  margin: 12px 0 0;
  padding-left: 18px;
  display: grid;
  gap: 8px;
  color: var(--onboarding-text);
  font-size: 1rem;
  line-height: 1.45;
}

.post-onboarding-preview {
  margin-top: 16px;
  border: 1px solid var(--onboarding-panel-border);
  border-radius: 16px;
  padding: 14px;
  background: var(--onboarding-panel-bg);
  backdrop-filter: blur(10px);
}

.post-onboarding-preview-head {
  display: grid;
  grid-template-columns: auto minmax(0, 1fr);
  gap: 12px;
  align-items: center;
}

.post-onboarding-preview-icon {
  width: 44px;
  height: 44px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border-radius: 14px;
  background: var(--onboarding-preview-icon-bg);
  color: var(--onboarding-preview-icon);
  font-size: 1.18rem;
}

.post-onboarding-preview-head strong {
  display: block;
  color: var(--onboarding-preview-title);
  font-size: 1rem;
}

.post-onboarding-preview-head small {
  display: block;
  margin-top: 2px;
  color: var(--onboarding-preview-subtitle);
  line-height: 1.45;
}

.post-onboarding-preview-grid {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  margin-top: 12px;
}

.post-onboarding-preview-grid span {
  min-height: 32px;
  display: inline-flex;
  align-items: center;
  gap: 6px;
  border: 1px solid var(--onboarding-panel-border);
  border-radius: 999px;
  padding: 5px 10px;
  background: color-mix(in srgb, var(--onboarding-preview-icon-bg) 70%, transparent);
  color: var(--onboarding-panel-text);
  font-size: 0.82rem;
  font-weight: 700;
}

.post-onboarding-preview-grid i {
  color: var(--onboarding-preview-icon);
}

.post-onboarding-progress {
  margin-top: 14px;
  display: flex;
  gap: 8px;
}

.post-onboarding-progress span {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: var(--onboarding-progress-idle);
}

.post-onboarding-progress span.active {
  background: var(--onboarding-progress-active);
}

.post-onboarding-footer {
  border-top: 1px solid rgba(104, 160, 143, 0.14);
}

@keyframes onboardingScaleIn {
  from {
    opacity: 0;
    transform: scale(0.98);
  }

  to {
    opacity: 1;
    transform: scale(1);
  }
}

.session-analytics-modal {
  width: min(1080px, 96vw);
  max-height: 88vh;
  border-radius: 20px;
  overflow: hidden;
  background: linear-gradient(180deg, rgba(249, 245, 239, 0.98), rgba(241, 235, 226, 0.96));
}

.session-analytics-header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 12px;
  position: sticky;
  top: 0;
  z-index: 2;
  background: inherit;
}

.session-analytics-head-copy h2 {
  margin: 0;
  font-size: 1.15rem;
}

.session-analytics-head-copy p {
  margin: 6px 0 0;
  font-size: 0.9rem;
  color: var(--text);
}

.session-analytics-head-copy small {
  display: block;
  margin-top: 4px;
  color: var(--text-muted);
  font-size: 0.76rem;
}

.session-analytics-head-actions {
  display: inline-flex;
  align-items: center;
  gap: 8px;
}

.session-analytics-download {
  min-height: 38px;
}

.session-analytics-body {
  max-height: calc(88vh - 92px);
  overflow-y: auto;
  display: grid;
  gap: 16px;
  padding: 4px 2px 6px;
}

.session-analytics-section {
  display: grid;
  gap: 12px;
}

.session-analytics-section h3 {
  margin: 0;
  font-size: 0.88rem;
  text-transform: uppercase;
  letter-spacing: 0.07em;
  color: var(--text-muted);
}

.session-analytics-summary-grid {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 10px;
}

.session-analytics-summary-card {
  border: 1px solid var(--border);
  border-radius: 14px;
  padding: 14px;
  background: rgba(255, 255, 255, 0.64);
  display: grid;
  gap: 5px;
}

.session-analytics-summary-card span {
  font-size: 0.72rem;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.04em;
}

.session-analytics-summary-card strong {
  font-size: 1.18rem;
  color: var(--text);
}

.session-analytics-summary-card small {
  color: var(--text-muted);
  font-size: 0.76rem;
  line-height: 1.4;
}

.session-analytics-two-col {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 12px;
}

.session-analytics-panel {
  border: 1px solid var(--border);
  border-radius: 16px;
  padding: 14px;
  background: rgba(255, 255, 255, 0.62);
  display: grid;
  gap: 12px;
}

.session-analytics-panel header {
  display: grid;
  gap: 4px;
}

.session-analytics-panel header h3 {
  margin: 0;
  font-size: 0.94rem;
  font-weight: 650;
  color: var(--text);
}

.session-analytics-panel header p {
  margin: 0;
  font-size: 0.78rem;
  color: var(--text-muted);
}

.analytics-progress-split {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 10px;
}

.analytics-progress-stat {
  border-radius: 14px;
  border: 1px solid rgba(154, 103, 56, 0.12);
  background: rgba(255, 255, 255, 0.48);
  padding: 12px;
  display: grid;
  gap: 4px;
}

.analytics-line-chart svg {
  width: 100%;
  height: 160px;
}

.analytics-y-axis line {
  stroke: rgba(154, 103, 56, 0.14);
  stroke-width: 1;
}

.analytics-y-axis text {
  fill: var(--text-muted);
  font-size: 10px;
}

.analytics-line-path {
  fill: none;
  stroke: #bd8c58;
  stroke-width: 3;
  stroke-linecap: round;
  stroke-linejoin: round;
}

.analytics-line-dot {
  fill: #bd8c58;
  stroke: rgba(255, 255, 255, 0.88);
  stroke-width: 1.4;
}

.analytics-line-labels {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(18px, 1fr));
  gap: 6px;
  color: var(--text-muted);
  font-size: 0.72rem;
  text-align: center;
}

.analytics-heatmap-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(84px, 1fr));
  gap: 8px;
}

.analytics-heatmap-cell {
  border-radius: 12px;
  border: 1px solid rgba(154, 103, 56, 0.12);
  background:
    linear-gradient(180deg, rgba(250, 241, 223, calc(0.84 - (var(--cell-intensity, 0.06) * 0.18))), rgba(112, 70, 38, calc(0.12 + (var(--cell-intensity, 0.06) * 0.46)))),
    rgba(196, 148, 72, calc(0.12 + (var(--cell-intensity, 0.06) * 0.24)));
  padding: 10px;
  display: grid;
  gap: 3px;
}

.analytics-heatmap-cell span {
  font-size: 0.72rem;
  color: var(--text-muted);
}

.analytics-heatmap-cell strong {
  font-size: 0.95rem;
  color: var(--text);
}

.analytics-empty-panel {
  border-radius: 12px;
  border: 1px dashed rgba(154, 103, 56, 0.18);
  padding: 14px;
  color: var(--text-muted);
  font-size: 0.78rem;
}

.stats-detail-actions-prominent {
  margin-bottom: 14px;
}

.bar-row {
  display: grid;
  grid-template-columns: minmax(0, 86px) minmax(0, 1fr) auto;
  align-items: center;
  gap: 8px;
}

.bar-row span,
.bar-row em {
  font-size: 0.72rem;
  color: var(--text-muted);
  font-style: normal;
}

.bar-track {
  height: 7px;
  border-radius: 999px;
  background: rgba(79, 157, 138, 0.12);
  overflow: hidden;
}

.bar-fill {
  height: 100%;
  border-radius: inherit;
  background: #4f9d8a;
}

.comparison-chart-shell {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 8px;
}

.comparison-item {
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 8px;
  background: rgba(255, 255, 255, 0.58);
  display: grid;
  gap: 4px;
}

.comparison-item span {
  font-size: 0.7rem;
  color: var(--text-muted);
}

.comparison-item strong {
  font-size: 1.2rem;
  color: var(--text);
}

.pie-chart-shell {
  display: grid;
  gap: 10px;
}

.pie-chart-ring {
  width: 92px;
  height: 92px;
  border-radius: 50%;
  margin: 0 auto;
  box-shadow: inset 0 0 0 12px rgba(0, 0, 0, 0.08);
}

.pie-chart-legend {
  display: grid;
  gap: 4px;
}

.pie-chart-legend span {
  font-size: 0.72rem;
  color: var(--text-muted);
}

.heatmap-grid {
  display: grid;
  grid-template-columns: repeat(14, minmax(0, 1fr));
  gap: 6px;
}

.heatmap-cell {
  border: 1px solid var(--border);
  border-radius: 8px;
  min-height: 32px;
  background: radial-gradient(circle at center, rgba(79, 157, 138, calc(var(--heat-intensity, 0.1) * 0.55)), rgba(79, 157, 138, calc(var(--heat-intensity, 0.1) * 0.12)));
  color: var(--text);
  font-size: 0.66rem;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0;
}

.analytics-loading {
  min-height: 180px;
  display: grid;
  place-items: center;
  color: var(--text-muted);
  font-size: 0.84rem;
}

[data-theme="dark"] .session-analytics-modal {
  background: linear-gradient(180deg, #1f2422, #1a201d);
}

[data-theme="dark"] .session-analytics-summary-card,
[data-theme="dark"] .session-analytics-chart-card,
[data-theme="dark"] .comparison-item {
  background: rgba(40, 49, 45, 0.76);
  border-color: rgba(108, 158, 143, 0.22);
}

[data-theme="dark"] .bar-track {
  background: rgba(79, 157, 138, 0.22);
}

[data-theme="dark"] .heatmap-cell {
  border-color: rgba(108, 158, 143, 0.22);
}

@media (max-width: 1024px) {
  .session-analytics-summary-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .session-analytics-chart-grid {
    grid-template-columns: 1fr;
  }
}

@media (max-width: 768px) {
  .post-onboarding-modal {
    width: 100vw;
    height: 100dvh;
    max-height: 100dvh;
    border-radius: 0;
  }

  .post-onboarding-header {
    position: sticky;
    top: 0;
    z-index: 2;
    background: rgba(24, 30, 27, 0.96);
  }

  .session-analytics-modal {
    width: 100vw;
    max-height: 100dvh;
    height: 100dvh;
    border-radius: 0;
  }

  .session-analytics-body {
    max-height: calc(100dvh - 92px);
  }

  .session-analytics-summary-grid {
    grid-template-columns: 1fr 1fr;
  }

  .heatmap-grid {
    grid-template-columns: repeat(7, minmax(0, 1fr));
  }
}

.modal-content {
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.94), rgba(255, 250, 243, 0.92));
  border-radius: 20px;
  box-shadow: 0 28px 90px rgba(0, 0, 0, 0.42);
  border: 1px solid rgba(255, 255, 255, 0.55);
  display: flex;
  flex-direction: column;
  max-height: 90vh;
  overflow: hidden;
  animation: modalFadeIn 0.3s cubic-bezier(0.16, 1, 0.3, 1);
}

.resume-modal {
  width: min(760px, 96vw);
}

.resume-modal .modal-header h2 {
  font-size: clamp(1.25rem, 2.3vw, 1.75rem);
}

.resume-saved-at {
  display: inline-block;
  margin-top: 4px;
  color: var(--text-muted);
  font-size: 0.82rem;
}

.resume-grid {
  margin-top: 12px;
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 10px;
}

.resume-grid .pill {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 12px 14px;
}

@keyframes modalIn {
  from {
    transform: translateY(10px);
    opacity: 0.6;
  }

  to {
    transform: translateY(0);
    opacity: 1;
  }
}

@keyframes modalFadeIn {
  from {
    opacity: 0;
    transform: translateY(20px) scale(0.95);
  }

  to {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}

.modal-header {
  padding: 20px 24px;
  border-bottom: 1px solid var(--border);
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.modal-header h2 {
  margin: 0;
  font-size: 1.25rem;
  font-weight: 700;
}

.modal-body {
  padding: 24px;
  overflow-y: auto;
}

.modal-footer {
  padding: 20px 24px;
  border-top: 1px solid var(--border);
  background: var(--bg-elevated);
}

.confirm-modal {
  max-width: 460px;
  width: 100%;
}

.confirm-copy {
  color: var(--text-muted);
  line-height: 1.65;
}

.btn-danger {
  background: #b55041;
}

.tools-btn-danger {
  opacity: 0.82;
}

.btn-icon {
  background: none;
  border: none;
  font-size: 1.2rem;
  color: var(--text-muted);
  cursor: pointer;
  width: 32px;
  height: 32px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.2s;
}

.btn-icon:hover {
  background: var(--border);
  color: var(--text);
}

.planner-modal {
  max-width: 500px;
  width: 100%;
}

.planner-field {
  margin-bottom: 24px;
}

.planner-field label {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 0.85rem;
  font-weight: 600;
  color: var(--text);
  margin-bottom: 8px;
}

.planner-select,
.planner-input {
  width: 100%;
  padding: 12px 14px;
  border-radius: 12px;
  border: 1px solid var(--border);
  background: var(--surface);
  font-size: 0.9rem;
  transition: all 0.2s;
}

.planner-select:focus,
.planner-input:focus {
  outline: none;
  border-color: var(--accent);
  box-shadow: 0 0 0 2px var(--accent-light);
}

.verses-per-day-control {
  display: flex;
  align-items: center;
  gap: 12px;
}

.quantity-btn {
  width: 40px;
  height: 40px;
  border-radius: 12px;
  border: 1px solid var(--border);
  background: var(--surface);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.2s;
}

.quantity-btn:hover:not(:disabled) {
  background: var(--accent);
  color: white;
  border-color: var(--accent);
}

.quantity-btn:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

.planner-stats-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 12px;
  margin: 24px 0;
}

.planner-stat-card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 16px;
  padding: 16px;
  display: flex;
  align-items: center;
  gap: 12px;
  transition: all 0.2s;
}

.progress-info {
  display: flex;
  justify-content: space-between;
  font-size: 0.7rem;
  color: var(--text-muted);
  margin-bottom: 8px;
}

.progress-bar-track {
  height: 6px;
  background: var(--border);
  border-radius: 3px;
  overflow: hidden;
}

.progress-bar-fill {
  height: 100%;
  background: var(--accent);
  border-radius: 3px;
  transition: width 0.3s ease;
}

.modal-footer {
  display: flex;
  gap: 12px;
  padding: 20px 24px;
  border-top: 1px solid var(--border);
  background: var(--surface);
}

.btn-secondary {
  flex: 1;
  padding: 12px;
  border-radius: 12px;
  border: 1px solid var(--border);
  background: transparent;
  cursor: pointer;
  font-size: 0.9rem;
  transition: all 0.2s;
}

.btn-secondary:hover {
  background: var(--border);
}

.btn-primary {
  flex: 1;
  padding: 12px;
  border-radius: 12px;
  background: linear-gradient(135deg, var(--accent), var(--accent-strong));
  color: white;
  border: none;
  cursor: pointer;
  font-size: 0.9rem;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  transition: all 0.2s;
}

.btn-primary:hover {
  transform: translateY(-2px);
  box-shadow: 0 4px 12px rgba(154, 103, 56, 0.3);
}

.field-hint {
  display: block;
  font-size: 0.7rem;
  color: var(--text-muted);
  margin-top: 6px;
}

.pa-lbl {
  font-size: 0.8rem;
  color: var(--text-muted);
}

.analytics-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 16px;
  margin-top: 20px;
}

.analytics-help {
  margin-top: 10px;
  color: var(--text-muted);
  font-size: calc(0.78rem * var(--en-scale, 1));
  line-height: 1.4;
}

.stat-card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 12px;
  padding: 20px;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  text-align: center;
  transition: transform 0.2s;
}

.stat-delta {
  display: inline-flex;
  align-items: center;
  margin-left: 10px;
  padding: 4px 8px;
  border-radius: 999px;
  border: 1px solid var(--border);
  background: rgba(255, 255, 255, 0.72);
  font-size: 0.7rem;
  color: var(--accent-strong);
  font-weight: 700;
  vertical-align: middle;
}

.stat-card:hover {
  transform: translateY(-2px);
  border-color: var(--accent);
}

.stat-card i {
  font-size: 1.8rem;
  color: var(--accent);
  margin-bottom: 12px;
}

.stat-value {
  font-size: 1.5rem;
  font-weight: 700;
  color: var(--text);
  margin-bottom: 4px;
}

.stat-label {
  font-size: 0.85rem;
  color: var(--text-muted);
}

.stat-help {
  margin-top: 10px;
  color: var(--text-muted);
  font-size: calc(0.72rem * var(--en-scale, 1));
  line-height: 1.35;
}

.mini-trend {
  position: relative;
  width: 80px;
  height: 24px;
  margin-top: 10px;
}

.mini-trend span {
  position: absolute;
  width: 8px;
  border-radius: 999px;
  background: linear-gradient(180deg, var(--accent), var(--accent-soft));
  opacity: 0.9;
}

/* Home Dashboard UI */
.home-dashboard {
  max-width: 800px;
  margin: 40px auto;
  padding: 0 20px;
  animation: modalFadeIn 0.4s ease-out;
}

.dashboard-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-end;
  margin-bottom: 40px;
  flex-wrap: wrap;
  gap: 20px;
}

.welcome-text {
  max-width: 500px;
}

.header-stats {
  display: flex;
  gap: 16px;
  background: var(--surface);
  padding: 12px 20px;
  border-radius: 16px;
  border: 1px solid var(--border);
  box-shadow: var(--shadow-sm);
}

.mini-stat {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 0.9rem;
}

.mini-stat strong {
  color: var(--text);
  font-size: 1rem;
}

.dashboard-actions {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
  gap: 20px;
  margin-bottom: 40px;
}

.home-dashboard-minimal {
  display: flex;
  flex-direction: column;
  gap: 16px;
  min-height: 160px;
}

.idle-action-shell {
  display: grid;
  gap: 1.15rem;
  padding: 1.1rem;
  border: 1px solid color-mix(in srgb, var(--border) 76%, transparent);
  border-radius: 22px;
  background: color-mix(in srgb, var(--surface) 96%, transparent);
  box-shadow: var(--shadow-sm);
}

.idle-action-head {
  display: grid;
  gap: 0.35rem;
}

.idle-action-grid-shell {
  padding-inline: 0;
}

.workspace-idle-shell {
  margin-bottom: 1rem;
}

.idle-action-card {
  width: 100%;
  min-height: 180px;
  display: grid;
  align-content: start;
  gap: 0.75rem;
  padding: 1.15rem;
  text-align: left;
  border: 1px solid color-mix(in srgb, var(--border) 76%, transparent);
  border-radius: 18px;
  background: color-mix(in srgb, var(--surface) 98%, transparent);
  color: var(--text);
  transition: transform 140ms ease, box-shadow 140ms ease, border-color 140ms ease, background 140ms ease;
}

.idle-action-card:hover {
  transform: translateY(-2px);
  box-shadow: 0 18px 38px rgba(20, 18, 16, 0.08);
  border-color: color-mix(in srgb, var(--accent) 28%, var(--border));
}

.idle-action-card i {
  font-size: 1.45rem;
  color: var(--accent);
}

.idle-action-card strong {
  font-size: 1rem;
  line-height: 1.2;
}

.idle-action-card small {
  color: var(--text-muted);
  font-size: 0.9rem;
  line-height: 1.45;
}

.idle-action-card-primary {
  background: linear-gradient(180deg, color-mix(in srgb, var(--accent) 12%, var(--surface) 88%), color-mix(in srgb, var(--surface) 98%, transparent));
  border-color: color-mix(in srgb, var(--accent) 24%, var(--border));
}

.idle-action-card-accent {
  background: linear-gradient(180deg, color-mix(in srgb, #2f6f58 12%, var(--surface) 88%), color-mix(in srgb, var(--surface) 98%, transparent));
  border-color: color-mix(in srgb, #2f6f58 28%, var(--border));
}

[data-theme="dark"] .idle-action-shell {
  box-shadow: 0 14px 36px rgba(0, 0, 0, 0.34);
}

[data-theme="dark"] .idle-action-card {
  background: color-mix(in srgb, var(--surface) 88%, transparent);
}

[data-theme="dark"] .idle-action-card:hover {
  box-shadow: 0 18px 38px rgba(0, 0, 0, 0.38);
  border-color: color-mix(in srgb, var(--accent) 34%, var(--border));
}

[data-theme="dark"] .idle-action-card-primary {
  background: linear-gradient(180deg, color-mix(in srgb, var(--accent) 18%, var(--surface) 82%), color-mix(in srgb, var(--surface) 96%, transparent));
}

.workspace-empty-state {
  display: grid;
  place-items: center;
  min-height: min(42vh, 420px);
  padding: 1rem 0 2rem;
}

.workspace-empty-card {
  width: min(100%, 760px);
  display: grid;
  gap: 0.9rem;
  padding: clamp(1.25rem, 2.4vw, 2rem);
  border: 1px solid color-mix(in srgb, var(--border) 82%, transparent);
  border-radius: 24px;
  background: linear-gradient(180deg, color-mix(in srgb, var(--surface) 98%, transparent), color-mix(in srgb, var(--surface) 92%, transparent));
  box-shadow: var(--shadow-sm);
}

.workspace-empty-kicker {
  display: inline-flex;
  color: var(--accent);
  font-size: 0.72rem;
  font-weight: 800;
  text-transform: uppercase;
  letter-spacing: 0.08em;
}

.workspace-empty-card h2 {
  margin: 0;
  color: var(--text);
  font-size: clamp(1.3rem, 2.8vw, 1.95rem);
  line-height: 1.1;
}

.workspace-empty-card p {
  margin: 0;
  max-width: 56ch;
  color: var(--text-muted);
  font-size: 0.98rem;
  line-height: 1.55;
}

.workspace-empty-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem;
  margin-top: 0.25rem;
}

[data-theme="dark"] .workspace-empty-card {
  background: linear-gradient(180deg, color-mix(in srgb, var(--surface) 92%, transparent), color-mix(in srgb, var(--surface) 84%, transparent));
  box-shadow: 0 18px 38px rgba(0, 0, 0, 0.28);
}

[data-theme="dark"] .session-ended-grid-shell,
[data-theme="dark"] .session-ended-grid-btn {
  background: transparent;
}

[data-theme="dark"] .session-ended-grid-btn.btn-outline-secondary {
  color: var(--text);
  border-color: color-mix(in srgb, var(--border) 92%, transparent);
  background: color-mix(in srgb, var(--surface) 94%, transparent);
}

[data-theme="dark"] .session-ended-grid-btn.btn-success {
  color: #1a140f;
  border-color: color-mix(in srgb, #d4aa7c 68%, transparent);
  background: linear-gradient(135deg, #d4aa7c, #b98654);
}

.offcanvas {
  position: fixed;
  top: 0;
  right: 0;
  width: 380px;
  height: 100%;
  background: #fff;
  z-index: 1000;
  transform: translateX(100%);
  transition: transform 0.3s ease;
  display: flex;
  flex-direction: column;
  box-shadow: -4px 0 20px rgba(0, 0, 0, 0.15);
}

.offcanvas-launcher-card {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
  padding: 20px;
  margin-bottom: 18px;
  border: 1px solid var(--border);
  border-radius: 18px;
  background: var(--surface);
  box-shadow: var(--shadow-sm);
}

.offcanvas-launcher-copy {
  margin: 0;
  color: var(--text-muted);
  font-size: 0.95rem;
  line-height: 1.45;
}

.setup-start-card {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto auto;
  align-items: center;
  gap: 18px;
  padding: 20px;
  margin-bottom: 18px;
  border: 1px solid var(--border);
  border-radius: 18px;
  background: var(--surface);
  box-shadow: var(--shadow-sm);
}

.setup-start-copy {
  min-width: 0;
}

.setup-kicker {
  display: inline-flex;
  margin-bottom: 6px;
  color: var(--accent);
  font-size: 0.72rem;
  font-weight: 800;
  text-transform: uppercase;
  letter-spacing: 0.08em;
}

.setup-start-copy h2 {
  margin: 0 0 6px;
  color: var(--text);
  font-size: clamp(1.2rem, 2vw, 1.65rem);
  line-height: 1.1;
}

.setup-start-copy p {
  margin: 0;
  color: var(--text-muted);
  font-size: 0.95rem;
  line-height: 1.45;
}

.setup-review-hint {
  margin-top: 10px;
  padding: 10px 12px;
  border-radius: 12px;
  background: rgba(184, 130, 78, 0.10);
  border: 1px solid rgba(184, 130, 78, 0.18);
  color: var(--accent);
  font-weight: 700;
}

.setup-mode-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(112px, 1fr));
  gap: 10px;
}

.setup-mode-card {
  min-height: 86px;
  padding: 12px;
  border: 1px solid var(--border);
  border-radius: 14px;
  background: var(--surface);
  color: var(--text);
  cursor: pointer;
  display: grid;
  justify-items: center;
  align-content: center;
  gap: 4px;
  transition: border-color 0.18s ease, box-shadow 0.18s ease, transform 0.18s ease;
}

.setup-mode-card:hover,
.setup-mode-card.active {
  border-color: var(--accent);
  box-shadow: var(--shadow-sm);
  transform: translateY(-1px);
}

.setup-mode-card i {
  color: var(--accent);
  font-size: 1.2rem;
}

.setup-mode-card span {
  font-weight: 800;
}

.setup-mode-card small {
  color: var(--text-muted);
  font-size: 0.78rem;
}

.setup-primary {
  min-height: 48px;
  white-space: nowrap;
}

.setup-optional-panel,
.session-tools-panel {
  border: 1px solid var(--border);
  border-radius: 14px;
  background: rgba(255, 255, 255, 0.68);
}

.setup-optional-panel summary,
.session-tools-panel summary {
  cursor: pointer;
  list-style: none;
  padding: 12px 14px;
  font-weight: 700;
  color: var(--text);
}

.setup-optional-panel summary::-webkit-details-marker,
.session-tools-panel summary::-webkit-details-marker {
  display: none;
}

.setup-optional-grid,
.session-tools-grid {
  display: grid;
  gap: 12px;
  padding: 0 14px 14px;
}

.setup-optional-grid {
  grid-template-columns: repeat(2, minmax(0, 1fr));
}

.session-tools-grid {
  grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
}

.field-inline-toggle {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.toggle-chip {
  min-height: 42px;
  border: 1px solid var(--border);
  border-radius: 12px;
  background: var(--surface);
  color: var(--text);
  font-family: inherit;
  font-weight: 540;
}

.toggle-chip.active {
  border-color: var(--accent);
  color: white;
}

.continue-session-card {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
  padding: 16px 18px;
  margin-bottom: 18px;
  border: 1px solid var(--accent-soft);
  border-radius: 18px;
  background: linear-gradient(135deg, var(--surface), var(--accent-light));
  box-shadow: var(--shadow-sm);
  transition: transform 0.2s ease, box-shadow 0.2s ease, border-color 0.2s ease;
}

.smart-resume-card {
  align-items: stretch;
  border-color: rgba(154, 103, 56, 0.28);
  background:
    linear-gradient(135deg, rgba(255, 252, 246, 0.98), rgba(247, 236, 221, 0.92)),
    radial-gradient(circle at top left, rgba(154, 103, 56, 0.14), transparent 34%);
  box-shadow: 0 18px 40px rgba(99, 66, 32, 0.12);
}

.continue-session-card:hover {
  transform: translateY(-2px);
  box-shadow: var(--shadow-md);
  border-color: var(--accent);
}

.smart-resume-card:hover {
  box-shadow: 0 22px 48px rgba(99, 66, 32, 0.16);
}

.smart-resume-icon {
  flex: 0 0 auto;
  width: 54px;
  height: 54px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border-radius: 16px;
  background: var(--accent);
  color: white;
  font-size: 1.45rem;
  box-shadow: 0 12px 24px rgba(154, 103, 56, 0.22);
}

.continue-session-copy {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.smart-resume-copy {
  flex: 1 1 auto;
  min-width: 0;
  gap: 8px;
}

.smart-resume-copy strong {
  color: var(--text);
  font-size: 1.15rem;
  line-height: 1.2;
}

.continue-session-actions {
  display: flex;
  align-items: center;
  gap: 10px;
  flex-wrap: nowrap;
}

.smart-resume-card .continue-session-actions {
  flex: 0 0 auto;
  align-self: center;
}

.continue-session-kicker {
  font-size: 0.72rem;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: var(--accent);
  font-weight: 800;
}

.continue-session-copy small {
  color: var(--text-muted);
}

.smart-resume-context {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.smart-resume-context span {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  min-height: 30px;
  padding: 5px 9px;
  border: 1px solid rgba(154, 103, 56, 0.14);
  border-radius: 999px;
  background: rgba(255, 255, 255, 0.66);
  color: var(--text);
  font-size: 0.78rem;
  font-weight: 650;
}

.smart-resume-context i {
  color: var(--accent);
}

.smart-resume-progress {
  display: grid;
  gap: 6px;
  max-width: 520px;
}

.smart-resume-progress-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  color: var(--text-muted);
  font-size: 0.78rem;
  font-weight: 700;
}

.smart-resume-progress-head strong {
  color: var(--accent-strong);
  font-size: 0.78rem;
}

.smart-resume-progress-track {
  height: 7px;
  overflow: hidden;
  border-radius: 999px;
  background: rgba(154, 103, 56, 0.12);
}

.smart-resume-progress-track span {
  display: block;
  height: 100%;
  min-width: 8px;
  border-radius: inherit;
  background: linear-gradient(90deg, var(--accent), var(--accent-strong));
}

.continue-session-btn {
  min-height: 44px;
  white-space: nowrap;
  flex: 0 0 auto;
  padding-inline: 22px;
  box-shadow: 0 12px 24px rgba(154, 103, 56, 0.18);
}

.continue-session-dismiss {
  min-width: 44px;
  padding-inline: 0;
  justify-content: center;
}

.resume-action {
  background: linear-gradient(145deg, rgba(154, 103, 56, 0.12), rgba(255, 255, 255, 0.94));
  border-color: var(--accent-soft);
}

.resume-action .action-icon {
  background: rgba(154, 103, 56, 0.15);
  color: var(--accent);
}

.resume-action .action-arrow {
  color: var(--accent);
}

.action-card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 16px;
  padding: 24px;
  cursor: pointer;
  transition: all 0.2s cubic-bezier(0.16, 1, 0.3, 1);
  display: flex;
  flex-direction: column;
  position: relative;
  overflow: hidden;
}

.action-card:hover {
  transform: translateY(-4px);
  box-shadow: 0 12px 24px rgba(0, 0, 0, 0.05);
  border-color: var(--accent);
}

.action-card.primary-action {
  background: linear-gradient(145deg, var(--accent), var(--accent-dark));
  color: white;
  border: none;
}

.action-card.primary-action .action-icon {
  background: rgba(255, 255, 255, 0.2);
  color: white;
}

.action-card.primary-action h3,
.action-card.primary-action p,
.action-card.primary-action .action-arrow {
  color: white;
}

.action-icon {
  width: 48px;
  height: 48px;
  background: var(--bg-body);
  border-radius: 12px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.5rem;
  color: var(--accent);
  margin-bottom: 20px;
}

.action-content h3 {
  font-size: 1.15rem;
  margin: 0 0 8px 0;
  color: var(--text);
}

.action-content p {
  font-size: 0.9rem;
  color: var(--text-muted);
  margin: 0;
  line-height: 1.4;
}

.action-arrow {
  position: absolute;
  bottom: 24px;
  right: 24px;
  font-size: 1.2rem;
  color: var(--accent);
  opacity: 0;
  transform: translateX(-10px);
  transition: all 0.2s ease;
}

.action-card:hover .action-arrow {
  opacity: 1;
  transform: translateX(0);
}

.dashboard-recent {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 16px;
  padding: 24px;
}

.recent-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 20px;
}

.recent-header h3 {
  margin: 0;
  font-size: 1.1rem;
}

.btn-ghost {
  background: none;
  border: none;
  color: var(--accent);
  font-weight: 500;
  cursor: pointer;
  padding: 6px 12px;
  border-radius: 8px;
  transition: background 0.2s;
}

.btn-ghost:hover {
  background: var(--accent-light);
}

.recent-stats {
  display: flex;
  gap: 32px;
  flex-wrap: wrap;
}

.r-stat {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.r-stat span {
  font-size: 0.8rem;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.r-stat strong {
  font-size: 1.4rem;
  color: var(--text);
}

@media (max-width: 768px) {
  .quick-tools-grid {
    grid-template-columns: 1fr;
    gap: 8px;
    padding: 12px;
  }

  .workspace-shell {
    width: 100%;
    margin-bottom: 14px;
  }

  .workspace-shell {
    padding: 14px;
  }

  .workspace-shell-head {
    grid-template-columns: minmax(0, 1fr);
    gap: 12px;
  }

  .workspace-shell-actions {
    width: 100%;
    display: flex;
    flex-wrap: wrap;
    justify-content: stretch;
  }

  .workspace-shell-title-row {
    align-items: flex-start;
  }

  .workspace-shell-phase {
    min-height: 26px;
  }

  .workspace-shell-meta {
    gap: 6px;
  }

  .workspace-shell-chaining {
    gap: 6px;
  }

  .resume-feedback-row {
    font-size: 0.74rem;
  }

  .resume-grid {
    grid-template-columns: 1fr;
  }

  .workspace-fab {
    top: 8px;
    display: grid;
    grid-template-columns: minmax(0, 1fr);
    gap: 8px;
    padding: 9px;
    margin: 8px 0 6px;
    border-radius: 14px;
  }

  .workspace-fab-meta {
    min-width: 0;
  }

  .workspace-fab-kicker {
    font-size: 0.64rem;
  }

  .workspace-fab-title {
    font-size: 0.9rem;
  }

  .workspace-fab-sub {
    font-size: 0.72rem;
    gap: 5px;
  }

  .workspace-fab-sub span {
    flex: 1 1 auto;
    justify-content: center;
    min-width: min(128px, 100%);
  }

  .workspace-fab-copy {
    font-size: 0.78rem;
  }

  .workspace-fab-live {
    gap: 6px;
  }

  .workspace-fab-live-pill {
    flex: 1 1 0;
    min-width: 0;
    justify-content: center;
  }

  .workspace-fab-actions {
    display: grid;
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 8px;
    width: 100%;
  }

  .fab-btn {
    width: 100%;
    min-width: 0;
    justify-content: center;
    padding: 8px 10px;
    font-size: 0.82rem;
    min-height: 44px;
  }

  .main-nav-btn,
  .main-card-primary {
    width: 100%;
    min-height: 44px;
  }

  .settings-heading {
    grid-template-columns: minmax(0, 1fr);
    gap: 10px;
    padding-bottom: 12px;
    margin-bottom: 14px;
  }

  .settings-status {
    justify-self: start;
  }

  .settings-card-grid,
  .settings-display-grid {
    grid-template-columns: minmax(0, 1fr);
  }

  .settings-card-toggle,
  .settings-card-range {
    min-height: 0;
    padding: 13px;
    gap: 12px;
  }

  .settings-toggle {
    min-height: 38px;
  }

  .settings-range-wrap {
    gap: 10px;
  }

  .settings-apply-section {
    padding: 12px;
  }

  .settings-apply-primary {
    min-height: 46px;
    border-radius: 12px;
    font-size: 0.88rem;
  }

  .setup-start-card {
    grid-template-columns: 1fr;
    align-items: stretch;
    padding: 16px;
  }

  .setup-mode-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .setup-primary {
    width: 100%;
    justify-content: center;
  }

  .continue-session-card {
    flex-direction: column;
    align-items: stretch;
  }

  .smart-resume-card {
    gap: 14px;
  }

  .smart-resume-icon {
    width: 48px;
    height: 48px;
  }

  .dashboard-actions {
    grid-template-columns: 1fr;
    gap: 14px;
    margin-bottom: 20px;
  }

  .offcanvas-launcher-card {
    flex-direction: column;
    align-items: stretch;
  }

  .action-card {
    padding: 18px;
  }

  .action-icon {
    margin-bottom: 14px;
  }

  .continue-session-btn,
  .btn-primary,
  .btn-secondary,
  .tools-btn,
  .player-btn,
  .toolbar-chip,
  .toggle-chip {
    min-height: 44px;
  }

  .continue-session-actions {
    justify-content: space-between;
  }

  .continue-session-btn {
    width: 100%;
  }

  .settings-toggle {
    min-height: 34px;
  }

  .inline-setting-row {
    align-items: stretch;
  }

  .input-compact,
  .inline-setting-pill {
    width: 100%;
    flex: 1 1 100%;
    justify-content: center;
  }

  .technique-row,
  .technique-row-main,
  .technique-control {
    align-items: stretch;
    flex-direction: column;
  }

  .technique-toggle,
  .segmented-control {
    width: 100%;
  }

  .player-bar {
    /* Mobile: sticky bottom controls (thumb-friendly, no overlap) */
    left: 0;
    right: 0;
    bottom: 0;
    transform: none;
    width: 100%;
    max-width: 100%;
    border-radius: 18px 18px 0 0;
    padding: 12px 14px calc(env(safe-area-inset-bottom, 0px) + 12px);
  }

  .player-bar.collapsed {
    transform: none;
  }

  .player-main {
    grid-template-columns: minmax(88px, 0.75fr) auto minmax(0, 1fr) minmax(0, 1fr) auto;
    align-items: center;
    gap: 8px;
  }

  .player-info {
    flex: 0 1 120px;
    min-width: 0;
  }

  .player-chapter {
    font-size: 0.78rem;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    max-width: 120px;
  }

  .player-verse {
    font-size: 0.72rem;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    max-width: 120px;
  }

  .player-controls {
    justify-content: center;
    gap: 4px;
  }

  .player-progress-wrap {
    order: 0;
    min-width: 0;
    gap: 6px;
  }

  .player-loop-controls {
    order: 3;
    width: 100%;
    grid-column: 1 / -2;
    justify-content: space-between;
  }

  .player-loop-group {
    width: 100%;
    justify-content: space-between;
  }

  .player-speed-controls {
    display: none;
  }

  .analytics-grid {
    grid-template-columns: 1fr;
  }

  .session-rail-top {
    grid-template-columns: 1fr;
    align-items: stretch;
  }

  .session-rail-actions {
    width: 100%;
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 10px;
  }

  .rail-btn {
    flex: initial;
    width: 100%;
    justify-content: center;
  }

  .rail-btn-primary {
    grid-column: 1 / -1;
  }

  .reading-toolbar {
    padding: 12px;
    gap: 10px;
  }

  .reading-toolbar-group {
    width: 100%;
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 10px;
  }

  .toolbar-chip {
    flex: initial;
    width: 100%;
  }

  .font-dropdown {
    grid-column: 1 / -1;
  }

  .reading-toolbar {
    padding: 12px;
    gap: 10px;
  }

  .reading-toolbar-group {
    width: 100%;
  }

  .toolbar-chip {
    flex: 1 1 calc(50% - 4px);
    justify-content: center;
    min-width: 0;
  }

  .font-dropdown {
    width: 100%;
  }

  .font-dropdown-trigger {
    width: 100%;
    justify-content: space-between;
  }

  .verse-card {
    padding: 16px;
    border-radius: 18px;
  }

  .verse-header {
    flex-direction: column;
    align-items: stretch;
    gap: 12px;
  }

  .verse-badges,
  .verse-actions {
    flex-wrap: wrap;
  }

  .verse-actions {
    justify-content: space-between;
  }

  .verse-font-controls {
    margin-right: 0;
    flex: 1 1 100%;
    justify-content: center;
  }

  .modal-content,
  .confirm-modal,
  .planner-modal {
    width: 100%;
    max-width: 100%;
    border-radius: 18px;
  }

  .modal-header,
  .modal-body,
  .modal-footer {
    padding-left: 16px;
    padding-right: 16px;
  }

  .planner-stats-grid {
    grid-template-columns: 1fr;
  }

  .tools {
    width: 100vw;
    max-width: 100vw;
  }

  .tools-top,
  .tools-body,
  .tools-footer {
    padding-left: 14px;
    padding-right: 14px;
  }

  .tools-tabs {
    overflow-x: hidden;
    display: grid;
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 8px;
  }

  .tools-tabs button {
    width: 100%;
    min-width: 0;
  }

  .reading-aid-grid,
  .session-tools-grid {
    grid-template-columns: 1fr;
  }

  .stats-grid {
    grid-template-columns: 1fr;
  }

  .stats-detail-head,
  .export-error-card,
  .save-section {
    flex-direction: column;
    align-items: stretch;
  }

  .verse-card,
  .tools,
  .sheet,
  .sheet-content {
    overflow-x: hidden;
  }
}

@media (min-width: 769px) and (max-width: 1024px) {
  .dashboard-actions {
    grid-template-columns: 1fr;
  }

  .session-rail-top {
    grid-template-columns: 1fr;
  }

  .session-rail-actions {
    flex-wrap: wrap;
  }

  .reading-toolbar {
    align-items: flex-start;
  }

  .reading-toolbar-group:first-child {
    flex: 1 1 100%;
  }

  .toolbar-chip {
    flex: 0 1 auto;
  }

  .player-bar {
    width: calc(100vw - 40px);
  }

  .player-main {
    grid-template-columns: minmax(132px, 0.9fr) auto minmax(160px, 0.9fr) minmax(150px, 1fr) auto;
    gap: 12px;
  }

  .player-progress-wrap {
    min-width: 0;
  }
}

@media (max-width: 480px) {
  .verse-header {
    flex-wrap: wrap;
  }

  .verse-badges {
    flex-wrap: wrap;
  }

  .verse-actions {
    margin-top: 8px;
    width: 100%;
    justify-content: flex-start;
  }

  .session-pill {
    white-space: normal;
    text-align: center;
    justify-content: center;
  }

  .rail-btn,
  .toolbar-chip {
    flex: 1 1 100%;
  }

  .player-time {
    min-width: auto;
    font-size: 0.7rem;
  }

  .player-progress-wrap {
    gap: 8px;
  }

  .verse-number,
  .verse-status-badge,
  .verse-status-subtle {
    width: 100%;
    justify-content: center;
    text-align: center;
  }
}

.verse-status-badge-review {
  border-color: rgba(183, 28, 28, 0.24);
  color: #9f1f1f;
  background: rgba(183, 28, 28, 0.08);
}

.verse-card.feedback-mastered {
  border-left: 4px solid #43a047;
}

.verse-card.feedback-weak {
  border-left: 4px solid #e3a008;
}

.verse-card.feedback-repeat {
  border-left: 4px solid #c62828;
}

.main.flow-recall .verse-card.active .verse-arabic {
  color: transparent;
  text-shadow: 0 0 22px rgba(232, 237, 247, 0.55);
}



.main.flow-practice .verse-card.active .verse-arabic {
  opacity: 0.45;
}

.main.flow-recall .verse-card.active .verse-arabic .tajweed-mark,
.main.flow-recall .verse-card.active .verse-arabic word,
.main.flow-recall .verse-card.active .verse-arabic .wbw-word {
  color: transparent !important;
  background: transparent !important;
  box-shadow: none !important;
}

.workspace-quick-controls {
  width: 100%;
  padding: 0 10px 10px;
}

.quick-pill-group-list {
  display: flex;
  gap: 6px;
  flex-wrap: wrap;
  align-items: center;
}

.quick-pill-group-list .view-mode-toggle {
  margin-left: auto;
  order: 20;
}

.toolbar-chip-sm {
  min-height: 28px;
  padding: 3px 9px;
  font-size: 0.72rem;
  border-radius: 999px;
}

.view-mode-toggle {
  --view-toggle-bg: #fffaf2;
  --view-toggle-border: #b58a62;
  --view-toggle-text: #5d4d40;
  --view-toggle-hover-bg: #f4e5d4;
  --view-toggle-active-bg: #5f3b20;
  --view-toggle-active-text: #fff7e8;
  --view-toggle-active-shadow: rgba(95, 59, 32, 0.24);
  display: inline-flex;
  align-items: center;
  gap: 0.25rem;
  padding: 0.25rem;
  border: 1px solid var(--view-toggle-border);
  border-radius: 999px;
  background: var(--view-toggle-bg) !important;
  box-shadow: 0 10px 22px rgba(95, 59, 32, 0.12), inset 0 1px 0 rgba(255, 255, 255, 0.58);
}

.view-mode-btn {
  display: inline-flex;
  align-items: center;
  gap: 0.35rem;
  min-height: 30px;
  padding: 0.3rem 0.68rem;
  border: 0;
  border-radius: 999px;
  background: transparent !important;
  color: var(--view-toggle-text) !important;
  font-size: 0.74rem;
  font-weight: 800;
  transition: background 180ms ease, color 180ms ease, transform 180ms ease, box-shadow 180ms ease;
}

.view-mode-btn:hover {
  transform: translateY(-1px);
  color: #2d1b10 !important;
  background: var(--view-toggle-hover-bg) !important;
}

.view-mode-btn.active {
  background: var(--view-toggle-active-bg) !important;
  color: var(--view-toggle-active-text) !important;
  box-shadow: 0 9px 18px var(--view-toggle-active-shadow) !important;
}

.view-mode-btn.active i,
.view-mode-btn.active span {
  color: inherit !important;
}

.mushaf-workspace {
  width: 100%;
  display: grid;
  gap: 0.65rem;
}

.mushaf-frame {
  position: relative;
  margin-inline: auto;
  width: min(100%, 1040px);
  transition: width 220ms ease, max-width 220ms ease, margin 220ms ease, transform 220ms ease;
}

@media (min-width: 1100px) {
  .main.mushaf-mode-active.tools-open .content {
    padding-right: min(var(--tools-width, 520px), 32vw);
    transition: padding-right 220ms ease;
  }

  .main.mushaf-mode-active.tools-open .mushaf-frame {
    width: min(100%, 900px);
    margin-inline: 0 auto;
  }
}

.mushaf-viewport {
  overflow: hidden;
  border-radius: 12px;
}

.mushaf-track {
  display: flex;
}

.mushaf-empty-page {
  min-height: min(58vh, 560px);
  display: grid;
  place-items: center;
  align-content: center;
  gap: 0.5rem;
  padding: 2rem;
  border: 1px dashed rgba(99, 102, 241, 0.24);
  border-radius: 8px;
  background: rgba(255, 255, 255, 0.58);
  color: var(--muted);
  text-align: center;
}

.mushaf-empty-page i {
  color: var(--accent);
  font-size: 1.6rem;
}

.mushaf-empty-page strong {
  color: var(--text);
  font-size: 0.95rem;
}

.mushaf-empty-page span {
  max-width: 32rem;
  font-size: 0.82rem;
  font-weight: 700;
}

.mushaf-page {
  position: relative;
  flex: 0 0 100%;
  isolation: isolate;
  min-height: min(74vh, 820px);
  display: grid;
  grid-template-rows: auto minmax(0, 1fr);
  gap: clamp(0.8rem, 1.7vh, 1.35rem);
  padding: clamp(2.7rem, 4vw, 4.5rem) clamp(1rem, 6vw, 5.25rem) clamp(1.5rem, 3vw, 3rem);
  border: 7px double var(--mushaf-border, rgba(150, 99, 52, 0.42));
  border-radius: 10px;
  background:
    linear-gradient(90deg, var(--mushaf-border-soft, rgba(150, 99, 52, 0.16)) 50%, transparent 0) 0 0 / 1.15rem 1.15rem,
    linear-gradient(0deg, var(--mushaf-border-soft, rgba(150, 99, 52, 0.16)) 50%, transparent 0) 0 0 / 1.15rem 1.15rem,
    var(--mushaf-bg, #f1ede8);
  color: var(--mushaf-text, #050505);
  box-shadow:
    inset 0 0 0 1px var(--mushaf-inner-border, rgba(255, 255, 255, 0.55)),
    inset 0 0 0 1.15rem color-mix(in srgb, var(--mushaf-bg, #f1ede8) 88%, transparent),
    0 18px 42px rgba(15, 23, 42, 0.12);
}

.mushaf-page::before,
.mushaf-page::after {
  content: "";
  position: absolute;
  z-index: -1;
  pointer-events: none;
}

.mushaf-page::before {
  inset: 1rem;
  border: 1px solid var(--mushaf-border, rgba(150, 99, 52, 0.34));
  border-radius: 6px;
}

.mushaf-page::after {
  inset: 1.35rem;
  border: 1px solid var(--mushaf-border-soft, rgba(150, 99, 52, 0.18));
  border-radius: 4px;
}

.mushaf-bg-warm {
  --mushaf-bg: #f1ede8;
  --mushaf-text: #050505;
  --mushaf-muted: #6f6258;
  --mushaf-hover: rgba(150, 99, 52, 0.09);
  --mushaf-border: rgba(137, 92, 49, 0.48);
  --mushaf-border-soft: rgba(137, 92, 49, 0.13);
  --mushaf-inner-border: rgba(255, 250, 243, 0.72);
}

.mushaf-bg-paper {
  --mushaf-bg: #fffaf0;
  --mushaf-text: #111827;
  --mushaf-muted: #6b5f4b;
  --mushaf-hover: rgba(180, 126, 42, 0.12);
  --mushaf-border: rgba(166, 119, 48, 0.46);
  --mushaf-border-soft: rgba(166, 119, 48, 0.12);
  --mushaf-inner-border: rgba(255, 255, 255, 0.76);
}

.mushaf-bg-contrast {
  --mushaf-bg: #ffffff;
  --mushaf-text: #000000;
  --mushaf-muted: #111827;
  --mushaf-hover: rgba(0, 0, 0, 0.07);
  --mushaf-border: rgba(17, 24, 39, 0.34);
  --mushaf-border-soft: rgba(17, 24, 39, 0.09);
  --mushaf-inner-border: rgba(255, 255, 255, 0.86);
}

.mushaf-bg-night {
  --mushaf-bg: #101317;
  --mushaf-text: #f8fafc;
  --mushaf-muted: #cbd5e1;
  --mushaf-hover: rgba(148, 163, 184, 0.16);
  --mushaf-border: rgba(211, 168, 96, 0.46);
  --mushaf-border-soft: rgba(211, 168, 96, 0.1);
  --mushaf-inner-border: rgba(248, 250, 252, 0.06);
}

.mushaf-sheet-tools {
  position: absolute;
  top: 0.75rem;
  right: 0.75rem;
  z-index: 5;
  display: inline-flex;
  align-items: center;
  gap: 0.18rem;
  padding: 0.18rem;
  border: 1px solid color-mix(in srgb, var(--mushaf-text) 14%, transparent);
  border-radius: 999px;
  background: color-mix(in srgb, var(--mushaf-bg) 84%, #ffffff 14%);
  box-shadow: 0 10px 24px rgba(15, 23, 42, 0.1);
  backdrop-filter: blur(12px);
}

.mushaf-sheet-tools button,
.mushaf-font-controls {
  color: var(--mushaf-text);
}

.mushaf-sheet-tools>button,
.mushaf-font-controls button {
  display: inline-grid;
  place-items: center;
  width: 1.48rem;
  height: 1.48rem;
  border: 0;
  border-radius: 999px;
  background: transparent;
  font-size: 0.68rem;
  transition: background 160ms ease, color 160ms ease, transform 160ms ease;
}

.mushaf-sheet-tools>button:hover,
.mushaf-font-controls button:hover {
  background: color-mix(in srgb, var(--mushaf-text) 10%, transparent);
}

.mushaf-sheet-tools>button:active,
.mushaf-font-controls button:active {
  transform: scale(0.94);
}

.mushaf-font-controls {
  display: inline-flex;
  align-items: center;
  gap: 0.3rem;
  padding-inline: 0.2rem;
  font-size: 0.68rem;
  font-weight: 900;
}

.mushaf-bg-picker {
  display: inline-flex;
  align-items: center;
  gap: 0.22rem;
  padding-inline: 0.1rem;
}

.mushaf-bg-swatch {
  width: 0.92rem !important;
  height: 0.92rem !important;
  border-radius: 999px !important;
  padding: 0 !important;
  border: 1px solid color-mix(in srgb, var(--mushaf-text) 16%, transparent) !important;
}

.mushaf-click-guide {
  position: absolute;
  top: 0.78rem;
  left: 0.85rem;
  z-index: 5;
  display: inline-flex;
  align-items: center;
  max-width: min(25rem, calc(100% - 18rem));
  gap: 0.42rem;
  padding: 0.34rem 0.58rem;
  border: 1px solid color-mix(in srgb, var(--mushaf-border, #895c31) 38%, transparent);
  border-radius: 999px;
  background: color-mix(in srgb, var(--mushaf-bg) 88%, #ffffff 12%);
  color: var(--mushaf-muted);
  box-shadow: 0 10px 22px rgba(15, 23, 42, 0.08);
  font-size: 0.72rem;
  font-weight: 800;
  line-height: 1.25;
  text-align: left;
  backdrop-filter: blur(12px);
}

.mushaf-click-guide i {
  color: var(--accent);
  font-size: 0.86rem;
}

.mushaf-bg-swatch.active {
  outline: 1.5px solid var(--accent);
  outline-offset: 1.5px;
}

.mushaf-bg-swatch-warm {
  background: #f1ede8 !important;
}

.mushaf-bg-swatch-paper {
  background: #fffaf0 !important;
}

.mushaf-bg-swatch-contrast {
  background: #fff !important;
}

.mushaf-bg-swatch-night {
  background: #101317 !important;
}

.mushaf-page-header {
  display: grid;
  justify-items: center;
  gap: clamp(0.65rem, 1.6vh, 1.2rem);
  color: var(--mushaf-text);
  text-align: center;
}

.mushaf-page-header h2 {
  margin: 0;
  color: var(--mushaf-text);
  font-family: "Amiri Quran", "Amiri", "Scheherazade New", serif;
  font-size: clamp(1.8rem, 3.8vw, 3.35rem);
  font-weight: 700;
  line-height: 1.2;
}

.mushaf-bismillah {
  color: var(--mushaf-text);
  font-family: "Amiri Quran", "Amiri", "Scheherazade New", serif;
  font-size: clamp(1.45rem, 3vw, 2.55rem);
  font-weight: 600;
  line-height: 1.45;
  letter-spacing: 0;
  text-align: center;
}

.mushaf-page-footer {
  min-height: 0;
  display: flex;
  justify-content: center;
  pointer-events: none;
}

.mushaf-page-body {
  display: block;
  direction: rtl;
  text-align: justify;
  text-align-last: center;
  line-height: 2.45;
  overflow: visible;
  padding: clamp(0.8rem, 2vh, 1.7rem) 0;
  -webkit-overflow-scrolling: touch;
  scrollbar-width: thin;
  font-variant-ligatures: contextual;
}

.mushaf-ayah {
  position: relative;
  display: inline;
  appearance: none;
  border: 0;
  border-radius: 6px;
  background: transparent;
  color: var(--mushaf-text);
  padding: 0;
  margin: 0 0.04em;
  text-align: right;
  white-space: normal;
  line-height: inherit;
  vertical-align: baseline;
  cursor: pointer;
  transition: background 180ms ease, box-shadow 180ms ease, filter 180ms ease, opacity 180ms ease;
}

.mushaf-ayah:hover,
.mushaf-ayah.active {
  background: transparent;
  box-shadow: none;
}

.mushaf-ayah:hover .mushaf-ayah-text,
.mushaf-ayah.active .mushaf-ayah-text {
  background: var(--mushaf-hover);
  box-shadow: 0 0 0 0.08em color-mix(in srgb, var(--mushaf-text) 10%, transparent);
  border-radius: 0.16em;
}

.mushaf-ayah.review-priority {
  box-shadow: inset 0 -2px 0 rgba(245, 158, 11, 0.48);
}

.mushaf-ayah-text {
  display: inline;
  color: var(--mushaf-text);
  font-size: calc((var(--verse-font-percent, 120) / 100) * clamp(1.45rem, 2.8vw, 2.85rem));
  font-weight: 500;
  letter-spacing: 0;
  line-height: inherit;
  white-space: normal;
  unicode-bidi: isolate;
}

.mushaf-ayah-text .wbw-word,
.mushaf-ayah-text word {
  display: inline !important;
  margin: 0;
  padding: 0;
  border-radius: 0.18em;
  color: inherit;
  font: inherit !important;
  font-size: 1em !important;
  font-weight: inherit !important;
  line-height: inherit;
  letter-spacing: inherit;
  white-space: normal;
  transform: none !important;
  vertical-align: baseline;
}

.mushaf-ayah-text .tajweed-mark,
.mushaf-ayah-text .wbw-word *,
.mushaf-ayah-text word * {
  font-size: 1em !important;
  line-height: inherit !important;
}

.mushaf-ayah-text .wbw-word.highlighted,
.mushaf-ayah-text word.highlighted {
  background: color-mix(in srgb, var(--accent) 22%, transparent);
  color: inherit !important;
  box-shadow: inset 0 -0.08em 0 var(--accent);
  transform: none !important;
}

.mushaf-ayah-text .word-audio-btn {
  display: none !important;
}

.mushaf-ayah-number {
  display: inline-grid;
  place-items: center;
  box-sizing: border-box;
  width: 1.9em;
  height: 1.9em;
  margin-inline: 0.16em 0.26em;
  border: 0.5px solid rgba(150, 99, 52, 0.58);
  padding: 0;
  border-radius: 50%;
  background:
    radial-gradient(circle at center, #eef0e6 48%, transparent 50%),
    conic-gradient(from 20deg, #b0175a, #6f8d61, #b0175a, #6f8d61, #b0175a);
  color: #111;
  direction: ltr;
  font-family: system-ui, sans-serif;
  font-size: clamp(0.68rem, 1.18vw, 0.94rem);
  font-variant-numeric: tabular-nums;
  font-weight: 900;
  line-height: 1;
  letter-spacing: 0;
  text-align: center;
  vertical-align: middle;
  transform: translateY(-0.08em);
}

.mushaf-ayah-number-digits-1 {
  width: 1.9em !important;
  height: 1.9em !important;
}

.mushaf-ayah-number-digits-2 {
  width: 2.35em !important;
  height: 2.35em !important;
}

.mushaf-ayah-number-digits-3 {
  width: 2.95em !important;
  height: 2.95em !important;
}

.mushaf-active-tools button,
.mushaf-nav-btn {
  display: inline-grid;
  place-items: center;
  width: 2.35rem;
  height: 2.35rem;
  border: 1px solid rgba(99, 102, 241, 0.2);
  border-radius: 999px;
  background: rgba(255, 255, 255, 0.9);
  color: var(--text);
}

.mushaf-nav-btn:disabled {
  cursor: not-allowed;
  opacity: 0.36;
}

.mushaf-hint {
  display: none;
  align-items: center;
  justify-content: center;
  gap: 0.45rem;
  color: var(--muted);
  font-size: 0.82rem;
  font-weight: 700;
  text-align: center;
}

.main.focus-mode-active .mushaf-ayah:not(.active) {
  opacity: var(--focus-dim-opacity, 0.54);
}

.main.blur-mode-active .mushaf-ayah.blur-upcoming .mushaf-ayah-text {
  filter: blur(var(--recall-blur, 10px));
  user-select: none;
}

.main.blur-mode-active .mushaf-ayah.blur-upcoming.peek-revealed .mushaf-ayah-text,
.main.blur-mode-active .mushaf-ayah.active .mushaf-ayah-text {
  filter: none;
  user-select: auto;
}

[data-theme="dark"] .view-mode-toggle,
[data-theme="dark"] .mushaf-empty-page,
[data-theme="dark"] .mushaf-active-tools button,
[data-theme="dark"] .mushaf-nav-btn {
  border-color: rgba(148, 163, 184, 0.18);
  background: rgba(15, 23, 42, 0.88);
}

[data-theme="dark"] .view-mode-toggle {
  --view-toggle-bg: #17120d;
  --view-toggle-border: #8d6a45;
  --view-toggle-text: #e9d7bd;
  --view-toggle-hover-bg: #2a2118;
  --view-toggle-active-bg: #f0c47b;
  --view-toggle-active-text: #1d1309;
  --view-toggle-active-shadow: rgba(240, 196, 123, 0.2);
  box-shadow: 0 10px 24px rgba(0, 0, 0, 0.24), inset 0 1px 0 rgba(255, 255, 255, 0.06);
}

[data-theme="dark"] .view-mode-btn {
  color: var(--view-toggle-text);
}

[data-theme="dark"] .view-mode-btn:hover {
  color: #fff4df !important;
  background: var(--view-toggle-hover-bg) !important;
}

[data-theme="dark"] .mushaf-page {
  box-shadow:
    inset 0 0 0 1px rgba(248, 250, 252, 0.06),
    inset 0 0 0 1.15rem rgba(16, 19, 23, 0.82),
    0 18px 45px rgba(0, 0, 0, 0.34);
}

[data-theme="dark"] .mushaf-sheet-tools,
[data-theme="dark"] .mushaf-click-guide {
  background: color-mix(in srgb, var(--mushaf-bg) 86%, #000000 14%);
  border-color: color-mix(in srgb, var(--mushaf-border, #d3a860) 45%, transparent);
  box-shadow: 0 12px 26px rgba(0, 0, 0, 0.28);
}

[data-theme="dark"] .mushaf-click-guide {
  color: #d8c7aa;
}

[data-theme="dark"] .mushaf-ayah-number {
  color: #0f172a;
  border-color: rgba(248, 250, 252, 0.32);
}

[data-theme="dark"] .mushaf-ayah:hover,
[data-theme="dark"] .mushaf-ayah.active {
  background: transparent;
  box-shadow: none;
}

[data-theme="dark"] .mushaf-ayah:hover .mushaf-ayah-text,
[data-theme="dark"] .mushaf-ayah.active .mushaf-ayah-text {
  background: rgba(240, 196, 123, 0.12);
  box-shadow: 0 0 0 0.08em rgba(240, 196, 123, 0.18);
}

@media (max-width: 720px) {
  .mushaf-frame {
    grid-template-columns: minmax(0, 1fr);
  }

  .mushaf-nav-btn {
    display: none;
  }

  .mushaf-page {
    min-height: 70vh;
    padding: 5.7rem 0.85rem 1.4rem;
  }

  .mushaf-sheet-tools {
    top: 0.75rem;
    right: 0.75rem;
    left: auto;
    justify-content: flex-end;
    flex-wrap: nowrap;
    border-radius: 999px;
  }

  .mushaf-click-guide {
    top: 3.45rem;
    right: 0.75rem;
    left: 0.75rem;
    max-width: none;
    justify-content: center;
    text-align: center;
    border-radius: 10px;
    font-size: 0.68rem;
  }

  .mushaf-page-body {
    line-height: 2.35;
  }

  .mushaf-page-header h2 {
    font-size: clamp(1.65rem, 9vw, 2.55rem);
  }

  .mushaf-bismillah {
    font-size: clamp(1.25rem, 6.5vw, 1.95rem);
  }

  .mushaf-ayah-text {
    font-size: calc((var(--verse-font-percent, 120) / 100) * clamp(1.32rem, 7vw, 2.05rem));
  }

  .view-mode-toggle {
    width: 100%;
  }

  .view-mode-btn {
    flex: 1 1 0;
    justify-content: center;
  }
}

.workspace-control-live {
  margin-top: 8px;
  padding: 8px 10px;
  border-radius: 10px;
  background: rgba(154, 103, 56, 0.08);
  display: flex;
  gap: 8px;
  align-items: center;
  flex-wrap: wrap;
}

.workspace-control-live-label {
  font-size: 0.7rem;
  font-weight: 700;
  text-transform: uppercase;
  color: var(--text-muted);
}

.workspace-control-live strong {
  font-size: 0.78rem;
  color: var(--text);
}

.workspace-applied-pills {
  margin-top: 8px;
  display: flex;
  gap: 6px;
  flex-wrap: wrap;
}

.workspace-applied-pill {
  display: inline-flex;
  align-items: center;
  min-height: 26px;
  padding: 3px 9px;
  border-radius: 999px;
  border: 1px solid rgba(160, 120, 76, 0.22);
  background: rgba(255, 255, 255, 0.72);
  font-size: 0.72rem;
  font-weight: 600;
  color: var(--text-muted);
}

.quick-font-dropdown,
.quick-font-dropdown .font-dropdown-trigger {
  width: auto;
  min-width: 0;
}

.quick-font-dropdown .font-dropdown-trigger {
  justify-content: space-between;
}

.setup-metric-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 10px;
  margin-top: 10px;
}

.setup-metric-card {
  border-radius: 14px;
  border: 1px solid var(--border);
  background: rgba(255, 255, 255, 0.42);
  padding: 10px 12px;
  display: grid;
  gap: 4px;
}

.setup-metric-card span {
  font-size: 0.72rem;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  color: var(--text-muted);
}

.setup-metric-card strong {
  font-size: 1.08rem;
  color: var(--text);
}

.setup-metric-card small {
  font-size: 0.74rem;
  line-height: 1.4;
  color: var(--text-muted);
}

.setup-metric-list {
  display: grid;
  gap: 6px;
  margin-top: 8px;
}

.setup-metric-list-row,
.setup-metric-list-empty {
  border-radius: 10px;
  background: rgba(154, 103, 56, 0.06);
  padding: 8px 10px;
  font-size: 0.76rem;
  color: var(--text-muted);
}

.setup-metric-list-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
}

.setup-metric-list-row strong {
  color: var(--text);
  font-size: 0.78rem;
}

.session-quickstart-card {
  display: flex;
  gap: 16px;
  justify-content: space-between;
  align-items: center;
  padding: 16px;
  border-radius: 18px;
  background: rgba(17, 24, 39, 0.04);
  border: 1px solid rgba(17, 24, 39, 0.08);
}

.session-quickstart-copy {
  margin: 6px 0 0;
  color: #5f6b7a;
}

.session-quickstart-actions {
  display: flex;
  flex-direction: column;
  align-items: flex-end;
  gap: 8px;
}

.preset-btn-primary {
  background: #0f766e;
  color: #fff;
}

.presets-grid-wide {
  width: 100%;
}

@media (max-width: 768px) {
  .tools-top {
    position: sticky;
    top: 0;
    z-index: 3;
    backdrop-filter: blur(16px);
    background: rgba(250, 245, 238, 0.94);
  }

  [data-theme="dark"] .tools-top {
    background: rgba(18, 16, 13, 0.94);
  }

  .tools-topbar {
    align-items: flex-start;
  }

  .action-buttons-group {
    width: 100%;
    display: grid;
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 8px;
  }

  .action-btn,
  .action-icon-btn {
    width: 100%;
    min-width: 0;
  }

  .action-btn-primary,
  .action-btn-exit {
    grid-column: 1 / -1;
  }

  .workspace-quick-controls {
    padding: 0;
  }

  .quick-pill-group-list .toolbar-chip {
    flex: 1 1 calc(50% - 6px);
    min-height: 34px;
  }

  .workspace-quick-controls .toolbar-chip,
  .quick-right-controls,
  .quick-font-dropdown,
  .quick-font-dropdown .font-dropdown-trigger {
    width: 100%;
    min-width: 0;
  }

  .quick-right-controls {
    justify-content: flex-start;
  }

  .session-quickstart-card {
    flex-direction: column;
    align-items: stretch;
  }

  .session-quickstart-actions {
    align-items: stretch;
  }
}

.workspace-shell {
  transition: box-shadow 0.2s ease, border-color 0.2s ease;
}

.workspace-shell:has(.action-btn-exit) {
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.08);
  border-color: rgba(165, 126, 84, 0.28);
}

.workspace-shell-meta {
  padding: 0 10px 8px;
}

.workspace-shell-meta>span {
  display: inline-flex;
  align-items: center;
  min-height: 26px;
}

.main,
.content,
.workspace,
.workspace-main {
  overflow-x: clip;
}

.content {
  transition: padding-right 220ms ease;
}

[data-theme="dark"] .workspace-control-live,
[data-theme="dark"] .workspace-applied-pill {
  background: rgba(255, 247, 236, 0.055);
  border-color: rgba(255, 236, 216, 0.14);
  color: var(--text);
}

[data-theme="dark"] .quick-font-dropdown .font-dropdown-trigger,
[data-theme="dark"] .setup-metric-card {
  background: rgba(255, 247, 236, 0.055);
  border-color: rgba(255, 236, 216, 0.14);
  color: var(--text);
}

[data-theme="dark"] .setup-metric-list-row,
[data-theme="dark"] .setup-metric-list-empty,
[data-theme="dark"] .analytics-progress-stat,
[data-theme="dark"] .analytics-heatmap-cell,
[data-theme="dark"] .workspace-shell-compact-meta span {
  background: rgba(255, 247, 236, 0.045);
  border-color: rgba(255, 236, 216, 0.14);
  color: var(--text-muted);
}

[data-theme="light"] .quick-font-dropdown .font-dropdown-trigger,
[data-theme="sepia"] .quick-font-dropdown .font-dropdown-trigger,
[data-theme="light"] .setup-metric-card,
[data-theme="sepia"] .setup-metric-card {
  background: rgba(255, 255, 255, 0.72);
  border-color: rgba(160, 120, 76, 0.16);
  color: var(--text-muted);
}

[data-theme="light"] .setup-metric-list-row,
[data-theme="light"] .setup-metric-list-empty,
[data-theme="light"] .analytics-progress-stat,
[data-theme="light"] .analytics-heatmap-cell,
[data-theme="light"] .workspace-shell-compact-meta span,
[data-theme="sepia"] .setup-metric-list-row,
[data-theme="sepia"] .setup-metric-list-empty,
[data-theme="sepia"] .analytics-progress-stat,
[data-theme="sepia"] .analytics-heatmap-cell,
[data-theme="sepia"] .workspace-shell-compact-meta span {
  background: rgba(154, 103, 56, 0.08);
  color: var(--text-muted);
}

[data-theme="dark"] .session-analytics-panel,
[data-theme="dark"] .session-analytics-summary-card {
  background: rgba(40, 34, 30, 0.74);
  border-color: rgba(216, 185, 150, 0.14);
}

[data-theme="dark"] .workspace-shell {
  background:
    linear-gradient(180deg, rgba(34, 29, 26, 0.98), rgba(24, 20, 18, 0.96)),
    radial-gradient(circle at top right, rgba(208, 160, 107, 0.1), transparent 28%);
}

[data-theme="dark"] .stats-full-analytics-btn {
  color: #1a140f;
  background: linear-gradient(135deg, #d0a06b, #b98654);
  box-shadow: 0 14px 30px rgba(0, 0, 0, 0.36);
}

[data-theme="light"] .stats-full-analytics-btn,
[data-theme="sepia"] .stats-full-analytics-btn {
  color: #fff;
  background: linear-gradient(135deg, var(--accent), var(--accent-strong));
  box-shadow: 0 12px 24px rgba(112, 78, 43, 0.18);
}

[data-theme="light"] .post-onboarding-modal,
[data-theme="sepia"] .post-onboarding-modal {
  --onboarding-bg: linear-gradient(180deg, rgba(255, 255, 255, 0.98), rgba(250, 245, 238, 0.96));
  --onboarding-border: rgba(160, 120, 76, 0.16);
  --onboarding-text: var(--text);
  --onboarding-muted: var(--text-muted);
  --onboarding-kicker-bg: rgba(139, 90, 44, 0.12);
  --onboarding-kicker-text: #8b5a2c;
  --onboarding-panel-bg:
    radial-gradient(circle at 12% 10%, rgba(112, 78, 43, 0.12), transparent 38%),
    rgba(255, 248, 239, 0.72);
  --onboarding-panel-border: rgba(160, 120, 76, 0.16);
  --onboarding-panel-text: var(--text-muted);
  --onboarding-preview-title: var(--text);
  --onboarding-preview-subtitle: var(--text-muted);
  --onboarding-preview-icon-bg: var(--accent-light);
  --onboarding-preview-icon: var(--accent-strong);
  --onboarding-progress-idle: color-mix(in srgb, var(--accent) 24%, transparent);
  --onboarding-progress-active: var(--accent);
}

[data-theme="light"] .post-onboarding-header,
[data-theme="sepia"] .post-onboarding-header,
[data-theme="light"] .post-onboarding-footer,
[data-theme="sepia"] .post-onboarding-footer {
  border-color: var(--onboarding-border);
}

[data-theme="light"] .post-onboarding-header h2,
[data-theme="sepia"] .post-onboarding-header h2 {
  color: var(--onboarding-text);
}

[data-theme="light"] .post-onboarding-body p,
[data-theme="sepia"] .post-onboarding-body p,
[data-theme="light"] .post-onboarding-points,
[data-theme="sepia"] .post-onboarding-points {
  color: var(--onboarding-muted);
}

[data-theme="light"] .post-onboarding-preview,
[data-theme="sepia"] .post-onboarding-preview {
  background: var(--onboarding-panel-bg);
  border-color: var(--onboarding-panel-border);
}

[data-theme="light"] .post-onboarding-preview-icon,
[data-theme="sepia"] .post-onboarding-preview-icon,
[data-theme="light"] .post-onboarding-preview-grid span,
[data-theme="sepia"] .post-onboarding-preview-grid span {
  background: var(--onboarding-preview-icon-bg);
  border-color: var(--onboarding-panel-border);
  color: var(--onboarding-preview-icon);
}

[data-theme="light"] .post-onboarding-preview-head strong,
[data-theme="sepia"] .post-onboarding-preview-head strong {
  color: var(--onboarding-preview-title);
}

[data-theme="light"] .post-onboarding-preview-head small,
[data-theme="sepia"] .post-onboarding-preview-head small {
  color: var(--onboarding-preview-subtitle);
}

[data-theme="light"] .session-analytics-summary-card,
[data-theme="light"] .session-analytics-chart-card,
[data-theme="light"] .comparison-item,
[data-theme="sepia"] .session-analytics-summary-card,
[data-theme="sepia"] .session-analytics-chart-card,
[data-theme="sepia"] .comparison-item {
  background: rgba(255, 255, 255, 0.72);
  border-color: rgba(160, 120, 76, 0.14);
}

.action-buttons-group {
  flex-wrap: wrap;
  justify-content: flex-end;
}

.action-btn-recordings {
  min-width: 188px;
}

.recordings-library-modal {
  width: min(1180px, calc(100vw - 28px));
  max-height: calc(100dvh - 20px);
  height: auto;
}

.recordings-library-header {
  align-items: flex-start;
  padding-top: 14px;
  padding-bottom: 14px;
}

.recordings-library-header-actions {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  margin-left: auto;
}

.recordings-library-back-btn {
  min-height: 38px;
  padding: 0 12px;
  border-radius: 12px;
  border: 1px solid rgba(154, 103, 56, 0.16);
  background: rgba(255, 255, 255, 0.76);
  color: var(--text);
  display: inline-flex;
  align-items: center;
  gap: 8px;
  font-size: 0.78rem;
  font-weight: 700;
  cursor: pointer;
}

.recordings-library-back-btn:hover {
  background: var(--accent-light);
  border-color: rgba(154, 103, 56, 0.28);
  color: var(--accent);
}

.recordings-library-head-copy {
  display: grid;
  gap: 6px;
}

.recordings-library-hierarchy,
.recordings-library-nav-meta,
.recordings-library-detail-meta {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  align-items: center;
}

.recordings-library-hierarchy span,
.recordings-library-nav-meta span,
.recordings-library-detail-meta span {
  display: inline-flex;
  align-items: center;
  min-height: 24px;
  padding: 0 8px;
  border-radius: 999px;
  border: 1px solid rgba(154, 103, 56, 0.16);
  background: rgba(255, 255, 255, 0.72);
  color: var(--text-muted);
  font-size: 0.72rem;
  font-weight: 600;
}

[data-theme="dark"] .recordings-library-hierarchy span,
[data-theme="dark"] .recordings-library-nav-meta span,
[data-theme="dark"] .recordings-library-detail-meta span {
  background: rgba(255, 247, 236, 0.08);
  border-color: rgba(255, 236, 216, 0.18);
  color: var(--text);
}

.recordings-library-head-copy p {
  margin: 0;
  color: var(--text-muted);
  font-size: 0.88rem;
  line-height: 1.5;
}

.recordings-library-body {
  padding: 14px 18px 18px;
}

.recordings-library-loading,
.recordings-library-empty {
  min-height: 360px;
  display: grid;
  place-items: center;
  text-align: center;
  gap: 12px;
  color: var(--text-muted);
}

.recordings-library-empty h3 {
  margin: 0;
  color: var(--text);
  font-size: 1.2rem;
}

.recordings-library-empty p {
  margin: 0;
  max-width: 420px;
  line-height: 1.6;
}

.recordings-library-empty-icon {
  width: 72px;
  height: 72px;
  border-radius: 24px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-size: 1.8rem;
  color: var(--accent);
  background: rgba(154, 103, 56, 0.08);
  border: 1px solid rgba(154, 103, 56, 0.16);
}

.recordings-library-shell {
  display: grid;
  grid-template-columns: minmax(232px, 260px) minmax(0, 1fr);
  gap: 16px;
  min-height: 0;
}

.recordings-library-nav,
.recordings-library-detail {
  border: 1px solid var(--border);
  border-radius: 14px;
  background: rgba(255, 255, 255, 0.68);
  min-height: 0;
}

.recordings-library-nav {
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

.recordings-library-nav-head {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 12px;
  padding: 12px;
  border-bottom: 1px solid rgba(154, 103, 56, 0.08);
}

.recordings-library-nav-head>div:first-child {
  flex: 1;
  min-width: 0;
}

.recordings-library-nav-kicker,
.recordings-library-detail-kicker {
  display: block;
  margin-bottom: 4px;
  font-size: 0.72rem;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--text-muted);
}

.recordings-library-nav-head strong,
.recordings-library-detail-count {
  color: var(--text);
  font-size: 0.92rem;
  font-weight: 650;
}

.recordings-library-detail-count {
  width: 34px;
  height: 34px;
  border-radius: 999px;
  border: 1px solid rgba(154, 103, 56, 0.12);
  background: rgba(255, 255, 255, 0.6);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-size: 0.82rem;
}

.recordings-library-nav-toggle {
  display: none;
  align-items: center;
  gap: 8px;
  border: 1px solid var(--border);
  border-radius: 12px;
  background: rgba(255, 255, 255, 0.72);
  color: var(--text);
  padding: 9px 12px;
  font-size: 0.78rem;
  font-weight: 600;
  cursor: pointer;
}

.recordings-library-search {
  padding: 10px 12px;
  display: grid;
  gap: 8px;
}

.recordings-library-search-field {
  position: relative;
}

.recordings-library-search-hint {
  margin: 0;
  padding-left: 2px;
}

.recordings-library-ayah-translation {
  margin: 8px 0 0;
  max-width: 38rem;
  color: var(--text-muted);
  font-size: 0.84rem;
  line-height: 1.6;
  font-style: italic;
}

.recordings-library-search i {
  position: absolute;
  left: 14px;
  top: 50%;
  transform: translateY(-50%);
  color: var(--text-muted);
  pointer-events: none;
}

.recordings-library-search input {
  width: 100%;
  min-height: 42px;
  border-radius: 12px;
  border: 1px solid var(--border);
  background: rgba(255, 255, 255, 0.72);
  color: var(--text);
  padding: 0 14px 0 40px;
  font-size: 0.88rem;
}

.recordings-library-search input:focus {
  outline: none;
  border-color: rgba(154, 103, 56, 0.32);
  box-shadow: 0 0 0 3px rgba(154, 103, 56, 0.08);
}

.recordings-library-nav-scroll {
  flex: 1;
  overflow-y: auto;
  padding: 0 8px 12px 12px;
}

.recordings-library-surah-group {
  display: grid;
  gap: 6px;
  padding: 8px 0 10px;
}

.recordings-library-surah-group+.recordings-library-surah-group {
  border-top: 1px solid rgba(154, 103, 56, 0.08);
}

.recordings-library-surah-title {
  font-size: 0.88rem;
  font-weight: 700;
  color: var(--text);
}

.recordings-library-ayah-group {
  display: grid;
  gap: 6px;
}

.recordings-library-ayah-item {
  width: 100%;
  border: 1px solid transparent;
  border-radius: 12px;
  background: rgba(154, 103, 56, 0.05);
  padding: 9px 11px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  text-align: left;
  cursor: pointer;
  transition: background 0.2s ease, border-color 0.2s ease, transform 0.2s ease;
}

.recordings-library-ayah-item:hover {
  transform: translateY(-1px);
  border-color: rgba(154, 103, 56, 0.18);
  background: rgba(154, 103, 56, 0.09);
}

.recordings-library-ayah-item.active {
  border-color: rgba(154, 103, 56, 0.5);
  background: linear-gradient(135deg, rgba(154, 103, 56, 0.28), rgba(154, 103, 56, 0.18));
  box-shadow: 0 10px 24px rgba(154, 103, 56, 0.2);
}

.recordings-library-ayah-label {
  color: var(--text);
  font-size: 0.88rem;
  font-weight: 600;
}

.recordings-library-ayah-count {
  color: var(--text-muted);
  font-size: 0.76rem;
  white-space: nowrap;
}

.recordings-library-recordings {
  display: grid;
  gap: 6px;
  margin: 0 0 6px 12px;
  padding-left: 10px;
  border-left: 2px solid rgba(154, 103, 56, 0.12);
}

.recordings-library-recording-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
  padding: 9px 10px;
  border-radius: 10px;
  border: 1px solid rgba(154, 103, 56, 0.12);
  background: rgba(255, 255, 255, 0.82);
  animation: recordingsSlideIn 180ms ease;
}

.recordings-library-recording-item.playing {
  border-color: rgba(154, 103, 56, 0.4);
  box-shadow: 0 14px 26px rgba(154, 103, 56, 0.18);
}

.recordings-library-recording-copy {
  display: grid;
  gap: 2px;
  min-width: 0;
}

.recordings-library-recording-copy strong {
  color: var(--text);
  font-size: 0.8rem;
}

.recordings-library-recording-copy span {
  color: var(--text-muted);
  font-size: 0.7rem;
}

.recordings-library-ai-score {
  min-width: 44px;
  padding: 5px 9px;
  border-radius: 999px;
  text-align: center;
  font-size: 0.76rem;
  font-weight: 700;
}

.recordings-library-ai-score.tone-excellent,
.recording-result-pill-ai.tone-excellent {
  background: rgba(66, 145, 96, 0.14);
  color: #2f7a4d;
}

.recordings-library-ai-score.tone-good,
.recording-result-pill-ai.tone-good {
  background: rgba(176, 126, 50, 0.16);
  color: #7b5223;
}

.recordings-library-ai-score.tone-review,
.recording-result-pill-ai.tone-review {
  background: rgba(180, 87, 61, 0.14);
  color: #994833;
}

.recording-history-ai-detail {
  display: grid;
  gap: 10px;
  margin-top: 4px;
  padding: 12px;
  border: 1px solid rgba(154, 103, 56, 0.12);
  border-radius: 12px;
  background: rgba(154, 103, 56, 0.045);
}

.recording-history-ai-detail p {
  margin: 0;
  color: var(--text);
  font-weight: 560;
}

.recording-history-ai-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 8px;
}

.recording-history-ai-grid span {
  display: grid;
  gap: 4px;
  min-width: 0;
  padding: 9px;
  border-radius: 10px;
  background: rgba(255, 255, 255, 0.62);
  color: var(--text-muted);
  font-size: 0.82rem;
}

.recording-history-ai-grid strong {
  color: var(--text);
  font-size: 0.76rem;
  font-weight: 650;
}

.recording-history-ai-transcript summary {
  cursor: pointer;
  color: var(--text-muted);
  font-weight: 600;
}

.recording-history-ai-transcript p {
  margin-top: 8px;
  text-align: right;
  font-size: 1.05rem;
  line-height: 1.8;
}

[data-theme="dark"] .recordings-library-search input,
[data-theme="dark"] .recordings-library-nav-toggle,
[data-theme="dark"] .recordings-library-ayah-item {
  background: rgba(255, 247, 236, 0.08);
  border-color: rgba(255, 236, 216, 0.2);
  color: var(--text);
}

[data-theme="dark"] .recordings-library-ayah-item.active {
  background: linear-gradient(135deg, rgba(208, 160, 107, 0.28), rgba(255, 255, 255, 0.06));
  border-color: rgba(208, 160, 107, 0.42);
  box-shadow: 0 12px 26px rgba(0, 0, 0, 0.24);
}

[data-theme="dark"] .recordings-library-recording-item {
  background: rgba(255, 247, 236, 0.08);
  border-color: rgba(255, 236, 216, 0.18);
}

[data-theme="dark"] .recordings-library-ai-score.tone-excellent,
[data-theme="dark"] .recording-result-pill-ai.tone-excellent {
  background: rgba(90, 190, 128, 0.16);
  color: #9ce0b0;
}

[data-theme="dark"] .recordings-library-ai-score.tone-good,
[data-theme="dark"] .recording-result-pill-ai.tone-good {
  background: rgba(224, 171, 87, 0.16);
  color: #f0d19b;
}

[data-theme="dark"] .recordings-library-ai-score.tone-review,
[data-theme="dark"] .recording-result-pill-ai.tone-review {
  background: rgba(232, 120, 89, 0.16);
  color: #f1ad9a;
}

[data-theme="dark"] .recording-history-ai-detail {
  border-color: rgba(255, 236, 216, 0.16);
  background: rgba(255, 247, 236, 0.055);
}

[data-theme="dark"] .recording-history-ai-grid span {
  background: rgba(255, 255, 255, 0.045);
}

[data-theme="dark"] .recordings-library-recording-item.playing {
  border-color: rgba(208, 160, 107, 0.38);
  box-shadow: 0 14px 26px rgba(0, 0, 0, 0.26);
}

@keyframes recordingsSlideIn {
  from {
    opacity: 0;
    transform: translateY(6px);
  }

  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.recordings-group-expand-enter-active,
.recordings-group-expand-leave-active {
  overflow: hidden;
  transition: opacity 0.18s ease, transform 0.18s ease, max-height 0.22s ease;
}

.recordings-group-expand-enter-from,
.recordings-group-expand-leave-to {
  opacity: 0;
  transform: translateY(-4px);
  max-height: 0;
}

.recordings-library-detail {
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

.recordings-library-detail-head {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 14px;
  padding: 12px 14px 10px;
  border-bottom: 1px solid rgba(154, 103, 56, 0.08);
}

.recordings-library-detail-head>div:first-child {
  flex: 1;
  min-width: 0;
}

.recordings-library-detail-head h3 {
  margin: 0;
  color: var(--text);
  font-size: 1rem;
}

.recordings-library-history {
  flex: 1;
  overflow-y: auto;
  padding: 12px 14px 16px;
  display: grid;
  gap: 10px;
  align-content: start;
  align-items: start;
}

.recording-history-card {
  border: 1px solid rgba(154, 103, 56, 0.12);
  border-radius: 12px;
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.9), rgba(253, 249, 244, 0.82));
  padding: 14px;
  display: grid;
  gap: 9px;
  min-height: 0;
  transition: border-color 0.2s ease, box-shadow 0.2s ease, transform 0.2s ease;
}

.recording-history-card.playing {
  border-color: rgba(154, 103, 56, 0.3);
  box-shadow: 0 14px 30px rgba(154, 103, 56, 0.12);
  transform: translateY(-1px);
}

.recording-history-top,
.recording-history-actions,
.recording-delete-confirm,
.recording-delete-confirm-actions,
.recording-history-meta {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
}

.recording-history-top {
  align-items: flex-start;
}

.recording-history-copy {
  display: grid;
  gap: 3px;
  flex: 1;
  min-width: 0;
}

.recording-history-kicker {
  color: var(--text);
  font-size: 0.92rem;
  font-weight: 700;
}

.recording-history-note {
  margin-top: 0;
}

.recording-history-copy strong {
  color: var(--text);
  font-size: 0.96rem;
}

.recording-history-copy span,
.recording-history-meta span {
  color: var(--text-muted);
  font-size: 0.8rem;
}

.recording-history-meta {
  justify-content: flex-start;
  flex-wrap: wrap;
  gap: 12px;
}

.recording-history-actions {
  justify-content: flex-start;
  flex-wrap: wrap;
  gap: 10px;
  padding-top: 2px;
}

.recording-history-meta span {
  display: inline-flex;
  align-items: center;
  gap: 6px;
}

.recording-history-action {
  min-width: 92px;
  width: auto;
  padding: 0 12px;
  gap: 8px;
}

.recording-history-action-delete {
  color: #8b4f39;
}

.recording-history-action span {
  font-size: 0.76rem;
  font-weight: 600;
}

.recording-result-pill {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-height: 26px;
  padding: 0 8px;
  border-radius: 999px;
  border: 1px solid transparent;
  font-size: 0.68rem;
  font-weight: 700;
  letter-spacing: 0.03em;
  white-space: nowrap;
}

.recording-result-pill.tone-excellent {
  background: #dceee1;
  border-color: rgba(47, 114, 72, 0.3);
  color: #1d5b33;
}

.recording-result-pill.tone-good {
  background: #f0dfc4;
  border-color: rgba(166, 121, 72, 0.32);
  color: #6d461c;
}

.recording-result-pill.tone-review {
  background: #f1d7ce;
  border-color: rgba(187, 103, 46, 0.34);
  color: #8a3e24;
}

.recording-delete-confirm {
  border-top: 1px solid rgba(154, 103, 56, 0.08);
  padding-top: 12px;
  flex-wrap: wrap;
}

.recording-delete-confirm span {
  color: var(--text);
  font-size: 0.82rem;
  font-weight: 600;
}

.recording-delete-confirm-actions {
  justify-content: flex-end;
}

.recording-inline-btn {
  min-height: 38px;
  padding: 9px 14px;
  flex: initial;
}

.recordings-library-empty-panel {
  flex: 1;
  min-height: 280px;
}

[data-theme="dark"] .recordings-library-nav,
[data-theme="dark"] .recordings-library-detail,
[data-theme="dark"] .recording-history-card {
  background: rgba(40, 34, 30, 0.76);
  border-color: rgba(216, 185, 150, 0.14);
}

[data-theme="dark"] .self-check-modal,
[data-theme="dark"] .self-check-modal-stage,
