@keyframes reciteCheckBorder {
  0% {
    filter: hue-rotate(0deg);
    transform: scale(1);
  }
  50% {
    opacity: 0.95;
    transform: scale(1.015);
  }
  100% {
    filter: hue-rotate(18deg);
    transform: scale(1);
  }
}

