  z-index: -1;
  border-radius: inherit;
  background: linear-gradient(90deg, rgba(37, 95, 77, 0.12), rgba(37, 95, 77, 0.58), rgba(37, 95, 77, 0.12));
  opacity: 0.75;
  animation: reciteCheckBorder 2.4s linear infinite;
}

.mushaf-ai-button.active {
  color: #fff;
  background: linear-gradient(180deg, #255f4d, #1e4f40);
  border-color: #255f4d;
}

.mushaf-ai-button i {
  font-size: 0.95rem;
}

.mushaf-ai-button span {
  white-space: nowrap;
}

.mushaf-sheet-tools-global > button,
.mushaf-sheet-tools-global .mushaf-font-controls button {
  width: 44px;
  height: 44px;
  border-radius: 14px;
}

.mushaf-sheet-tools-global .mushaf-bg-swatch {
  width: 42px !important;
  height: 42px !important;
}

.mushaf-page {
  min-height: min(78vh, 900px);
  /* padding-inline: clamp(2.2rem, 6.5vw, 6.5rem); */
}

.mushaf-ayah-text {
  font-size: calc((var(--verse-font-percent, 120) / 100) * clamp(1.45rem, 2.8vw, 2.85rem));
}

.self-check-idle-actions {
  justify-content: flex-start;
  grid-template-columns: minmax(180px, 260px) minmax(180px, 260px);
  gap: 12px;
}

.self-check-idle-actions .self-check-action-btn {
  min-height: 52px;
  justify-content: center;
  font-weight: 560;
}

.self-check-modal-quick-actions {
  display: flex;
  justify-content: flex-start;
  align-items: center;
  gap: 12px;
  margin: 0 0 14px;
}

.self-check-modal-quick-actions .self-check-action-btn {
  min-height: 52px;
  padding-inline: 16px;
  font-weight: 560;
}

.self-check-modal-quick-actions .self-check-action-btn span {
  white-space: nowrap;
}

.mushaf-border-picker {
  display: none !important;
}

.recitation-check-panel-inline {
  padding: 18px;
}

.recitation-result-stats {
  gap: 10px;
}

.recitation-result-stat {
  min-height: 116px;
  padding: 14px 16px;
}

.recitation-result-stat span,
.recitation-next-card span,
.recording-history-kicker,
.self-check-kicker,
.recitation-check-kicker {
  font-weight: 560;
  letter-spacing: 0.04em;
}

.recitation-result-stat strong,
.recording-history-kicker,
.self-check-attempt-copy strong,
.recitation-check-head h2 {
  font-weight: 560;
}

.recitation-next-card {
  padding: 16px 18px;
}

.recitation-next-card strong {
  font-size: 0.95rem;
  font-weight: 560;
}

.recitation-next-card p {
  font-weight: 400;
}

.recitation-review-ayah {
  padding: 18px 20px;
  border: 1px solid rgba(154, 103, 56, 0.12);
  border-radius: 10px;
  color: var(--text);
  font-family: "Uthmanic Hafs", "Amiri Quran", "Scheherazade New", serif;
  font-size: clamp(1.35rem, 2.8vw, 2.35rem);
  font-weight: 400;
  line-height: 2.05;
  text-align: center;
}

.recitation-review-ayah .wbw-word,
.recitation-review-ayah word {
  display: inline !important;
  margin-inline: 0.04em;
  padding: 0.02em 0.1em 0.05em;
  border-radius: 0.18em;
  font: inherit !important;
  transition: color 160ms ease, background 160ms ease, box-shadow 160ms ease;
}

.recitation-review-ayah .recitation-word-pending {
  color: color-mix(in srgb, var(--text) 58%, transparent);
  opacity: 0.62;
}

.recitation-review-ayah .recitation-word-correct {
  color: #138a4c;
  background: rgba(19, 138, 76, 0.13);
  box-shadow: inset 0 -0.12em 0 rgba(19, 138, 76, 0.3);
}

.recitation-review-ayah .recitation-word-partial {
  color: #b06a00;
  background: rgba(176, 106, 0, 0.14);
  box-shadow: inset 0 -0.12em 0 rgba(176, 106, 0, 0.32);
}

.recitation-review-ayah .recitation-word-incorrect {
  color: #a93226;
  background: rgba(169, 50, 38, 0.13);
  box-shadow: inset 0 -0.12em 0 rgba(169, 50, 38, 0.32);
}

.recordings-library-modal {
  width: min(1240px, calc(100vw - 42px));
}

.recordings-library-history {
  gap: 12px;
}

.recording-history-card {
  padding: 14px 16px;
}

.recording-history-copy span,
.recording-history-note,
.recording-history-meta span {
  font-weight: 400;
}

.recording-history-ai-detail {
  margin-top: 12px;
  display: grid;
  gap: 12px;
}

.recording-history-ai-detail .recitation-result-stat {
  min-height: 98px;
}

.recording-history-ai-detail .recitation-review-ayah {
  font-size: clamp(1.5rem, 3vw, 2.5rem);
  line-height: 1.9;
  padding: 14px 16px;
}

@media (max-width: 680px) {
  .self-check-ayah-actions {
    transform: scale(0.92);
    transform-origin: right bottom;
  }

  .recordings-library-shell {
    grid-template-columns: 1fr;
  }

  .mushaf-frame {
    max-width: calc(100vw - 20px);
  }

  .mushaf-sheet-tools-global {
    flex-wrap: wrap;
    justify-content: center;
  }

  .mushaf-ayah-text {
    font-size: calc((var(--verse-font-percent, 120) / 100) * clamp(1.35rem, 6.8vw, 2.1rem));
  }

  .self-check-idle-actions {
    grid-template-columns: 1fr;
  }
}

.memorisation-checker-modal {
  width: min(1120px, calc(100vw - 28px));
  height: min(92vh, 900px);
  display: flex;
  flex-direction: column;
  background: #fbf7ef;
  color: #1f241f;
  border: 1px solid rgba(92, 70, 46, 0.18);
}

.memorisation-checker-header {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto auto;
  align-items: center;
  gap: 12px;
  padding: 16px 18px;
  background: rgba(255, 252, 247, 0.92);
}

.memorisation-checker-header-actions {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  gap: 10px;
  min-width: 0;
}

.memorisation-checker-start-btn {
  min-height: 44px;
  min-width: 152px;
  justify-content: center;
  border-radius: 8px;
}

.memorisation-checker-body {
  flex: 1 1 auto;
  min-height: 0;
  display: grid;
  grid-template-rows: minmax(280px, 1fr) minmax(240px, 42%);
  gap: 12px;
  padding: 12px;
  overflow: hidden;
}

.memorisation-checker-workspace,
.memorisation-checker-ayah-panel {
  min-width: 0;
  min-height: 0;
  border-radius: 8px;
  border: 1px solid rgba(92, 70, 46, 0.14);
  background: rgba(255, 255, 255, 0.72);
  box-shadow: none;
}

.memorisation-checker-workspace {
  display: grid;
  grid-template-rows: auto minmax(0, 1fr) auto;
  gap: 12px;
  padding: 14px;
  overflow: auto;
}

.memorisation-checker-ayah-panel {
  display: grid;
  grid-template-rows: auto auto minmax(0, 1fr);
  gap: 10px;
  padding: 14px;
  overflow: hidden;
}

.memorisation-checker-section-head {
  display: grid;
  gap: 3px;
}

.memorisation-checker-section-head span {
  color: #2f6f58;
  font-size: 0.72rem;
  font-weight: 700;
  letter-spacing: 0.06em;
  text-transform: uppercase;
}

.memorisation-checker-section-head strong {
  color: #1f241f;
  font-size: 1rem;
  font-weight: 650;
}

.memorisation-checker-live {
  min-height: 0;
  display: grid;
  grid-template-rows: auto minmax(170px, 1fr) auto auto;
  gap: 10px;
}

.memorisation-checker-word-stream.recitation-word-stream {
  display: flex !important;
  flex-wrap: wrap;
  align-content: flex-start;
  justify-content: center;
  gap: 10px;
  min-height: 190px;
  max-height: none;
  padding: 18px;
  overflow: auto;
  border: 1px solid rgba(92, 70, 46, 0.12);
  border-radius: 8px;
  background: #fffaf3;
}

.memorisation-checker-word-stream .recitation-word-chip {
  display: inline-flex !important;
  align-items: center;
  justify-content: center;
  min-height: 42px;
  padding: 5px 12px 7px;
  border-radius: 8px;
  font-family: "Uthmanic Hafs", "Amiri Quran", "Scheherazade New", serif;
  font-size: clamp(1.3rem, 2.5vw, 2.15rem);
  line-height: 1.35;
}

.memorisation-checker-live-placeholder {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 100%;
  min-height: 120px;
  color: rgba(31, 36, 31, 0.48);
  font-size: 0.92rem;
}

.memorisation-checker-final-words.recitation-word-stream {
  min-height: auto;
  padding: 12px;
  gap: 7px;
  background: rgba(255, 250, 243, 0.72);
}

.memorisation-checker-final-words .recitation-word-chip {
  min-height: 32px;
  padding: 3px 9px 5px;
  font-size: clamp(1.05rem, 1.8vw, 1.55rem);
}

.memorisation-checker-ayah-actions {
  justify-self: end;
  margin: 0;
  max-width: 100%;
  overflow-x: auto;
  box-shadow: none;
}

.memorisation-checker-ayah {
  min-height: 0;
  overflow: auto;
  border-radius: 8px;
  background: #fffaf3;
  color: #1f241f;
  font-size: clamp(1.55rem, 3vw, 2.45rem) !important;
}

[data-theme="dark"] .memorisation-checker-modal {
  background: #121514;
  color: #f4efe6;
  border-color: rgba(244, 239, 230, 0.14);
}

[data-theme="dark"] .memorisation-checker-header,
[data-theme="dark"] .memorisation-checker-workspace,
[data-theme="dark"] .memorisation-checker-ayah-panel {
  background: #191d1b;
  border-color: rgba(244, 239, 230, 0.12);
}

[data-theme="dark"] .memorisation-checker-section-head strong,
[data-theme="dark"] .memorisation-checker-ayah {
  color: #f4efe6;
}

[data-theme="dark"] .memorisation-checker-section-head span {
  color: #8fd2ac;
}

[data-theme="dark"] .memorisation-checker-word-stream.recitation-word-stream,
[data-theme="dark"] .memorisation-checker-final-words.recitation-word-stream,
[data-theme="dark"] .memorisation-checker-ayah {
  background: #101312;
  border-color: rgba(244, 239, 230, 0.1);
}

[data-theme="dark"] .memorisation-checker-live-placeholder {
  color: rgba(244, 239, 230, 0.5);
}

@media (max-width: 720px) {
  .memorisation-checker-modal {
    width: 100vw;
    height: 100dvh;
    max-height: none;
    border-radius: 0;
  }

  .memorisation-checker-header {
    grid-template-columns: minmax(0, 1fr) auto;
  }

  .memorisation-checker-header-actions {
    grid-column: 1 / -1;
    justify-content: stretch;
  }

  .memorisation-checker-header-actions .memorisation-checker-status,
  .memorisation-checker-start-btn {
    flex: 1 1 0;
  }

  .memorisation-checker-body {
    grid-template-rows: minmax(260px, 1fr) minmax(240px, 40%);
    padding: 10px;
  }

  .memorisation-checker-word-stream .recitation-word-chip {
    font-size: clamp(1.15rem, 6vw, 1.8rem);
  }
}

.memorisation-checker-modal .memorisation-checker-header {
  grid-template-columns: minmax(0, 1fr) auto auto;
}

.memorisation-checker-modal .memorisation-checker-body {
  grid-template-rows: minmax(0, 2fr) minmax(0, 1fr);
  overflow: hidden;
}



.memorisation-checker-modal .memorisation-checker-live {
  min-height: 0;
  overflow: hidden;
}

.memorisation-checker-modal .memorisation-checker-results {
  display: grid;
  gap: 10px;
  min-height: 0;
  overflow: hidden;
  border-radius: 8px;
}

.memorisation-checker-modal .memorisation-checker-results .recitation-result-stats {
  grid-template-columns: repeat(6, minmax(0, 1fr));
  gap: 8px;
}

.memorisation-checker-modal .memorisation-checker-results .recitation-result-stat {
  min-height: 86px;
  padding: 10px 12px;
}

.memorisation-checker-modal .memorisation-checker-results .recitation-result-stat strong {
  font-size: clamp(1.25rem, 2vw, 1.8rem);
}

.memorisation-checker-modal .memorisation-checker-results .recitation-result-stat small,
.memorisation-checker-modal .memorisation-checker-results .memorisation-checker-section-head p {
  font-size: 0.78rem;
  line-height: 1.35;
}

.memorisation-checker-modal .memorisation-checker-final-words.recitation-word-stream {
  max-height: 116px;
  min-height: 72px;
  overflow: hidden;
}

.memorisation-checker-modal .memorisation-checker-final-words .recitation-word-chip {
  font-size: clamp(0.95rem, 1.6vw, 1.35rem);
}

.memorisation-checker-modal .recitation-next-card {
  padding: 12px 14px;
}


.memorisation-checker-modal .memorisation-checker-ayah {
  order: 2;
  width: 100%;
  min-height: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: clamp(14px, 2vw, 22px);
}

.memorisation-checker-modal .memorisation-checker-ayah-actions {
  order: 3;
  justify-self: stretch;
  width: 100%;
  justify-content: center;
  padding: 8px;
  border-radius: 8px;
  background: rgba(255, 250, 243, 0.72);
}

.memorisation-checker-modal .memorisation-checker-ayah-actions .self-check-ayah-action {
  color: #244338;
  border-color: rgba(47, 111, 88, 0.22);
}

.memorisation-checker-modal .memorisation-checker-start-btn {
  position: relative;
  isolation: isolate;
  overflow: visible;
  border: 1px solid rgba(143, 210, 172, 0.42);
  box-shadow: 0 18px 40px rgba(47, 111, 88, 0.22);
}

.memorisation-checker-modal .memorisation-checker-start-btn::before {
  content: "";
  position: absolute;
  inset: -3px;
  z-index: -1;
  border-radius: 11px;
  background: linear-gradient(90deg, rgba(143, 210, 172, 0.16), rgba(143, 210, 172, 0.88), rgba(143, 210, 172, 0.16));
  animation: reciteCheckBorder 2.1s linear infinite;
}

[data-theme="dark"] .memorisation-checker-modal .memorisation-checker-ayah-actions {
  background: rgba(16, 19, 18, 0.86);
  border-color: rgba(244, 239, 230, 0.1);
}

[data-theme="dark"] .memorisation-checker-modal .memorisation-checker-ayah-actions .self-check-ayah-action {
  color: #e8d7bd;
  border-color: rgba(232, 215, 189, 0.2);
  background: rgba(255, 255, 255, 0.055);
}

.view-mode-ai-btn {
  padding-inline: 10px;
  color: #2f6f58;
}

[data-theme="dark"] .view-mode-ai-btn {
  color: #8fd2ac;
}

@media (max-width: 980px) {
  .memorisation-checker-modal .memorisation-checker-results .recitation-result-stats {
    grid-template-columns: repeat(3, minmax(0, 1fr));
  }
}

@media (max-width: 720px) {
  .memorisation-checker-modal .memorisation-checker-body {
    grid-template-rows: minmax(0, 2fr) minmax(0, 1fr);
  }

  .memorisation-checker-modal .memorisation-checker-results .recitation-result-stats {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}

