/* SNIPPET 1: CORE DESIGN SYSTEM */
:root {
  --bg-body: #f7f3ef;
  --surface: #ffffff;
  --surface-elevated: #fffbf7;
  --border-light: rgba(100, 70, 40, 0.12);
  --border-medium: rgba(100, 70, 40, 0.2);
  --text-primary: #231f1c;
  --text-secondary: #6b5e52;
  --text-muted: #9b8e82;
  --accent: #b5723c;
  --accent-deep: #8b532b;
  --accent-soft: rgba(181, 114, 60, 0.12);
  --success: #2e7d64;
  --success-soft: rgba(46, 125, 100, 0.12);
  --warning: #e09d32;
  --error: #c2573a;
  --radius-card: 20px;
  --radius-element: 14px;
  --shadow-sm: 0 4px 12px rgba(0, 0, 0, 0.04);
  --shadow-md: 0 8px 24px rgba(0, 0, 0, 0.06);
  --transition: all 0.2s ease;
}

/* SNIPPET 2: SESSION HEADER */
.session-header {
  background: var(--surface);
  border-radius: var(--radius-card);
  padding: 24px 28px;
  margin-bottom: 28px;
  border: 1px solid var(--border-light);
  box-shadow: var(--shadow-sm);
  display: flex;
  justify-content: space-between;
  align-items: center;
  flex-wrap: wrap;
  gap: 20px;
}

.session-title {
  font-size: 1.75rem;
  font-weight: 700;
  letter-spacing: -0.02em;
}

.session-badge {
  background: var(--accent-soft);
  color: var(--accent);
  padding: 6px 14px;
  border-radius: 40px;
  font-size: 0.75rem;
  font-weight: 600;
}

/* SNIPPET 3: VERSE CARD */
.verse-card {
  background: var(--surface);
  border-radius: var(--radius-card);
  padding: 28px;
  margin-bottom: 20px;
  border: 1px solid var(--border-light);
  transition: var(--transition);
}

.verse-card.active {
  border-left: 4px solid var(--accent);
  box-shadow: var(--shadow-md);
}

.verse-arabic {
  font-family: 'UthmanicHafs', 'Amiri', 'Noto Naskh Arabic', serif;
  font-size: 2.2rem;
  line-height: 1.8;
  text-align: right;
  direction: rtl;
  color: var(--text-primary);
  margin-bottom: 16px;
}

.verse-translation {
  color: var(--text-secondary);
  font-size: 0.95rem;
  line-height: 1.6;
  border-top: 1px solid var(--border-light);
  padding-top: 16px;
}

/* SNIPPET 4: TOGGLE CHIP */
.toggle-chip {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 8px 18px;
  border-radius: 40px;
  background: var(--surface);
  border: 1px solid var(--border-medium);
  color: var(--text-secondary);
  font-size: 0.8rem;
  font-weight: 500;
  cursor: pointer;
  transition: var(--transition);
}

.toggle-chip.active {
  background: var(--accent);
  border-color: var(--accent);
  color: white;
}

/* SNIPPET 5: PROGRESS BAR */
.progress-section {
  margin: 20px 0;
}

.progress-label {
  display: flex;
  justify-content: space-between;
  font-size: 0.75rem;
  color: var(--text-secondary);
  margin-bottom: 8px;
}

.progress-track {
  height: 6px;
  background: var(--border-light);
  border-radius: 10px;
  overflow: hidden;
}

.progress-fill {
  height: 100%;
  background: var(--accent);
  border-radius: 10px;
  transition: width 0.3s ease;
}

/* SNIPPET 6: BUTTON STYLES */
.btn-primary {
  background: var(--accent);
  color: white;
  border: none;
  padding: 12px 24px;
  border-radius: var(--radius-element);
  font-weight: 600;
  font-size: 0.875rem;
  cursor: pointer;
  transition: var(--transition);
  display: inline-flex;
  align-items: center;
  gap: 8px;
}

.btn-primary:hover {
  background: var(--accent-deep);
  transform: translateY(-1px);
}

.btn-secondary {
  background: transparent;
  border: 1px solid var(--border-medium);
  color: var(--text-secondary);
  padding: 12px 24px;
  border-radius: var(--radius-element);
  font-weight: 500;
  cursor: pointer;
  transition: var(--transition);
}

/* SNIPPET 7: AI CHECKER MODAL */
.ai-checker-modal {
  background: var(--surface);
  border-radius: var(--radius-card);
  max-width: 900px;
  width: 90%;
  margin: 40px auto;
  padding: 28px;
  box-shadow: var(--shadow-lg);
  border: 1px solid var(--border-light);
}

.checker-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 24px;
  padding-bottom: 16px;
  border-bottom: 1px solid var(--border-light);
}

.checker-title {
  font-size: 1.35rem;
  font-weight: 700;
}

/* SNIPPET 8: WORD STREAM (LIVE RECOGNITION) */
.word-stream {
  display: flex;
  flex-wrap: wrap;
  gap: 12px;
  justify-content: center;
  padding: 24px;
  background: var(--surface-elevated);
  border-radius: var(--radius-element);
  border: 1px solid var(--border-light);
  margin: 20px 0;
  direction: rtl;
}

.word-chip {
  display: inline-block;
  padding: 8px 16px;
  background: var(--surface);
  border-radius: 40px;
  font-family: 'UthmanicHafs', 'Amiri', serif;
  font-size: 1.2rem;
  border: 1px solid var(--border-light);
  transition: var(--transition);
}

.word-chip.correct {
  background: var(--success-soft);
  border-color: var(--success);
  color: var(--success);
}

.word-chip.partial {
  background: var(--warning-soft);
  border-color: var(--warning);
  color: #b87a1a;
}

.word-chip.incorrect {
  background: var(--error-soft);
  border-color: var(--error);
  color: var(--error);
}

/* SNIPPET 9: RESULTS GRID */
.results-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
  gap: 16px;
  margin: 24px 0;
}

.result-card {
  background: var(--surface-elevated);
  padding: 20px;
  border-radius: var(--radius-element);
  text-align: center;
  border: 1px solid var(--border-light);
}

.result-value {
  font-size: 2rem;
  font-weight: 700;
  color: var(--accent);
}

.result-label {
  font-size: 0.75rem;
  color: var(--text-secondary);
  margin-top: 4px;
}

/* SNIPPET 10: RECORDINGS LIBRARY */
.library-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
  gap: 16px;
  margin-top: 20px;
}

.recording-card {
  background: var(--surface);
  border: 1px solid var(--border-light);
  border-radius: var(--radius-element);
  padding: 16px;
  transition: var(--transition);
}

.recording-card:hover {
  border-color: var(--accent-soft);
  box-shadow: var(--shadow-sm);
}

.recording-meta {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 12px;
}

.recording-date {
  font-size: 0.7rem;
  color: var(--text-muted);
}

/* SNIPPET 11: RESPONSIVE TOOLBAR */
.tools-tabs {
  display: flex;
  gap: 8px;
  background: var(--surface);
  padding: 6px;
  border-radius: 60px;
  border: 1px solid var(--border-light);
  width: fit-content;
}

.tab-btn {
  padding: 10px 20px;
  border-radius: 40px;
  background: transparent;
  border: none;
  font-weight: 500;
  color: var(--text-secondary);
  cursor: pointer;
  transition: var(--transition);
}

.tab-btn.active {
  background: var(--accent);
  color: white;
}

/* SNIPPET 12: STATS CARDS */
.stats-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 20px;
  margin: 24px 0;
}

.stat-card {
  background: var(--surface);
  border-radius: var(--radius-element);
  padding: 20px;
  text-align: center;
  border: 1px solid var(--border-light);
}

.stat-number {
  font-size: 2rem;
  font-weight: 700;
  color: var(--accent);
}

/* SNIPPET 13: MICRO INTERACTIONS */
@keyframes slideUp {
  from {
    opacity: 0;
    transform: translateY(10px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.modal-content {
  animation: slideUp 0.25s ease;
}

button:active {
  transform: scale(0.97);
}

/* SNIPPET 14: MOBILE ADAPTATION */
@media (max-width: 768px) {
  .session-header {
    flex-direction: column;
    align-items: flex-start;
    padding: 20px;
  }
  
  .verse-arabic {
    font-size: 1.6rem;
  }
  
  .stats-grid {
    grid-template-columns: repeat(2, 1fr);
  }
  
  .tools-tabs {
    width: 100%;
    overflow-x: auto;
  }
  
  .btn-primary, .btn-secondary {
    padding: 10px 18px;
    font-size: 0.8rem;
  }
}

/* SNIPPET 15: DARK MODE TOGGLE */
.theme-toggle {
  position: fixed;
  bottom: 24px;
  right: 24px;
  width: 48px;
  height: 48px;
  border-radius: 50%;
  background: var(--surface);
  border: 1px solid var(--border-medium);
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  box-shadow: var(--shadow-md);
  z-index: 100;
}

