  }

  .verse-menu-wrap {
    margin-left: auto !important;
  }
}
.setup-search-pill {
  gap: 0.45rem !important;
  border-radius: 999px !important;
  padding: 0.75rem 1rem !important;
}

.action-btn-search {
  border-radius: 999px !important;
}

.quran-search-modal-backdrop {
  position: fixed;
  inset: 0;
  z-index: 2600;
  display: grid;
  place-items: center;
  padding: clamp(0.75rem, 2vw, 1.5rem);
  background: rgba(20, 17, 14, 0.46);
  backdrop-filter: blur(12px);
}

.quran-search-modal {
  width: min(1040px, 100%);
  max-height: min(92vh, 940px);
  display: flex;
  flex-direction: column;
  gap: 1rem;
  overflow: hidden;
  border: 1px solid var(--border);
  border-radius: 24px;
  background: var(--surface-strong);
  color: var(--text);
  box-shadow: 0 28px 84px rgba(20, 17, 14, 0.28);
}

.quran-search-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
  padding: 1.25rem 1.25rem 0;
}

.quran-search-title-icon {
  width: 3rem;
  height: 3rem;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border: 1px solid var(--border);
  border-radius: 999px;
  color: var(--accent);
  background: color-mix(in srgb, var(--surface) 78%, transparent);
  box-shadow: 0 12px 30px rgba(166, 109, 57, 0.12);
}

.quran-search-title-icon i {
  font-size: 1.2rem;
}

.quran-search-kicker {
  color: var(--accent);
  font-size: 0.74rem;
  font-weight: 700;
  letter-spacing: 0.1em;
  text-transform: uppercase;
}

.quran-search-header h2 {
  margin: 0.25rem 0 0;
  font-size: clamp(1.35rem, 2.4vw, 2rem);
  line-height: 1.1;
}

.pill-control {
  min-height: 42px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.45rem;
  border: 1px solid var(--border);
  border-radius: 999px;
  padding: 0.62rem 0.9rem;
  background: rgba(255, 255, 255, 0.58);
  color: var(--text);
  font-weight: 650;
  text-decoration: none;
  transition: transform 0.16s ease, border-color 0.16s ease, background 0.16s ease, box-shadow 0.16s ease;
}

.pill-control:hover:not(:disabled),
.pill-control.active {
  border-color: rgba(47, 111, 88, 0.34);
  background: rgba(47, 111, 88, 0.1);
  box-shadow: 0 10px 24px rgba(47, 111, 88, 0.08);
  transform: translateY(-1px);
}

.pill-control:disabled {
  opacity: 0.52;
}

.quran-search-close {
  width: 44px;
  min-width: 44px;
  padding: 0;
}

.quran-search-input-row {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto auto;
  gap: 0.75rem;
  padding: 0 1.25rem;
}

.quran-search-input-shell {
  min-height: 52px;
  display: flex;
  align-items: center;
  gap: 0.65rem;
  border: 1px solid var(--border);
  border-radius: 999px;
  padding: 0 1rem;
  background: rgba(255, 255, 255, 0.68);
}

.quran-search-input-shell input {
  width: 100%;
  border: 0;
  outline: 0;
  background: transparent;
  color: var(--text);
  font-size: 1rem;
}

.quran-search-hint {
  margin: -0.25rem 1.35rem 0;
  color: var(--text-muted);
  font-size: 0.9rem;
}

.quran-search-hint.warning,
.quran-search-status.error {
  color: #a13d32;
}

.quran-search-controls {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto;
  gap: 0.85rem;
  align-items: end;
  padding: 0 1.25rem;
}

.quran-search-filter-grid {
  display: grid;
  grid-template-columns: minmax(150px, 220px) minmax(150px, 260px);
  gap: 0.75rem;
}

.quran-search-filter-grid label {
  display: grid;
  gap: 0.35rem;
  color: var(--text-muted);
  font-size: 0.78rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.06em;
}

.quran-search-select,
.quran-search-filter-input {
  min-height: 42px;
  border: 1px solid var(--border);
  border-radius: 999px;
  padding: 0.55rem 0.85rem;
  background: rgba(255, 255, 255, 0.68);
  color: var(--text);
  font-size: 0.95rem;
}

.quran-search-pill-row {
  display: flex;
  flex-wrap: wrap;
  justify-content: flex-end;
  gap: 0.5rem;
}

.quran-search-font-pill {
  min-height: 42px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border-radius: 999px;
  padding: 0.55rem 0.85rem;
  background: rgba(47, 111, 88, 0.1);
  color: var(--text);
  font-weight: 750;
  font-variant-numeric: tabular-nums;
}

.quran-search-status {
  margin: 0 1.25rem;
  border: 1px solid var(--border);
  border-radius: 18px;
  padding: 1rem;
  background: rgba(255, 255, 255, 0.48);
  color: var(--text-muted);
}

.quran-search-results {
  min-height: 0;
  overflow: auto;
  display: grid;
  gap: 0.8rem;
  padding: 0 1.25rem 1.25rem;
}

.quran-search-results-head {
  position: sticky;
  top: 0;
  z-index: 1;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
  border: 1px solid var(--border);
  border-radius: 999px;
  padding: 0.65rem 0.9rem;
  background: color-mix(in srgb, var(--surface-strong) 92%, transparent);
  backdrop-filter: blur(10px);
}

.quran-search-results-head span {
  color: var(--text-muted);
  font-size: 0.88rem;
}

.quran-search-result-card {
  border: 1px solid var(--border);
  border-radius: 18px;
  padding: 1rem;
  background: rgba(255, 255, 255, 0.6);
}

.quran-search-result-meta {
  display: flex;
  justify-content: space-between;
  gap: 1rem;
  color: var(--text-muted);
  font-size: 0.9rem;
}

.quran-search-result-meta span {
  color: var(--text);
  font-weight: 750;
}

.quran-search-arabic {
  margin: 0.8rem 0 0;
  direction: rtl;
  line-height: 2.1;
  text-align: right;
}

.quran-search-translation {
  margin: 0.75rem 0 0;
  color: var(--text-muted);
  font-size: 1rem;
  line-height: 1.65;
}

.quran-search-modal mark {
  border-radius: 0.35em;
  padding: 0.05em 0.16em;
  background: rgba(224, 171, 91, 0.34);
  color: inherit;
}

[data-theme="dark"] .quran-search-modal,
[data-theme="dark"] .quran-search-input-shell,
[data-theme="dark"] .quran-search-select,
[data-theme="dark"] .quran-search-filter-input,
[data-theme="dark"] .pill-control,
[data-theme="dark"] .quran-search-status,
[data-theme="dark"] .quran-search-result-card {
  background: rgba(24, 23, 21, 0.94);
}

@media (max-width: 760px) {
  .quran-search-modal-backdrop {
    align-items: stretch;
    padding: 0;
  }

  .quran-search-modal {
    max-height: 100vh;
    border-radius: 0;
  }

  .quran-search-input-row,
  .quran-search-controls,
  .quran-search-filter-grid {
    grid-template-columns: 1fr;
  }

  .quran-search-pill-row {
    justify-content: flex-start;
  }

  .quran-search-result-meta,
  .quran-search-results-head {
    align-items: flex-start;
    flex-direction: column;
  }
}

