}

.quick-pill-group-list .view-mode-btn.active {
  background: rgba(47, 111, 88, 0.14) !important;
  border-color: rgba(47, 111, 88, 0.34) !important;
}

.workspace-applied-pills {
  margin: 0 !important;
  gap: 0.38rem !important;
}

.quick-ai-actions {
