  gap: 0.28rem !important;
}

.top-card-menu button {
  margin: 0 !important;
}

.top-card-menu button.active {
  box-shadow: inset 0 0 0 1px rgba(47, 111, 88, 0.2) !important;
}

.mushaf-pill-bar {
