}

[data-theme="dark"] .verse-arabic:not(.tajweed-enabled),
[data-theme="dark"] .mushaf-ayah-text:not(.tajweed-enabled),
[data-theme="dark"] .self-check-modal-ayah:not(.tajweed-enabled),
