}

.workspace-shell-main-title {
  cursor: pointer !important;
  transition:
    color 120ms ease,
    opacity 120ms ease,
    text-decoration-color 120ms ease !important;
  text-decoration: underline;
  text-decoration-color: transparent;
  text-underline-offset: 0.14em;
}

